/* AUTO-GENERATED — Connecticut Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["CT"] = {"code":"CT","name":"Connecticut","agency":"Connecticut DMV","agencyShort":"DMV","handbook":"https://portal.ct.gov/dmv/commercial-and-industry-services/get-commercial-driver-license","links":{},"en":[{"q":"Under Connecticut law, what is the maximum width of a commercial vehicle (excluding safety devices such as mirrors) permitted to operate on Connecticut highways without a special permit?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"Connecticut General Statutes Sec. 14-262 sets the maximum legal vehicle width at 102 inches (8 feet 6 inches), not counting safety devices such as mirrors. The CTDOT Vehicle Size and Weight Limitations sheet lists Width 102.37 inches. Source: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations.","handbook":"","hbref":""},{"q":"What is the maximum height, including load, that a vehicle may be in Connecticut before a special height permit from the Commissioner of Transportation is required?","options":["12 feet 6 inches","13 feet 0 inches","13 feet 6 inches","14 feet 0 inches"],"answer":2,"explanation":"Connecticut General Statutes Sec. 14-264 prohibits operating a vehicle whose height with its load exceeds 13 feet 6 inches without a special written permit (except a load of loose hay or straw). Source: CGS Sec. 14-264; CTDOT Vehicle Size and Weight Limitations.","handbook":"","hbref":""},{"q":"In Connecticut, what is the maximum length, including load, of a single-unit (straight) truck operating without a permit?","options":["40 feet","45 feet","48 feet","53 feet"],"answer":1,"explanation":"Connecticut General Statutes Sec. 14-262 limits a single-unit vehicle to a maximum length, including load, of 45 feet. Source: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations (\"Single unit vehicle 45 feet\").","handbook":"","hbref":""},{"q":"For a tractor pulling a single semitrailer on general (non-restricted) Connecticut highways, what is the maximum legal length of the semitrailer?","options":["45 feet","48 feet","53 feet","57 feet"],"answer":1,"explanation":"On general highways Connecticut allows a tractor and a 48-foot semitrailer combination with no overall length limit, but the trailer itself is limited to 48 feet. Source: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations.","handbook":"","hbref":""},{"q":"On Connecticut's designated (restricted) highway system, a 53-foot semitrailer is allowed provided the distance from the kingpin to the center of the rearmost axle does not exceed what figure?","options":["41 feet","43 feet","45 feet","48 feet"],"answer":1,"explanation":"On the designated highway system Connecticut permits a tractor and a 53-foot semitrailer with no overall length limit, but the kingpin-to-center-of-rearmost-axle distance must not exceed 43 feet. Source: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations.","handbook":"","hbref":""},{"q":"On Connecticut's designated highway system, a tractor pulling twin (double) trailers may have each trailer up to what maximum length?","options":["27 feet","28 feet","33 feet","40 feet"],"answer":1,"explanation":"On the designated highway system, Connecticut allows a tractor and twin trailer combination with no overall length limit, but each trailer is limited to 28 feet. Source: CTDOT Vehicle Size and Weight Limitations (Restricted to the Designated Highway System).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight a 5-axle combination may carry on Connecticut highways without an overweight permit, when bridge-formula requirements are met?","options":["73,000 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"answer":1,"explanation":"Connecticut's maximum practicable weight is 80,000 pounds on 5 axles with 51 feet between the first and last axle, allowed when the Federal Bridge Formula requirements are met. Source: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a.","handbook":"","hbref":""},{"q":"In Connecticut, what is the maximum weight allowed on a single axle when the axle is spaced 6 feet or more from adjacent axles?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":2,"explanation":"Connecticut allows 22,400 pounds per axle when axles are spaced 6 feet or greater apart; axles spaced less than 6 feet apart are limited to 18,000 pounds per axle. Source: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a.","handbook":"","hbref":""},{"q":"Under Connecticut weight rules, what is the maximum weight permitted on any single axle when that axle is spaced LESS than 6 feet from an adjacent axle?","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"answer":1,"explanation":"Connecticut limits axles spaced less than 6 feet apart to 18,000 pounds per axle; only at 6 feet or greater spacing is 22,400 pounds allowed. Source: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a.","handbook":"","hbref":""},{"q":"When a Connecticut combination vehicle's gross weight exceeds 73,000 pounds (up to 80,000 pounds), what additional requirement must be satisfied?","options":["The vehicle must use only solid rubber tires","All Federal Bridge Formula requirements must be met","The vehicle must travel only at night","A police escort must accompany the vehicle"],"answer":1,"explanation":"Per CTDOT, a maximum gross weight of 80,000 pounds is allowed only when all requirements of the Federal Bridge Formula are met for weights over 73,000 pounds. Source: CTDOT Vehicle Size and Weight Limitations (Gross Vehicle Weights Over 73,000 pounds).","handbook":"","hbref":""},{"q":"In Connecticut, the maximum permitted weight transmitted to the road by the tires of any vehicle is based on tire width. What is that limit?","options":["500 pounds per inch of tire width","600 pounds per inch of tire width","700 pounds per inch of tire width","800 pounds per inch of tire width"],"answer":1,"explanation":"Connecticut limits tire loading to 600 pounds per inch of tire width (maximum). Source: CTDOT Vehicle Size and Weight Limitations (Tires - Load per inch width of tire 600 pounds maximum).","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed in Connecticut for a 2-axle straight truck when neither axle weight exceeds 18,000 pounds?","options":["32,000 pounds","36,000 pounds","40,000 pounds","53,800 pounds"],"answer":1,"explanation":"Connecticut allows a 2-axle vehicle up to 36,000 pounds when axle weight does not exceed 18,000 pounds (32,000 pounds is the figure without that axle condition). Source: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a.","handbook":"","hbref":""},{"q":"For a tractor-semitrailer combination in Connecticut, what is the maximum gross weight when the combination has 3 axles?","options":["53,800 pounds","58,400 pounds","67,400 pounds","73,000 pounds"],"answer":1,"explanation":"Connecticut sets a 3-axle tractor-semitrailer combination at a maximum of 58,400 pounds; a 4-axle combination is 67,400 pounds and 5-or-more axles up to 73,000 pounds. Source: CTDOT Vehicle Size and Weight Limitations (Tractor Semitrailer).","handbook":"","hbref":""},{"q":"The federal weight standard that Connecticut applies to determine the maximum gross weight permitted on a group of consecutive axles is known as the:","options":["Federal Axle Spread Rule","Federal Bridge Formula","Federal Gross Combination Standard","Federal Tandem Weight Table"],"answer":1,"explanation":"Connecticut applies the Federal Bridge Formula to determine allowable weight on axle groups; it must be satisfied for gross weights over 73,000 pounds up to 80,000 pounds. Source: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a.","handbook":"","hbref":""},{"q":"In Connecticut, who issues oversize/overweight (nonconforming vehicle) permits, and through what system are applications submitted?","options":["The Commissioner of Transportation, via the DMV-managed Commercial Vehicle Operations (CVO) WebPortal","The local police department of each town the vehicle passes through","The Federal Motor Carrier Safety Administration online portal","The Department of Energy and Environmental Protection by paper application"],"answer":0,"explanation":"Under CGS Sec. 14-270, the Commissioner of Transportation issues special permits for nonconforming (oversize/overweight) vehicles; applications are processed through the Connecticut Commercial Vehicle Operations (CVO) WebPortal managed by the CT DMV. Source: CGS Sec. 14-270; CTDOT Oversize/Overweight Permit FAQ.","handbook":"","hbref":""},{"q":"A standard Connecticut single-trip oversize/overweight permit is generally valid for what period, and travel is restricted to what hours?","options":["30 days; any time of day or night","3 days; daylight hours only","7 days; nighttime only","1 day; rush hours excluded"],"answer":1,"explanation":"CTDOT issues single-trip oversize/overweight permits valid for a 3-day period, with travel limited to daylight hours (generally one-half hour after sunrise to one-half hour before sunset). Source: CTDOT Vehicle Size and Weight Limitations; CTDOT Oversize/Overweight Permit FAQ.","handbook":"","hbref":""},{"q":"Under Connecticut law (CGS Sec. 14-267a), what is the fine for operating an overweight commercial vehicle, based on the amount of excess weight?","options":["$1 per 100 pounds of excess weight","$3 per 100 pounds (or fraction thereof) of excess weight","$10 per 100 pounds of excess weight","A flat $500 regardless of excess weight"],"answer":1,"explanation":"Connecticut General Statutes Sec. 14-267a sets the overweight fine at three dollars per one hundred pounds, or fraction thereof, of excess weight. Source: CGS Sec. 14-267a.","handbook":"","hbref":""},{"q":"Connecticut provides a special weight allowance for certain agricultural hauling. What is the maximum gross vehicle weight permitted for a bulk milk pickup tanker or a vehicle hauling agricultural commodities (where federal law permits)?","options":["80,000 pounds","88,000 pounds","100,000 pounds","120,000 pounds"],"answer":2,"explanation":"Connecticut General Statutes Sec. 14-267a sets a permissible gross weight of up to 100,000 pounds for bulk milk pickup tankers and vehicles hauling agricultural commodities (feed, seed, fertilizer and products of agriculture), where federal law allows. Source: CGS Sec. 14-267a.","handbook":"","hbref":""},{"q":"Under CGS Sec. 14-267a, for a vehicle with two consecutive sets of tandem axles, a gross load of 68,000 pounds is permitted on those tandems only if the distance between the first and last axle of the two sets is at least:","options":["30 feet","34 feet","36 feet","40 feet"],"answer":2,"explanation":"Connecticut General Statutes Sec. 14-267a allows two consecutive sets of tandem axles to carry a gross 68,000 pounds provided the overall distance between the first and last axles of those consecutive tandem sets is 36 feet or more. Source: CGS Sec. 14-267a.","handbook":"","hbref":""},{"q":"In Connecticut, what is the minimum Gross Vehicle Weight Rating (GVWR) that places a single vehicle into the Class B CDL category?","options":["16,001 pounds or more","26,001 pounds or more","10,001 pounds or more","33,001 pounds or more"],"answer":1,"explanation":"A Connecticut Class B CDL authorizes driving any single vehicle with a GVWR of 26,001 pounds or more, and any such vehicle towing a unit not in excess of 10,000 pounds. Source: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Under Connecticut rules, a Class A CDL is required to drive a combination of vehicles with a GVWR of 26,001 pounds or more provided the towed unit's GVWR exceeds what figure?","options":["5,000 pounds","26,001 pounds","10,000 pounds","15,000 pounds"],"answer":2,"explanation":"A Connecticut Class A CDL covers combinations with a GVWR of 26,001 pounds or more where the towed vehicle's GVWR is in excess of 10,000 pounds. Source: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"A Connecticut driver operates a single vehicle under 26,001 pounds GVWR designed to carry 20 passengers including the driver. Which CDL class applies?","options":["Class A","Class B","Class C","No CDL is required"],"answer":2,"explanation":"A Connecticut Class C CDL covers a single vehicle under 26,001 pounds GVWR (or towing a unit not over 10,000 pounds) that is designed to transport 16 or more passengers including the driver, or that carries placarded hazardous materials. Source: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Connecticut CDL restricted to intrastate (within Connecticut only) operation?","options":["16","18","19","21"],"answer":1,"explanation":"Connecticut requires an applicant to be at least 18 years old for an intrastate CDL (operation within Connecticut only). Source: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a commercial motor vehicle in interstate commerce on a Connecticut CDL?","options":["18","19","20","21"],"answer":3,"explanation":"Connecticut requires an applicant to be at least 21 years old for interstate operation (within and outside Connecticut). Source: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Which endorsement does Connecticut require to drive a vehicle that transports hazardous materials in amounts requiring placards?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"answer":1,"explanation":"Connecticut requires the H (Hazardous Materials) endorsement to operate a vehicle transporting placarded hazardous materials. Source: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"In Connecticut, the N (tank/liquid bulk) endorsement is required for a permanently mounted cargo tank rated at what minimum capacity?","options":["100 gallons or more","119 gallons or more","500 gallons or more","1,000 gallons or more"],"answer":1,"explanation":"Connecticut requires the N endorsement for a vehicle designed to haul a liquid or liquid gas in a permanently mounted cargo tank rated at 119 gallons or more (or a portable tank rated at 1,000 gallons or more). Source: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Which Connecticut endorsement is required to tow more than one trailer with a vehicle requiring a Class A CDL?","options":["P endorsement","N endorsement","T endorsement","S endorsement"],"answer":2,"explanation":"Connecticut requires the T (Doubles/Triples) endorsement when a Class A CDL vehicle tows more than one trailer. Source: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Before a Connecticut driver can be issued an S (school bus) endorsement, which other endorsement must the driver also hold?","options":["H (Hazardous Materials)","N (Tank)","P (Passenger)","T (Doubles/Triples)"],"answer":2,"explanation":"In Connecticut the school bus (S) endorsement also requires the holder to have the Passenger (P) endorsement and maintain an acceptable driving record. Source: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Under federal rules applied in Connecticut, how long must an applicant hold a Commercial Learner Permit (CLP) before being eligible to take the CDL skills (road) test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"An applicant may not take the CDL skills test during the 14 days following initial issuance of the CLP; the permit must be held a minimum of 14 days. Source: 49 CFR 383.25(e), applied by Connecticut DMV.","handbook":"","hbref":""},{"q":"How long is a Connecticut Commercial Learner Permit (CLP) valid from the date of issuance?","options":["90 days","180 days","One year","Two years"],"answer":2,"explanation":"A Connecticut CLP remains active for one year from the date of issuance; if a CDL is not obtained within that period the applicant must retake the required tests. Source: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Effective February 7, 2022, who must complete Entry-Level Driver Training (ELDT) through an FMCSA-registered provider before testing in Connecticut?","options":["Only applicants for a hazmat endorsement","Anyone renewing an existing CDL","First-time CDL applicants, those upgrading Class B to Class A, and first-time H, P, or S endorsement applicants","Only drivers under age 21"],"answer":2,"explanation":"Since February 7, 2022, ELDT is required for first-time CDL applicants, drivers upgrading a Class B to a Class A, and first-time applicants for the H, P, or S endorsement, with training delivered by a provider on the FMCSA Training Provider Registry. Source: FMCSA ELDT rule (49 CFR Part 380); CT DMV CDL pages (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) for a Connecticut applicant must be completed through which system?","options":["The Connecticut DMV training portal","The FMCSA Training Provider Registry (TPR)","The TSA enrollment system","The Drug and Alcohol Clearinghouse"],"answer":1,"explanation":"ELDT must be completed with a provider listed on the FMCSA Training Provider Registry (TPR), which reports the driver's completion to FMCSA. Source: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov); CT DMV CDL pages.","handbook":"","hbref":""},{"q":"For the hazardous materials (H) endorsement, the ELDT requirement consists of which type of training?","options":["Theory training only","Behind-the-wheel training only","Both theory and behind-the-wheel training","No ELDT is required for hazmat"],"answer":0,"explanation":"The hazmat (H) endorsement ELDT requirement is theory-only; there is no behind-the-wheel component, unlike Class A/B and the P and S endorsements. Source: FMCSA ELDT rule (49 CFR Part 380); FMCSA Training Provider Registry.","handbook":"","hbref":""},{"q":"Besides knowledge and ELDT requirements, what additional federal screening must a Connecticut applicant pass to receive the hazmat (H) endorsement?","options":["A DOT physical only","A TSA Security Threat Assessment including fingerprinting","A state credit check","A vision-only exam"],"answer":1,"explanation":"A hazmat endorsement requires passing the TSA Security Threat Assessment, which includes a background check and fingerprinting, in addition to the knowledge test and ELDT theory training. Source: TSA HazMat Endorsement Threat Assessment Program; CT DMV endorsement pages.","handbook":"","hbref":""},{"q":"Which set of documents does the Connecticut DMV require when applying for a Commercial Learner Permit, consistent with REAL ID?","options":["Proof of identity, Social Security number, legal U.S. presence, and two proofs of Connecticut residency","Only a passport","A birth certificate and a utility bill","Only the current Connecticut driver's license"],"answer":0,"explanation":"Connecticut requires REAL ID documentation: proof of identity, Social Security number, legal U.S. presence, and two proofs of Connecticut residency, plus the self-certification confirmation and application form R-229a. Source: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"A Connecticut driver who will operate a commercial vehicle both inside and outside the state and must carry a DOT medical card should self-certify under which category?","options":["Excepted Interstate (EI)","Non-excepted Interstate (NI)","Excepted Intrastate (EA)","Non-excepted Intrastate (NA)"],"answer":1,"explanation":"Non-excepted Interstate (NI) covers driving in and outside Connecticut and requires meeting federal DOT medical certificate requirements. Source: CT DMV, Self-certification for CDL (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Which Connecticut self-certification category applies to a driver who operates only within Connecticut and is not required to meet federal DOT medical card requirements?","options":["Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)","Excepted Interstate (EI)"],"answer":2,"explanation":"Excepted Intrastate (EA) applies to drivers operating only within Connecticut who are exempt from the federal DOT medical certificate requirement. Source: CT DMV, Self-certification for CDL (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"Before processing a Connecticut CDL transaction, the DMV verifies an applicant's status in which federal system?","options":["The TSA PreCheck database","The FMCSA Drug and Alcohol Clearinghouse","The National Driver Register only","The Selective Service System"],"answer":1,"explanation":"Connecticut applicants must register with the FMCSA Drug and Alcohol Clearinghouse, and DMV checks the applicant's Clearinghouse status before processing the CDL transaction. Source: CT DMV CDL pages (portal.ct.gov/dmv); FMCSA Drug and Alcohol Clearinghouse.","handbook":"","hbref":""},{"q":"What is the minimum age, and what citizenship/immigration status, does Connecticut require for the hazardous materials (H) endorsement?","options":["Age 18, U.S. citizen only","Age 21, U.S. citizen, lawful permanent resident, or valid Employment Authorization Document holder","Age 19, any lawful resident","Age 21, U.S. citizen only"],"answer":1,"explanation":"Connecticut requires hazmat (H) applicants to be at least 21 and to be a U.S. citizen, a legal permanent resident, or to hold a valid Employment Authorization Document. Source: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"In Connecticut, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.04%","0.08%","0.02%","0.00%"],"answer":0,"explanation":"Connecticut follows the federal CMV standard: it is illegal to operate a CMV with a BAC of 0.04% or more (CT CDL Manual 1.3.2; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"By operating a CMV in Connecticut, a driver is automatically deemed to have given consent to chemical alcohol testing. What is this principle called?","options":["Implied consent","Probable cause","Express waiver","Administrative review"],"answer":0,"explanation":"Connecticut's implied consent law deems any licensed operator to have consented to a blood, breath, or urine test (CT CDL Manual 1.3.2; CGS Sec. 14-227b).","handbook":"","hbref":""},{"q":"A Connecticut CDL holder is convicted of a first major offense, such as driving a CMV with a BAC of 0.04% or more. For how long is the CDL disqualified?","options":["At least 1 year","At least 90 days","At least 6 months","At least 3 years"],"answer":0,"explanation":"A first major offense disqualifies the CDL for at least one year (CT CDL Manual 1.3.2; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"Under Connecticut rules, if a first major offense (such as a 0.04 BAC or test refusal) occurs while the driver is operating a CMV placarded for hazardous materials, the disqualification is at least:","options":["3 years","1 year","5 years","18 months"],"answer":0,"explanation":"A first major offense while operating a placarded HazMat CMV disqualifies the CDL for at least three years (CT CDL Manual 1.3.2; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"What is the Connecticut disqualification penalty for a driver convicted of a second major offense (for example, a second DUI or test refusal)?","options":["Lifetime disqualification","10-year disqualification","5-year disqualification","3-year disqualification"],"answer":0,"explanation":"A second major offense results in lifetime disqualification of the CDL (CT CDL Manual 1.3.2; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"A Connecticut CDL holder refuses to submit to a chemical alcohol test for the first time. How long is the CDL disqualified for this refusal?","options":["1 year","6 months","60 days","3 years"],"answer":0,"explanation":"Refusing to submit to a chemical test (implied consent violation) disqualifies the CDL for one year on the first offense (CT CDL Manual 1.3.2; CGS Sec. 14-227b).","handbook":"","hbref":""},{"q":"Under Connecticut's implied consent law, if a person refuses a chemical test, the regular (non-commercial) operator's license is subject to suspension for not less than:","options":["6 months","30 days","1 year","90 days"],"answer":0,"explanation":"Refusing a chemical test subjects the operator's license to suspension for not less than six months; if suspended, the CDL is also disqualified (CT CDL Manual 1.3.2; CGS Sec. 14-227b).","handbook":"","hbref":""},{"q":"In Connecticut, a CMV driver found with a detectable amount of alcohol below 0.04% is subject to what immediate action?","options":["Placed out-of-service for 24 hours","Disqualified for 60 days","Arrested for DUI","Fined $500 with no further action"],"answer":0,"explanation":"Any detectable alcohol under 0.04% results in being placed out-of-service for 24 hours (CT CDL Manual 1.3.2; 49 CFR 392.5).","handbook":"","hbref":""},{"q":"Which of the following is classified as a serious traffic violation for a Connecticut CDL holder?","options":["Speeding 15 mph or more above the posted limit","A first DUI in a CMV","Failing to stop at a railroad crossing","Violating an out-of-service order"],"answer":0,"explanation":"Serious traffic violations include excessive speeding (15 mph or more over the limit), reckless driving, and erratic lane changes; DUI and OOS violations are separate categories (CT CDL Manual 1.3.3).","handbook":"","hbref":""},{"q":"A Connecticut CDL holder commits two serious traffic violations within a three-year period. The minimum disqualification is:","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Two serious traffic violations within three years disqualify the CDL for at least 60 days (CT CDL Manual 1.3.3; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"If a Connecticut CDL holder commits three or more serious traffic violations within a three-year period, the minimum disqualification is:","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"Three or more serious traffic violations within three years disqualify the CDL for at least 120 days (CT CDL Manual 1.3.3; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"Which of these is NOT included in Connecticut's list of serious traffic violations?","options":["Driving 8 mph over the posted speed limit","Improper or erratic lane changes","Following a vehicle too closely","Reckless driving"],"answer":0,"explanation":"Serious violations require speeding 15 mph or more over the limit; 8 mph over does not qualify, while erratic lane changes, tailgating, and reckless driving do (CT CDL Manual 1.3.3).","handbook":"","hbref":""},{"q":"A Connecticut CDL holder commits a third out-of-service order violation within a 10-year period. The minimum disqualification is:","options":["3 years","1 year","2 years","180 days"],"answer":0,"explanation":"A third or subsequent out-of-service order violation within 10 years disqualifies the CDL for at least 3 years (up to 5) (CT CDL Manual 1.3.4; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"What is the Connecticut disqualification for a driver's FIRST conviction of a railroad-highway grade crossing violation while operating a CMV?","options":["At least 60 days","At least 30 days","At least 120 days","At least 180 days"],"answer":0,"explanation":"A first railroad-highway grade crossing violation disqualifies the CDL for at least 60 days (CT CDL Manual 1.3.5; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"For a SECOND railroad-highway grade crossing violation within three years, a Connecticut CDL holder is disqualified for at least:","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"A second grade crossing violation within three years disqualifies the CDL for at least 120 days (CT CDL Manual 1.3.5; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"Under Connecticut and federal CMV rules, a driver convicted of two or more violations of holding/using a hand-held mobile phone while operating a CMV faces a disqualification of 60 days for the second offense and how long for three or more offenses within three years?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"Hand-held mobile phone use while driving a CMV brings a 60-day disqualification for a second offense and 120 days for three or more within three years (CT CDL Manual 2.9.4; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"After being convicted of any traffic violation (other than parking), within how many days must a Connecticut CDL holder notify their employer?","options":["30 days","2 days","10 days","60 days"],"answer":0,"explanation":"A CDL holder must notify their employer within 30 days of conviction for any traffic violation, regardless of the vehicle driven (CT CDL Manual 1.4; 49 CFR 383.31).","handbook":"","hbref":""},{"q":"Under Connecticut's railroad-crossing law, where must a bus, school bus, or placarded hazmat/cargo-tank commercial vehicle stop before crossing tracks at grade?","options":["Not less than 15 feet nor more than 50 feet from the nearest rail","Exactly 25 feet from the nearest rail","Not less than 10 feet nor more than 40 feet from the nearest rail","Not less than 50 feet nor more than 100 feet from the nearest rail"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-250 and the CT CDL Manual require buses, vehicles carrying passengers, school transport vehicles, and CMVs with cargo tanks or hazmat to stop not less than 15 feet nor more than 50 feet from the nearest rail, then look and listen before crossing.","handbook":"","hbref":""},{"q":"When a Connecticut driver approaches a stationary emergency vehicle with flashing lights on a multi-lane highway, the state's Move Over law requires the driver to do what?","options":["Reduce speed to a reasonable level and, if in the adjacent lane, move over one lane when safe","Stop completely until the emergency vehicle clears the scene","Maintain the posted speed limit but sound the horn","Move over one lane only if the emergency vehicle is a police car"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-283b (the 'Move Over' law) requires operators to immediately slow to a reasonable speed below the limit and, when traveling in the lane adjacent to the shoulder, move over one lane unless that movement would be unsafe.","handbook":"","hbref":""},{"q":"On a Connecticut divided limited-access highway with three or more lanes in the same direction where the state so designates, which vehicle is prohibited from driving in the extreme left lane?","options":["A commercially registered truck","A passenger car with one occupant","A motorcycle","An ambulance responding to a call"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-230a bars commercially registered vehicles, motor buses, vehicles with trailers, and school buses from the extreme left lane on divided limited-access highways of three or more lanes (same direction) where the Office of the State Traffic Administration so designates; the fine is $88.","handbook":"","hbref":""},{"q":"Which roadways in Connecticut prohibit commercial vehicles such as tractor-trailers and box trucks?","options":["The Merritt, Wilbur Cross, and Milford Parkways (Route 15 corridor)","Interstate 95 and Interstate 84","All state routes numbered above 100","The Route 9 and Route 2 expressways"],"answer":0,"explanation":"Connecticut's parkways - the Merritt Parkway and Wilbur Cross Parkway (Route 15) and the Milford Parkway - ban commercial vehicles, trailers, and oversized vehicles, largely because of low historic overpasses. CT DOT Parkway Restrictions; the parkway-violation fine is $500 per violation.","handbook":"","hbref":""},{"q":"On a Connecticut highway where lanes are separated by a safety island or physical barrier, what must a driver on the OPPOSITE side of the barrier do when a school bus is stopped with red lights flashing?","options":["The driver may proceed without stopping","The driver must stop until the red lights are turned off","The driver must stop only if the bus has its door open","The driver must slow to 15 mph but need not stop"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-279 provides that on a highway with lanes separated by a safety island or physical barrier, a driver on the opposite side of that barrier may proceed without stopping for a school bus. A painted line alone does NOT qualify - both directions must stop.","handbook":"","hbref":""},{"q":"On a Connecticut roadway separated only by a painted center line (no physical barrier), what must a driver do when meeting a stopped school bus displaying flashing red lights on the opposite side?","options":["Stop, because a painted line does not qualify for the divided-highway exception","Proceed at reduced speed without stopping","Proceed without restriction since it is oncoming traffic","Stop only if children are visibly crossing"],"answer":0,"explanation":"Under Connecticut General Statutes Sec. 14-279, the no-stop exception applies only where a safety island or physical barrier separates the lanes. With only a painted line, vehicles on both sides must come to a complete stop for a school bus with flashing red lights.","handbook":"","hbref":""},{"q":"How close may a Connecticut driver approach a stopped, red-light-flashing school bus from the front before being required to stop?","options":["Not less than 10 feet from the front of the bus","Not less than 5 feet from the front of the bus","Not less than 20 feet from the front of the bus","Not less than 25 feet from the front of the bus"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-279 requires vehicles to stop not less than 10 feet from the front when approaching, and not less than 10 feet from the rear when overtaking or following, a registered school bus displaying flashing red signal lights.","handbook":"","hbref":""},{"q":"After stopping a disabled CMV on a one-way or divided Connecticut highway, where must the driver place the three reflective warning triangles?","options":["10 feet, 100 feet, and 200 feet toward the approaching traffic","10 feet, 50 feet, and 150 feet behind the vehicle","25 feet, 75 feet, and 125 feet toward approaching traffic","5 feet, 50 feet, and 500 feet toward approaching traffic"],"answer":0,"explanation":"The Connecticut CDL Manual (mirroring 49 CFR 392.22) directs that on a one-way or divided highway, warning devices be placed at 10 feet, 100 feet, and 200 feet toward the approaching traffic behind the stopped vehicle.","handbook":"","hbref":""},{"q":"Within how many minutes must a CDL driver in Connecticut place emergency warning devices after stopping a CMV on the road or shoulder?","options":["Within 10 minutes","Within 30 minutes","Within 5 minutes","Immediately, before exiting the cab"],"answer":0,"explanation":"The Connecticut CDL Manual states that if you must stop on a road or shoulder, you must turn on the four-way flashers and put out emergency warning devices within 10 minutes.","handbook":"","hbref":""},{"q":"Which list correctly identifies Connecticut vehicles that must STOP at every railroad grade crossing?","options":["Buses carrying passengers, school transport vehicles, and CMVs with cargo tanks or carrying hazardous materials","All commercial vehicles over 10,000 pounds regardless of cargo","Only empty tank trucks and tow trucks","Only vehicles towing a trailer"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-250 requires the operator of each CMV transporting passengers, service bus, or vehicle used to transport school children, and each CMV with a cargo tank or carrying hazardous materials, to stop 15 to 50 feet from the nearest rail before crossing.","handbook":"","hbref":""},{"q":"What is the highest posted speed limit a CMV may lawfully travel on a Connecticut interstate highway?","options":["65 mph, the same maximum that applies to passenger vehicles","55 mph, a special lower limit for all trucks statewide","70 mph on rural interstates","60 mph for any vehicle over 26,000 pounds"],"answer":0,"explanation":"Connecticut's maximum posted speed limit is 65 mph (CGS Sec. 14-219 / 14-218a), and the state does not set a separate, lower statewide truck speed limit - trucks and cars share the same 65 mph maximum where posted. Drivers must still obey any lower posted limits.","handbook":"","hbref":""},{"q":"On a two-lane Connecticut road carrying traffic in both directions (undivided), where should a CMV driver place the three warning triangles after stopping?","options":["Within 10 feet of the vehicle, and 100 feet ahead of and 100 feet behind it","10 feet, 100 feet, and 200 feet behind the vehicle only","50 feet ahead and 50 feet behind the vehicle only","Within 10 feet front and rear, and 250 feet in each direction"],"answer":0,"explanation":"The Connecticut CDL Manual instructs that on a two-lane, two-way or undivided highway, place one triangle within 10 feet of the vehicle and one each 100 feet behind and 100 feet ahead, on the shoulder or in the lane you stopped in.","handbook":"","hbref":""},{"q":"Under Connecticut's keep-right rule, where must a vehicle moving slower than the normal speed of traffic be driven?","options":["In the right-hand lane or as close as practicable to the right edge of the highway","In any lane, as long as it uses flashers","In the center lane of a three-lane road","In the left lane to stay out of merging traffic"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-230 requires vehicles to be driven on the right, and any vehicle proceeding at less than the normal speed of traffic to be driven in the right-hand lane available, or as close as practicable to the right curb or edge.","handbook":"","hbref":""},{"q":"What penalty does Connecticut impose for operating a commercial motor vehicle on a state parkway where such vehicles are prohibited?","options":["A fine of $500 for each violation","A written warning only on the first offense","A fine of $35 plus two points","Mandatory license suspension for 30 days"],"answer":0,"explanation":"Connecticut increased the penalty for operating a prohibited commercial vehicle on a parkway (Merritt, Wilbur Cross, Milford) to $500 per violation. CT DOT Parkway Restrictions; CGS Chapter 249 / Sec. 14-298 parkway-restriction authority.","handbook":"","hbref":""},{"q":"Beyond emergency vehicles, Connecticut's Move Over law also requires drivers to slow and move over for which of the following stopped on the shoulder?","options":["A nonemergency vehicle that is stationary on the shoulder","Only marked police cruisers","Only vehicles with red flares set out","Pedestrians waiting at a bus stop"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-283b was expanded to cover not only emergency vehicles (including maintenance vehicles and wreckers) with flashing lights but also any nonemergency vehicle that is stationary and located on the shoulder; drivers must slow and move over when safe.","handbook":"","hbref":""},{"q":"In Connecticut, what is the legal weight limit above which a vehicle generally requires a DOT overweight permit?","options":["80,000 pounds gross vehicle weight","73,280 pounds gross vehicle weight","100,000 pounds gross vehicle weight","65,000 pounds gross vehicle weight"],"answer":0,"explanation":"Connecticut follows the federal legal maximum of 80,000 pounds gross vehicle weight (on five axles). Loads exceeding 80,000 pounds require a CT DOT overweight permit. CT DOT Oversize/Overweight Permit regulations.","handbook":"","hbref":""},{"q":"Which subsequent-offense penalty applies in Connecticut for illegally passing a stopped school bus with red lights flashing (a second or later violation)?","options":["Not less than $500 nor more than $1,000, and/or up to 30 days imprisonment","A flat $90 infraction with no jail","A warning letter and two license points","A fixed $450 fine identical to the first offense"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-279 sets a $450 fine for a first offense of passing a stopped school bus, and for each subsequent offense not less than $500 nor more than $1,000, or imprisonment of not more than 30 days, or both.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle height in Connecticut before an oversize permit is required?","options":["13 feet 6 inches","12 feet 0 inches","14 feet 6 inches","13 feet 0 inches"],"answer":0,"explanation":"Connecticut's legal dimensional maximums are 8 feet 6 inches wide and 13 feet 6 inches high (with a 53-foot semitrailer length). Exceeding 13 feet 6 inches in height requires a CT DOT oversize permit. CT DOT Oversize/Overweight Permit regulations.","handbook":"","hbref":""},{"q":"A CDL driver approaches a railroad crossing in Connecticut hauling an EMPTY cargo tank that was last used for hazardous materials. What must the driver do?","options":["Stop 15 to 50 feet from the nearest rail, because the rule applies to cargo tanks whether loaded or empty","Proceed without stopping since the tank is empty","Stop only if a train is visible","Slow to 5 mph but continue across without a full stop"],"answer":0,"explanation":"Connecticut General Statutes Sec. 14-250 and the CT CDL Manual require vehicles with cargo tanks used for hazardous materials to stop 15 to 50 feet from the nearest rail whether the tank is loaded OR empty, and to cross only when the tracks can be cleared without stopping.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in Connecticut?","options":["The Connecticut Department of Motor Vehicles (DMV)","The Connecticut Department of Transportation (CTDOT)","The Federal Motor Carrier Safety Administration (FMCSA)","The Connecticut State Police, Commercial Vehicle Safety Division"],"answer":0,"explanation":"In Connecticut, the Department of Motor Vehicles (DMV) issues CDLs and administers the knowledge and skills testing. CTDOT handles oversize/overweight permits and FMCSA sets the federal standards, but the license itself is a state DMV credential. Source: CT DMV, 'Get a commercial driver's license' (portal.ct.gov/dmv).","handbook":"","hbref":""},{"q":"In Connecticut, what is the minimum age to obtain a CDL for intrastate (in-state only) operation?","options":["18 years old","16 years old","21 years old","25 years old"],"answer":0,"explanation":"Connecticut requires a driver to be at least 18 to operate a CMV intrastate (within Connecticut only). A driver must be at least 21 to drive interstate or to transport hazardous materials. Source: CT DMV, 'Get a commercial driver's license' / 'Get a commercial learner's permit.'","handbook":"","hbref":""},{"q":"In Connecticut, what is the minimum age to operate a commercial motor vehicle in interstate commerce or to haul hazardous materials?","options":["21 years old","18 years old","19 years old","23 years old"],"answer":0,"explanation":"Connecticut, following the federal standard, requires a driver to be at least 21 years old to drive a CMV across state lines (interstate) or to transport placardable quantities of hazardous materials. Drivers 18-20 are limited to intrastate operation. Source: CT DMV CLP/CDL pages; 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Before a new applicant may take the CDL skills test for a Class A or Class B license in Connecticut, what training must be completed?","options":["Entry-Level Driver Training (ELDT) — theory plus behind-the-wheel — from an FMCSA-registered provider","A 160-hour state-approved trade school program only","A defensive driving course approved by the Connecticut DMV","An eight-hour online hazardous materials awareness course"],"answer":0,"explanation":"Effective February 7, 2022, an entry-level applicant must complete mandatory Entry-Level Driver Training (ELDT) — both theory (knowledge) and behind-the-wheel (BTW) — through a provider on the FMCSA Training Provider Registry before taking the Class A/B skills test (and before the P, S, or H endorsement tests, as applicable). Source: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"An applicant must complete Entry-Level Driver Training before taking the knowledge test for which of these endorsements in Connecticut?","options":["The Hazardous Materials (H) endorsement","The Tank Vehicle (N) endorsement","The Double/Triple Trailers (T) endorsement","The Combination (no endorsement letter) class only"],"answer":0,"explanation":"ELDT must be completed before the Hazardous Materials (H) endorsement KNOWLEDGE test (H has no skills test). ELDT is also required before the skills tests for the Passenger (P) and School Bus (S) endorsements. The N and T endorsements are not subject to ELDT. Source: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR 380.609.","handbook":"","hbref":""},{"q":"What document must a new CDL applicant obtain FIRST in the Connecticut licensing process, before the full CDL?","options":["A Commercial Learner's Permit (CLP)","A DOT physical waiver from the DMV","A motor carrier operating authority (MC number)","A temporary interstate hauling certificate"],"answer":0,"explanation":"The process begins with passing the required knowledge tests to obtain a Commercial Learner's Permit (CLP). The applicant then practices, completes ELDT, and takes the skills test to convert the CLP into a CDL. Source: CT DMV, 'Get a commercial learner's permit' and 'Get a commercial driver's license.'","handbook":"","hbref":""},{"q":"How long is a Connecticut Commercial Learner's Permit (CLP) valid from its date of issuance?","options":["One year","60 days","Six months","Two years"],"answer":0,"explanation":"A Connecticut CLP is valid for one year from the date of issuance. If the holder does not obtain the CDL within that year, all required tests must be retaken to get a new permit. Source: CT DMV, 'Get a commercial learner's permit.'","handbook":"","hbref":""},{"q":"In Connecticut, how long must an applicant hold the CLP before being eligible to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 10 days","At least 60 days"],"answer":0,"explanation":"An applicant must hold the CLP for a minimum of 14 days before taking the CDL skills test. This federal minimum waiting period is enforced in Connecticut. Source: CT DMV, 'Get a commercial learner's permit'; 49 CFR 383.25(a)(3).","handbook":"","hbref":""},{"q":"The Connecticut CDL general knowledge test consists of 50 questions. How many must be answered correctly to pass?","options":["40 correct (80%)","35 correct (70%)","45 correct (90%)","30 correct (60%)"],"answer":0,"explanation":"The Connecticut general knowledge test has 50 multiple-choice questions and requires 40 correct answers (80%) to pass. Source: CT DMV, 'Get a commercial learner's permit.'","handbook":"","hbref":""},{"q":"How many separate parts make up the Connecticut CDL skills test?","options":["Three parts","Two parts","Four parts","Five parts"],"answer":0,"explanation":"The CDL skills test has three parts: the pre-trip vehicle inspection, the basic vehicle control skills test, and the on-road driving test. All three must be passed to earn the CDL. Source: CT DMV CDL testing; 49 CFR 383.113.","handbook":"","hbref":""},{"q":"Which of the following is one of the three required parts of the Connecticut CDL skills test?","options":["The pre-trip vehicle inspection","The 50-question general knowledge test","The DOT physical examination","The air brakes written endorsement test"],"answer":0,"explanation":"The three skills-test parts are the pre-trip vehicle inspection, basic vehicle control, and on-road driving. The general knowledge and air brakes tests are WRITTEN knowledge tests (taken for the CLP), and the DOT physical is a medical exam — none of these is part of the skills test. Source: CT DMV; 49 CFR 383.113.","handbook":"","hbref":""},{"q":"During the Connecticut CDL road test, the part where the applicant demonstrates maneuvers such as a straight-line backing or offset backing in a controlled area is called the:","options":["Basic vehicle control skills test","Pre-trip inspection test","On-road driving test","Combination vehicle test"],"answer":0,"explanation":"Backing and positioning maneuvers performed off public roads are part of the basic vehicle control skills test, the second of the three skills-test components. The pre-trip is the inspection, and the on-road test is conducted in traffic. Source: CT DMV; 49 CFR 383.113(b).","handbook":"","hbref":""},{"q":"If a Connecticut CDL applicant does not take or does not pass the air brakes knowledge test, what happens to the license?","options":["An 'L' restriction is placed, barring operation of any CMV equipped with air brakes","The applicant is denied a CDL entirely until air brakes is passed","A 'K' restriction limiting the driver to intrastate operation is added","Nothing — air brakes is optional and leaves no restriction"],"answer":0,"explanation":"A driver who fails to pass the air brakes knowledge test (and the related skills checks) receives an 'L' restriction, which prohibits operating any CMV equipped with air brakes. Source: CT DMV CLP/CDL information; 49 CFR 383.95.","handbook":"","hbref":""},{"q":"Federal CDL rules applied in Connecticut require each CDL/CLP holder to 'self-certify.' How many self-certification driving-type categories does the federal framework define?","options":["Four","Two","Three","Six"],"answer":0,"explanation":"The federal self-certification framework defines four categories: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). Connecticut's online self-certification practically presents the two non-excepted options most drivers use (NI and NA). Source: 49 CFR 383.71(b); CT DMV self-certification.","handbook":"","hbref":""},{"q":"A Connecticut driver who self-certifies as 'Non-Excepted Interstate' (NI) is making which statement about their operation and medical status?","options":["They operate across state lines and must meet the federal DOT medical certificate requirement","They operate only within Connecticut and are exempt from DOT medical requirements","They operate across state lines but are exempt from any medical certificate","They operate only within Connecticut and must carry a hazardous materials permit"],"answer":0,"explanation":"Non-Excepted Interstate (NI) means the driver operates a CMV in interstate commerce (in and outside Connecticut) and is subject to and must meet the federal DOT medical certification requirements. Source: CT DMV self-certification; 49 CFR 383.71(b).","handbook":"","hbref":""},{"q":"A Connecticut driver who self-certifies as 'Non-Excepted Intrastate' (NA) is certifying that they will:","options":["Operate a commercial motor vehicle only within the boundaries of Connecticut","Operate across state lines under a federal medical waiver","Operate nationwide without any medical certification","Operate only farm equipment exempt from CDL rules"],"answer":0,"explanation":"Non-Excepted Intrastate (NA) certifies operation of a CMV only within Connecticut. Such drivers may carry a 'K' restriction limiting them to intrastate driving and must meet Connecticut's medical/driver-qualification standards. Source: CT DMV self-certification (dmvselfservice.ct.gov).","handbook":"","hbref":""},{"q":"How does a CDL/CLP holder complete the self-certification step with the Connecticut DMV?","options":["Submit it through the DMV online self-service system and bring the printed email confirmation to the DMV","Have the medical examiner mail a paper certification to FMCSA headquarters","Self-certify only at the time of the road test, verbally to the examiner","File the certification with the Connecticut Department of Labor"],"answer":0,"explanation":"The driver self-certifies online through the Connecticut DMV self-service portal (dmvselfservice.ct.gov), receives an email confirmation, and brings that printed confirmation to the DMV when applying, renewing, upgrading, or changing driving type. Source: CT DMV self-certification.","handbook":"","hbref":""},{"q":"Which form must a certified medical examiner use to document a Connecticut CDL holder's DOT physical, and how does it reach the DMV?","options":["Form MCSA-5876, uploaded by the examiner through the National Registry and sent to the DMV electronically","Form R-229a, mailed by the applicant to the DMV within 30 days","Form MCSA-5876, hand-carried by the driver and scanned at any DMV branch","A handwritten doctor's note, faxed by the applicant to FMCSA"],"answer":0,"explanation":"The DOT medical exam must be recorded on Form MCSA-5876 (Medical Examiner's Certificate) by an examiner listed on the National Registry of Certified Medical Examiners; the examiner uploads the results through the National Registry, and they are transmitted to the Connecticut DMV electronically. Source: CT DMV, 'Getting medical certification for CDL.'","handbook":"","hbref":""},{"q":"What happens to a Connecticut CDL if the holder fails to keep a valid DOT medical certificate on file with the DMV?","options":["After a downgrade notice, the license is downgraded to a non-commercial Class D license","The CDL is permanently revoked and cannot be reinstated","A $500 federal civil penalty is automatically assessed each month","Nothing changes until the regular renewal date arrives"],"answer":0,"explanation":"If a valid medical certificate is not maintained, the driver's medical status becomes 'Not Certified'; the DMV sends a downgrade notice, and if a new valid certificate is not received electronically by the stated date, the CDL is downgraded to a Class D (non-commercial) license. Source: CT DMV, 'Getting medical certification for CDL.'","handbook":"","hbref":""},{"q":"How often must a Connecticut Commercial Driver License be renewed?","options":["Every four years","Every six years","Every two years","Every eight years"],"answer":0,"explanation":"A Connecticut CDL is issued on a four-year renewal cycle (renewing around the holder's birthday), shorter than the standard non-commercial license term. Source: CT DMV, 'Renew a CDL (commercial) license'; Conn. Gen. Stat. § 14-44h.","handbook":"","hbref":""}],"ru":{"0":{"q":"Согласно законодательству штата Коннектикут, какова максимальная ширина коммерческого транспортного средства (без учёта устройств безопасности, таких как зеркала), которое разрешено эксплуатировать на автомагистралях Коннектикута без специального разрешения?","options":["96 дюймов (8 футов)","102 дюйма (8 футов 6 дюймов)","108 дюймов (9 футов)","120 дюймов (10 футов)"],"explanation":"Раздел 14-262 Свода законов штата Коннектикут (Connecticut General Statutes Sec. 14-262) устанавливает максимальную законную ширину транспортного средства в 102 дюйма (8 футов 6 дюймов) без учёта устройств безопасности, таких как зеркала. В справочном листе CTDOT Vehicle Size and Weight Limitations указана ширина 102,37 дюйма. Источник: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"1":{"q":"Какова максимальная высота, включая груз, которую может иметь транспортное средство в Коннектикуте, прежде чем потребуется специальное разрешение на высоту от Уполномоченного по транспорту (Commissioner of Transportation)?","options":["12 футов 6 дюймов","13 футов 0 дюймов","13 футов 6 дюймов","14 футов 0 дюймов"],"explanation":"Раздел 14-264 Свода законов штата Коннектикут (Connecticut General Statutes Sec. 14-264) запрещает эксплуатацию транспортного средства, высота которого вместе с грузом превышает 13 футов 6 дюймов, без специального письменного разрешения (за исключением груза рыхлого сена или соломы). Источник: CGS Sec. 14-264; CTDOT Vehicle Size and Weight Limitations."},"2":{"q":"Какова в Коннектикуте максимальная длина, включая груз, одиночного (прямого) грузовика, эксплуатируемого без разрешения?","options":["40 футов","45 футов","48 футов","53 фута"],"explanation":"Раздел 14-262 Свода законов штата Коннектикут (Connecticut General Statutes Sec. 14-262) ограничивает максимальную длину одиночного транспортного средства, включая груз, до 45 футов. Источник: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations (\"Single unit vehicle 45 feet\")."},"3":{"q":"Для тягача, буксирующего один полуприцеп по обычным (неограниченным) автомагистралям Коннектикута, какова максимальная законная длина полуприцепа?","options":["45 футов","48 футов","53 фута","57 футов"],"explanation":"На обычных автомагистралях Коннектикут разрешает сочетание тягача и 48-футового полуприцепа без ограничения общей длины, но сам прицеп ограничен 48 футами. Источник: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"4":{"q":"На обозначенной (ограниченной) системе автомагистралей Коннектикута разрешён 53-футовый полуприцеп при условии, что расстояние от шкворня до центра самой задней оси не превышает какого значения?","options":["41 фут","43 фута","45 футов","48 футов"],"explanation":"На обозначенной системе автомагистралей Коннектикут разрешает сочетание тягача и 53-футового полуприцепа без ограничения общей длины, но расстояние от шкворня до центра самой задней оси не должно превышать 43 фута. Источник: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"5":{"q":"На обозначенной системе автомагистралей Коннектикута тягач, буксирующий сдвоенные (двойные) прицепы, может иметь каждый прицеп длиной до какого максимума?","options":["27 футов","28 футов","33 фута","40 футов"],"explanation":"На обозначенной системе автомагистралей Коннектикут разрешает сочетание тягача и сдвоенных прицепов без ограничения общей длины, но каждый прицеп ограничен 28 футами. Источник: CTDOT Vehicle Size and Weight Limitations (Restricted to the Designated Highway System)."},"6":{"q":"Какой максимальный полный вес транспортного средства может перевозить 5-осное сочетание по автомагистралям Коннектикута без разрешения на превышение веса, при соблюдении требований мостовой формулы?","options":["73 000 фунтов","80 000 фунтов","88 000 фунтов","90 000 фунтов"],"explanation":"Максимальный практически допустимый вес в Коннектикуте составляет 80 000 фунтов на 5 осях с расстоянием 51 фут между первой и последней осью, что разрешено при соблюдении требований Федеральной мостовой формулы (Federal Bridge Formula). Источник: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"7":{"q":"Какова в Коннектикуте максимальная нагрузка, допустимая на одну ось, когда эта ось расположена на расстоянии 6 футов или более от соседних осей?","options":["18 000 фунтов","20 000 фунтов","22 400 фунтов","24 000 фунтов"],"explanation":"Коннектикут допускает 22 400 фунтов на ось, когда оси расположены на расстоянии 6 футов или более друг от друга; оси, расположенные на расстоянии менее 6 футов друг от друга, ограничены 18 000 фунтов на ось. Источник: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"8":{"q":"Согласно правилам по весу Коннектикута, какова максимальная нагрузка, допустимая на любую одну ось, когда эта ось расположена на расстоянии МЕНЕЕ 6 футов от соседней оси?","options":["16 000 фунтов","18 000 фунтов","20 000 фунтов","22 400 фунтов"],"explanation":"Коннектикут ограничивает оси, расположенные на расстоянии менее 6 футов друг от друга, до 18 000 фунтов на ось; только при расстоянии 6 футов или более допускается 22 400 фунтов. Источник: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a."},"9":{"q":"Когда полный вес сочленённого транспортного средства в Коннектикуте превышает 73 000 фунтов (до 80 000 фунтов), какое дополнительное требование должно быть выполнено?","options":["Транспортное средство должно использовать только цельнорезиновые шины","Должны быть выполнены все требования Федеральной мостовой формулы (Federal Bridge Formula)","Транспортное средство должно передвигаться только ночью","Транспортное средство должно сопровождаться полицейским эскортом"],"explanation":"Согласно CTDOT, максимальный полный вес 80 000 фунтов разрешён только при выполнении всех требований Федеральной мостовой формулы (Federal Bridge Formula) для весов свыше 73 000 фунтов. Источник: CTDOT Vehicle Size and Weight Limitations (Gross Vehicle Weights Over 73,000 pounds)."},"10":{"q":"В Коннектикуте максимально допустимая нагрузка, передаваемая на дорогу шинами любого транспортного средства, основана на ширине шины. Каково это ограничение?","options":["500 фунтов на дюйм ширины шины","600 фунтов на дюйм ширины шины","700 фунтов на дюйм ширины шины","800 фунтов на дюйм ширины шины"],"explanation":"Коннектикут ограничивает нагрузку на шины до 600 фунтов на дюйм ширины шины (максимум). Источник: CTDOT Vehicle Size and Weight Limitations (Tires - Load per inch width of tire 600 pounds maximum)."},"11":{"q":"Какой максимальный полный вес допускается в Коннектикуте для 2-осного прямого грузовика, когда нагрузка ни на одну ось не превышает 18 000 фунтов?","options":["32 000 фунтов","36 000 фунтов","40 000 фунтов","53 800 фунтов"],"explanation":"Коннектикут допускает 2-осное транспортное средство весом до 36 000 фунтов, когда нагрузка на ось не превышает 18 000 фунтов (32 000 фунтов — это значение без указанного условия по оси). Источник: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a."},"12":{"q":"Для сочетания тягача с полуприцепом в Коннектикуте, каков максимальный полный вес, когда сочетание имеет 3 оси?","options":["53 800 фунтов","58 400 фунтов","67 400 фунтов","73 000 фунтов"],"explanation":"Коннектикут устанавливает для 3-осного сочетания тягача с полуприцепом максимум 58 400 фунтов; 4-осное сочетание — 67 400 фунтов, а 5 или более осей — до 73 000 фунтов. Источник: CTDOT Vehicle Size and Weight Limitations (Tractor Semitrailer)."},"13":{"q":"Федеральный стандарт по весу, который Коннектикут применяет для определения максимального полного веса, допустимого на группу последовательных осей, известен как:","options":["Федеральное правило разброса осей (Federal Axle Spread Rule)","Федеральная мостовая формула (Federal Bridge Formula)","Федеральный стандарт полного веса сочетания (Federal Gross Combination Standard)","Федеральная таблица веса сдвоенных осей (Federal Tandem Weight Table)"],"explanation":"Коннектикут применяет Федеральную мостовую формулу (Federal Bridge Formula) для определения допустимого веса на группы осей; она должна быть соблюдена для полных весов свыше 73 000 фунтов и до 80 000 фунтов. Источник: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"14":{"q":"В Коннектикуте кто выдаёт разрешения для негабаритных/перевесных (несоответствующих) транспортных средств, и через какую систему подаются заявления?","options":["Уполномоченный по транспорту (Commissioner of Transportation), через управляемый DMV веб-портал Commercial Vehicle Operations (CVO) WebPortal","Местное отделение полиции каждого города, через который проезжает транспортное средство","Онлайн-портал Федерального управления безопасности автотранспортных перевозчиков (Federal Motor Carrier Safety Administration)","Департамент энергетики и охраны окружающей среды (Department of Energy and Environmental Protection) по бумажному заявлению"],"explanation":"Согласно CGS Sec. 14-270, Уполномоченный по транспорту (Commissioner of Transportation) выдаёт специальные разрешения для несоответствующих (негабаритных/перевесных) транспортных средств; заявления обрабатываются через веб-портал Connecticut Commercial Vehicle Operations (CVO) WebPortal, управляемый Connecticut DMV. Источник: CGS Sec. 14-270; CTDOT Oversize/Overweight Permit FAQ."},"15":{"q":"Стандартное разрешение Коннектикута на одну поездку для негабаритного/перевесного транспортного средства, как правило, действительно в течение какого периода, и движение ограничено какими часами?","options":["30 дней; в любое время дня или ночи","3 дня; только в светлое время суток","7 дней; только в ночное время","1 день; за исключением часов пик"],"explanation":"CTDOT выдаёт разрешения на одну поездку для негабаритных/перевесных транспортных средств сроком на 3 дня, с движением, ограниченным светлым временем суток (как правило, от получаса после восхода солнца до получаса до заката). Источник: CTDOT Vehicle Size and Weight Limitations; CTDOT Oversize/Overweight Permit FAQ."},"16":{"q":"Согласно законодательству Коннектикута (CGS Sec. 14-267a), каков штраф за эксплуатацию перевесного коммерческого транспортного средства, исходя из величины избыточного веса?","options":["$1 за каждые 100 фунтов избыточного веса","$3 за каждые 100 фунтов (или их часть) избыточного веса","$10 за каждые 100 фунтов избыточного веса","Фиксированные $500 независимо от избыточного веса"],"explanation":"Раздел 14-267a Свода законов штата Коннектикут (Connecticut General Statutes Sec. 14-267a) устанавливает штраф за превышение веса в размере трёх долларов за каждые сто фунтов или их часть избыточного веса. Источник: CGS Sec. 14-267a."},"17":{"q":"Коннектикут предоставляет специальную весовую льготу для некоторых сельскохозяйственных перевозок. Каков максимальный полный вес транспортного средства, допустимый для автоцистерны для сбора молока навалом или транспортного средства, перевозящего сельскохозяйственные товары (там, где это разрешено федеральным законом)?","options":["80 000 фунтов","88 000 фунтов","100 000 фунтов","120 000 фунтов"],"explanation":"Раздел 14-267a Свода законов штата Коннектикут (Connecticut General Statutes Sec. 14-267a) устанавливает допустимый полный вес до 100 000 фунтов для автоцистерн для сбора молока навалом и транспортных средств, перевозящих сельскохозяйственные товары (корма, семена, удобрения и продукты сельского хозяйства), там, где это разрешено федеральным законом. Источник: CGS Sec. 14-267a."},"18":{"q":"Согласно CGS Sec. 14-267a, для транспортного средства с двумя последовательными группами сдвоенных осей полный груз в 68 000 фунтов на этих сдвоенных осях допускается только в том случае, если расстояние между первой и последней осью двух групп составляет не менее:","options":["30 футов","34 фута","36 футов","40 футов"],"explanation":"Раздел 14-267a Свода законов штата Коннектикут (Connecticut General Statutes Sec. 14-267a) допускает, чтобы две последовательные группы сдвоенных осей несли полный груз в 68 000 фунтов при условии, что общее расстояние между первой и последней осями этих последовательных групп сдвоенных осей составляет 36 футов или более. Источник: CGS Sec. 14-267a."},"19":{"q":"Каков в Коннектикуте минимальный полный разрешённый вес транспортного средства (GVWR), при котором одиночное транспортное средство относится к категории CDL класса B?","options":["16 001 фунт или более","26 001 фунт или более","10 001 фунт или более","33 001 фунт или более"],"explanation":"CDL класса B в Коннектикуте даёт право управлять любым одиночным транспортным средством с GVWR 26 001 фунт или более, а также любым таким транспортным средством, буксирующим единицу весом не более 10 000 фунтов. Источник: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"20":{"q":"Согласно правилам Коннектикута, CDL класса A требуется для управления сочетанием транспортных средств с GVWR 26 001 фунт или более при условии, что GVWR буксируемой единицы превышает какое значение?","options":["5 000 фунтов","26 001 фунт","10 000 фунтов","15 000 фунтов"],"explanation":"CDL класса A в Коннектикуте охватывает сочетания с GVWR 26 001 фунт или более, где GVWR буксируемого транспортного средства превышает 10 000 фунтов. Источник: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"21":{"q":"Водитель в Коннектикуте управляет одиночным транспортным средством с GVWR менее 26 001 фунта, рассчитанным на перевозку 20 пассажиров, включая водителя. Какой класс CDL применяется?","options":["Класс A","Класс B","Класс C","CDL не требуется"],"explanation":"CDL класса C в Коннектикуте охватывает одиночное транспортное средство с GVWR менее 26 001 фунта (или буксирующее единицу весом не более 10 000 фунтов), которое рассчитано на перевозку 16 или более пассажиров, включая водителя, либо перевозит опасные материалы, требующие табличек (placards). Источник: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"22":{"q":"Каков минимальный возраст для получения CDL Коннектикута с ограничением только для внутриштатной (только в пределах Коннектикута) эксплуатации?","options":["16","18","19","21"],"explanation":"Коннектикут требует, чтобы заявитель был не моложе 18 лет для внутриштатного CDL (эксплуатация только в пределах Коннектикута). Источник: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"23":{"q":"Каков минимальный возраст, требуемый для управления коммерческим автотранспортным средством в межштатных перевозках по CDL Коннектикута?","options":["18","19","20","21"],"explanation":"Коннектикут требует, чтобы заявитель был не моложе 21 года для межштатной эксплуатации (в пределах и за пределами Коннектикута). Источник: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"24":{"q":"Какое подтверждение (endorsement) требует Коннектикут для управления транспортным средством, перевозящим опасные материалы в количествах, требующих табличек (placards)?","options":["Подтверждение N","Подтверждение H","Подтверждение T","Подтверждение X"],"explanation":"Коннектикут требует подтверждение H (HazMat, опасные материалы) для управления транспортным средством, перевозящим опасные материалы, требующие табличек (placards). Источник: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"25":{"q":"В Коннектикуте подтверждение N (цистерна/наливной груз навалом) требуется для стационарно установленной грузовой цистерны с минимальной номинальной вместимостью какого значения?","options":["100 галлонов или более","119 галлонов или более","500 галлонов или более","1 000 галлонов или более"],"explanation":"Коннектикут требует подтверждение N для транспортного средства, предназначенного для перевозки жидкости или сжиженного газа в стационарно установленной грузовой цистерне с номинальной вместимостью 119 галлонов или более (либо в переносной цистерне с номинальной вместимостью 1 000 галлонов или более). Источник: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"26":{"q":"Какое подтверждение Коннектикута требуется для буксировки более чем одного прицепа транспортным средством, требующим CDL класса A?","options":["Подтверждение P","Подтверждение N","Подтверждение T","Подтверждение S"],"explanation":"Коннектикут требует подтверждение T (Doubles/Triples, сдвоенные/строенные прицепы), когда транспортное средство с CDL класса A буксирует более одного прицепа. Источник: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"27":{"q":"Прежде чем водителю в Коннектикуте может быть выдано подтверждение S (школьный автобус), какое другое подтверждение водитель также должен иметь?","options":["H (опасные материалы)","N (цистерна)","P (пассажирское)","T (сдвоенные/строенные прицепы)"],"explanation":"В Коннектикуте подтверждение для школьного автобуса (S) также требует, чтобы владелец имел пассажирское подтверждение (P) и поддерживал приемлемый водительский стаж. Источник: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"28":{"q":"Согласно федеральным правилам, применяемым в Коннектикуте, как долго заявитель должен иметь разрешение учащегося на коммерческое вождение (CLP), прежде чем получить право сдавать экзамен на навыки вождения CDL (дорожный экзамен)?","options":["Не менее 7 дней","Не менее 14 дней","Не менее 30 дней","Не менее 60 дней"],"explanation":"Заявитель не может сдавать экзамен на навыки вождения CDL в течение 14 дней после первоначальной выдачи CLP; разрешение должно действовать минимум 14 дней. Источник: 49 CFR 383.25(e), применяемый Connecticut DMV."},"29":{"q":"Как долго действительно разрешение учащегося на коммерческое вождение (CLP) Коннектикута с даты выдачи?","options":["90 дней","180 дней","Один год","Два года"],"explanation":"CLP Коннектикута остаётся действительным в течение одного года с даты выдачи; если CDL не получен в течение этого периода, заявитель должен повторно сдать требуемые экзамены. Источник: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"30":{"q":"С 7 февраля 2022 года кто должен пройти обучение водителей начального уровня (ELDT) через зарегистрированного в FMCSA поставщика, прежде чем сдавать экзамен в Коннектикуте?","options":["Только заявители на подтверждение hazmat","Любой, кто продлевает существующий CDL","Впервые подающие на CDL, повышающие класс B до класса A, а также впервые подающие на подтверждение H, P или S","Только водители моложе 21 года"],"explanation":"С 7 февраля 2022 года ELDT требуется для впервые подающих на CDL, водителей, повышающих класс B до класса A, и впервые подающих на подтверждение H, P или S, причём обучение проводится поставщиком из реестра поставщиков обучения FMCSA (FMCSA Training Provider Registry). Источник: FMCSA ELDT rule (49 CFR Part 380); CT DMV CDL pages (portal.ct.gov/dmv)."},"31":{"q":"Обучение водителей начального уровня (ELDT) для заявителя в Коннектикуте должно быть пройдено через какую систему?","options":["Учебный портал Connecticut DMV","Реестр поставщиков обучения FMCSA (FMCSA Training Provider Registry, TPR)","Систему регистрации TSA","Информационную систему по наркотикам и алкоголю (Drug and Alcohol Clearinghouse)"],"explanation":"ELDT должно быть пройдено у поставщика, указанного в реестре поставщиков обучения FMCSA (TPR), который сообщает о завершении обучения водителем в FMCSA. Источник: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov); CT DMV CDL pages."},"32":{"q":"Для подтверждения по опасным материалам (H) требование ELDT состоит из какого типа обучения?","options":["Только теоретическое обучение","Только обучение за рулём","Как теоретическое обучение, так и обучение за рулём","Для hazmat ELDT не требуется"],"explanation":"Требование ELDT для подтверждения hazmat (H) — только теоретическое; компонента обучения за рулём нет, в отличие от классов A/B и подтверждений P и S. Источник: FMCSA ELDT rule (49 CFR Part 380); FMCSA Training Provider Registry."},"33":{"q":"Помимо требований по знаниям и ELDT, какую дополнительную федеральную проверку должен пройти заявитель в Коннектикуте, чтобы получить подтверждение hazmat (H)?","options":["Только медосмотр DOT","Оценку угрозы безопасности TSA (TSA Security Threat Assessment), включая снятие отпечатков пальцев","Проверку кредитной истории штата","Только проверку зрения"],"explanation":"Подтверждение hazmat требует прохождения оценки угрозы безопасности TSA (TSA Security Threat Assessment), которая включает проверку биографических данных и снятие отпечатков пальцев, в дополнение к экзамену на знания и теоретическому обучению ELDT. Источник: TSA HazMat Endorsement Threat Assessment Program; CT DMV endorsement pages."},"34":{"q":"Какой набор документов требует Connecticut DMV при подаче заявления на разрешение учащегося на коммерческое вождение, в соответствии с REAL ID?","options":["Подтверждение личности, номер социального страхования, законное пребывание в США и два подтверждения проживания в Коннектикуте","Только паспорт","Свидетельство о рождении и счёт за коммунальные услуги","Только действующие водительские права Коннектикута"],"explanation":"Коннектикут требует документацию REAL ID: подтверждение личности, номер социального страхования, законное пребывание в США и два подтверждения проживания в Коннектикуте, а также подтверждение самосертификации и форму заявления R-229a. Источник: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"35":{"q":"Водитель в Коннектикуте, который будет управлять коммерческим транспортным средством как внутри, так и за пределами штата и должен иметь при себе медицинскую карту DOT, должен пройти самосертификацию по какой категории?","options":["Освобождённые межштатные (Excepted Interstate, EI)","Неосвобождённые межштатные (Non-excepted Interstate, NI)","Освобождённые внутриштатные (Excepted Intrastate, EA)","Неосвобождённые внутриштатные (Non-excepted Intrastate, NA)"],"explanation":"Категория «Неосвобождённые межштатные» (Non-excepted Interstate, NI) охватывает вождение внутри и за пределами Коннектикута и требует соответствия федеральным требованиям к медицинскому сертификату DOT. Источник: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)."},"36":{"q":"Какая категория самосертификации Коннектикута применяется к водителю, который управляет транспортным средством только в пределах Коннектикута и не обязан соответствовать федеральным требованиям к медицинской карте DOT?","options":["Неосвобождённые межштатные (Non-excepted Interstate, NI)","Неосвобождённые внутриштатные (Non-excepted Intrastate, NA)","Освобождённые внутриштатные (Excepted Intrastate, EA)","Освобождённые межштатные (Excepted Interstate, EI)"],"explanation":"Категория «Освобождённые внутриштатные» (Excepted Intrastate, EA) применяется к водителям, управляющим транспортным средством только в пределах Коннектикута, которые освобождены от требования к федеральному медицинскому сертификату DOT. Источник: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)."},"37":{"q":"Перед обработкой операции по CDL в Коннектикуте DMV проверяет статус заявителя в какой федеральной системе?","options":["База данных TSA PreCheck","Информационная система FMCSA по наркотикам и алкоголю (FMCSA Drug and Alcohol Clearinghouse)","Только Национальный реестр водителей (National Driver Register)","Система выборочной воинской службы (Selective Service System)"],"explanation":"Заявители в Коннектикуте должны зарегистрироваться в информационной системе FMCSA по наркотикам и алкоголю (FMCSA Drug and Alcohol Clearinghouse), и DMV проверяет статус заявителя в Clearinghouse перед обработкой операции по CDL. Источник: CT DMV CDL pages (portal.ct.gov/dmv); FMCSA Drug and Alcohol Clearinghouse."},"38":{"q":"Какой минимальный возраст и какой статус гражданства/иммиграции требует Коннектикут для подтверждения по опасным материалам (H)?","options":["Возраст 18, только гражданин США","Возраст 21, гражданин США, законный постоянный житель или владелец действующего разрешения на работу (Employment Authorization Document)","Возраст 19, любой законный житель","Возраст 21, только гражданин США"],"explanation":"Коннектикут требует, чтобы заявители на подтверждение hazmat (H) были не моложе 21 года и являлись гражданами США, законными постоянными жителями или имели действующее разрешение на работу (Employment Authorization Document). Источник: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"39":{"q":"Какова в Коннектикуте максимальная концентрация алкоголя в крови (BAC), при которой человек может законно управлять коммерческим автотранспортным средством (CMV)?","options":["0,04%","0,08%","0,02%","0,00%"],"explanation":"Коннектикут следует федеральному стандарту для CMV: запрещено управлять CMV с BAC 0,04% или более (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"40":{"q":"Управляя CMV в Коннектикуте, водитель автоматически считается давшим согласие на химический анализ на алкоголь. Как называется этот принцип?","options":["Подразумеваемое согласие (implied consent)","Достаточное основание (probable cause)","Прямой отказ от прав (express waiver)","Административный пересмотр (administrative review)"],"explanation":"Закон Коннектикута о подразумеваемом согласии (implied consent) считает любого лицензированного водителя давшим согласие на анализ крови, дыхания или мочи (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"41":{"q":"Владелец CDL в Коннектикуте осуждён за первое серьёзное нарушение (major offense), например, за управление CMV с BAC 0,04% или более. На какой срок CDL дисквалифицируется?","options":["Не менее 1 года","Не менее 90 дней","Не менее 6 месяцев","Не менее 3 лет"],"explanation":"Первое серьёзное нарушение (major offense) дисквалифицирует CDL не менее чем на один год (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"42":{"q":"Согласно правилам Коннектикута, если первое серьёзное нарушение (например, BAC 0,04 или отказ от анализа) происходит, когда водитель управляет CMV с табличками опасных материалов (placarded), дисквалификация составляет не менее:","options":["3 года","1 год","5 лет","18 месяцев"],"explanation":"Первое серьёзное нарушение во время управления CMV с табличками HazMat (placarded) дисквалифицирует CDL не менее чем на три года (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"43":{"q":"Каково наказание в виде дисквалификации в Коннектикуте для водителя, осуждённого за второе серьёзное нарушение (major offense) (например, второе вождение в нетрезвом виде или отказ от анализа)?","options":["Пожизненная дисквалификация","10-летняя дисквалификация","5-летняя дисквалификация","3-летняя дисквалификация"],"explanation":"Второе серьёзное нарушение (major offense) приводит к пожизненной дисквалификации CDL (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"44":{"q":"Владелец CDL в Коннектикуте впервые отказывается пройти химический анализ на алкоголь. На какой срок CDL дисквалифицируется за этот отказ?","options":["1 год","6 месяцев","60 дней","3 года"],"explanation":"Отказ пройти химический анализ (нарушение подразумеваемого согласия) дисквалифицирует CDL на один год при первом нарушении (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"45":{"q":"Согласно закону Коннектикута о подразумеваемом согласии, если человек отказывается от химического анализа, обычные (некоммерческие) водительские права подлежат приостановке на срок не менее:","options":["6 месяцев","30 дней","1 год","90 дней"],"explanation":"Отказ от химического анализа влечёт приостановку водительских прав на срок не менее шести месяцев; в случае приостановки CDL также дисквалифицируется (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"46":{"q":"В Коннектикуте водитель CMV, у которого обнаружено определяемое количество алкоголя ниже 0,04%, подвергается какому немедленному действию?","options":["Отстранение от эксплуатации (out-of-service) на 24 часа","Дисквалификация на 60 дней","Арест за вождение в нетрезвом виде","Штраф $500 без дальнейших действий"],"explanation":"Любое определяемое количество алкоголя ниже 0,04% приводит к отстранению от эксплуатации (out-of-service) на 24 часа (CT CDL Manual 1.3.2; 49 CFR 392.5)."},"47":{"q":"Что из перечисленного классифицируется как серьёзное нарушение правил дорожного движения (serious traffic violation) для владельца CDL в Коннектикуте?","options":["Превышение скорости на 15 миль/ч (mph) или более сверх установленного ограничения","Первое вождение в нетрезвом виде на CMV","Непрекращение движения на железнодорожном переезде","Нарушение предписания об отстранении от эксплуатации (out-of-service order)"],"explanation":"К серьёзным нарушениям правил дорожного движения относятся чрезмерное превышение скорости (на 15 миль/ч (mph) или более сверх ограничения), безрассудное вождение и беспорядочная смена полос; вождение в нетрезвом виде и нарушения предписаний об отстранении от эксплуатации (OOS) являются отдельными категориями (CT CDL Manual 1.3.3)."},"48":{"q":"Владелец CDL в Коннектикуте совершает два серьёзных нарушения правил дорожного движения в течение трёхлетнего периода. Минимальная дисквалификация составляет:","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение трёх лет дисквалифицируют CDL не менее чем на 60 дней (CT CDL Manual 1.3.3; 49 CFR 383.51)."},"49":{"q":"Если владелец CDL в Коннектикуте совершает три или более серьёзных нарушения правил дорожного движения в течение трёхлетнего периода, минимальная дисквалификация составляет:","options":["120 дней","60 дней","180 дней","1 год"],"explanation":"Три или более серьёзных нарушения правил дорожного движения в течение трёх лет дисквалифицируют CDL не менее чем на 120 дней (CT CDL Manual 1.3.3; 49 CFR 383.51)."},"50":{"q":"Что из перечисленного НЕ входит в список серьёзных нарушений правил дорожного движения Коннектикута?","options":["Движение со скоростью на 8 миль/ч (mph) выше установленного ограничения","Неправильная или беспорядочная смена полос","Слишком близкое следование за транспортным средством","Безрассудное вождение"],"explanation":"Серьёзные нарушения требуют превышения скорости на 15 миль/ч (mph) или более сверх ограничения; превышение на 8 миль/ч (mph) не квалифицируется, тогда как беспорядочная смена полос, следование вплотную и безрассудное вождение квалифицируются (CT CDL Manual 1.3.3)."},"51":{"q":"Владелец CDL в Коннектикуте совершает третье нарушение предписания об отстранении от эксплуатации (out-of-service order) в течение 10-летнего периода. Минимальная дисквалификация составляет:","options":["3 года","1 год","2 года","180 дней"],"explanation":"Третье или последующее нарушение предписания об отстранении от эксплуатации (out-of-service order) в течение 10 лет дисквалифицирует CDL не менее чем на 3 года (до 5) (CT CDL Manual 1.3.4; 49 CFR 383.51)."},"52":{"q":"Какова дисквалификация в Коннектикуте за ПЕРВОЕ осуждение за нарушение на железнодорожно-автомобильном переезде во время управления CMV?","options":["Не менее 60 дней","Не менее 30 дней","Не менее 120 дней","Не менее 180 дней"],"explanation":"Первое нарушение на железнодорожно-автомобильном переезде дисквалифицирует CDL не менее чем на 60 дней (CT CDL Manual 1.3.5; 49 CFR 383.51)."},"53":{"q":"За ВТОРОЕ нарушение на железнодорожно-автомобильном переезде в течение трёх лет владелец CDL в Коннектикуте дисквалифицируется не менее чем на:","options":["120 дней","60 дней","180 дней","1 год"],"explanation":"Второе нарушение на переезде в течение трёх лет дисквалифицирует CDL не менее чем на 120 дней (CT CDL Manual 1.3.5; 49 CFR 383.51)."},"54":{"q":"Согласно правилам Коннектикута и федеральным правилам для CMV, водитель, осуждённый за два или более нарушения, связанных с удержанием/использованием мобильного телефона в руке во время управления CMV, подвергается дисквалификации на 60 дней за второе нарушение и на какой срок за три или более нарушений в течение трёх лет?","options":["120 дней","60 дней","180 дней","1 год"],"explanation":"Использование мобильного телефона в руке во время управления CMV влечёт дисквалификацию на 60 дней за второе нарушение и на 120 дней за три или более в течение трёх лет (CT CDL Manual 2.9.4; 49 CFR 383.51)."},"55":{"q":"После осуждения за любое нарушение правил дорожного движения (кроме парковки) в течение скольких дней владелец CDL в Коннектикуте должен уведомить своего работодателя?","options":["30 дней","2 дня","10 дней","60 дней"],"explanation":"Владелец CDL должен уведомить своего работодателя в течение 30 дней с момента осуждения за любое нарушение правил дорожного движения, независимо от того, каким транспортным средством он управлял (CT CDL Manual 1.4; 49 CFR 383.31)."},"56":{"q":"Согласно закону Коннектикута о железнодорожных переездах, где должен остановиться автобус, школьный автобус или коммерческий транспорт с цистерной либо с табличками опасных грузов перед пересечением путей на одном уровне?","options":["Не ближе 15 футов и не дальше 50 футов от ближайшего рельса","Точно в 25 футах от ближайшего рельса","Не ближе 10 футов и не дальше 40 футов от ближайшего рельса","Не ближе 50 футов и не дальше 100 футов от ближайшего рельса"],"explanation":"Свод законов штата Коннектикут, раздел 14-250, и руководство CT CDL Manual требуют, чтобы автобусы, транспорт с пассажирами, транспорт для перевозки школьников и коммерческие транспортные средства с цистернами или опасными грузами останавливались не ближе 15 футов и не дальше 50 футов от ближайшего рельса, после чего водитель должен посмотреть и прислушаться, прежде чем пересекать пути."},"57":{"q":"Когда водитель в Коннектикуте приближается к стоящему аварийному транспортному средству с мигающими огнями на многополосном шоссе, что требует от него закон штата \"Move Over\"?","options":["Снизить скорость до разумного уровня и, находясь в соседней полосе, перестроиться на одну полосу, когда это безопасно","Полностью остановиться, пока аварийное транспортное средство не покинет место происшествия","Сохранять установленную скорость, но подать звуковой сигнал","Перестроиться на одну полосу, только если аварийное транспортное средство — полицейская машина"],"explanation":"Свод законов штата Коннектикут, раздел 14-283b (закон \"Move Over\"), требует от водителей немедленно снизить скорость до разумной величины ниже установленного ограничения и, двигаясь по полосе, прилегающей к обочине, перестроиться на одну полосу, если только такой маневр не будет небезопасным."},"58":{"q":"На разделённом скоростном шоссе ограниченного доступа в Коннектикуте с тремя или более полосами в одном направлении, где штат это обозначил, какому транспортному средству запрещено двигаться по крайней левой полосе?","options":["Грузовику с коммерческой регистрацией","Легковому автомобилю с одним человеком","Мотоциклу","Машине скорой помощи, выезжающей по вызову"],"explanation":"Свод законов штата Коннектикут, раздел 14-230a, запрещает коммерчески зарегистрированным транспортным средствам, автобусам, транспорту с прицепами и школьным автобусам движение по крайней левой полосе на разделённых шоссе ограниченного доступа с тремя или более полосами (в одном направлении), где это обозначило Управление по организации дорожного движения штата; штраф составляет $88."},"59":{"q":"На каких дорогах в Коннектикуте запрещено движение коммерческого транспорта, такого как тягачи с полуприцепами и фургоны?","options":["Парквеи Merritt, Wilbur Cross и Milford (коридор Route 15)","Interstate 95 и Interstate 84","Все дороги штата с номерами выше 100","Скоростные дороги Route 9 и Route 2"],"explanation":"Парквеи Коннектикута — Merritt Parkway и Wilbur Cross Parkway (Route 15), а также Milford Parkway — запрещают движение коммерческого транспорта, прицепов и негабаритных транспортных средств, в основном из-за низких исторических путепроводов. CT DOT Parkway Restrictions; штраф за нарушение на парквее составляет $500 за каждое нарушение."},"60":{"q":"На шоссе в Коннектикуте, где полосы разделены защитным островком или физическим барьером, что должен делать водитель на ПРОТИВОПОЛОЖНОЙ стороне барьера, когда школьный автобус остановился с мигающими красными огнями?","options":["Водитель может продолжать движение без остановки","Водитель должен остановиться, пока красные огни не будут выключены","Водитель должен остановиться, только если у автобуса открыта дверь","Водитель должен снизить скорость до 15 mph, но останавливаться не обязан"],"explanation":"Свод законов штата Коннектикут, раздел 14-279, предусматривает, что на шоссе, где полосы разделены защитным островком или физическим барьером, водитель на противоположной стороне этого барьера может продолжать движение без остановки перед школьным автобусом. Одна лишь нарисованная линия НЕ подходит — в этом случае останавливаться должны в обоих направлениях."},"61":{"q":"На дороге в Коннектикуте, разделённой только нарисованной осевой линией (без физического барьера), что должен делать водитель при встрече с остановившимся школьным автобусом с мигающими красными огнями на противоположной стороне?","options":["Остановиться, поскольку нарисованная линия не подпадает под исключение для разделённых шоссе","Продолжать движение со сниженной скоростью без остановки","Продолжать движение без ограничений, поскольку это встречный поток","Остановиться, только если видно, что переходят дети"],"explanation":"Согласно Своду законов штата Коннектикут, раздел 14-279, исключение, разрешающее не останавливаться, применяется только там, где полосы разделены защитным островком или физическим барьером. При наличии лишь нарисованной линии транспортные средства с обеих сторон должны полностью остановиться перед школьным автобусом с мигающими красными огнями."},"62":{"q":"Насколько близко водитель в Коннектикуте может приблизиться спереди к остановившемуся школьному автобусу с мигающими красными огнями, прежде чем обязан остановиться?","options":["Не ближе 10 футов от передней части автобуса","Не ближе 5 футов от передней части автобуса","Не ближе 20 футов от передней части автобуса","Не ближе 25 футов от передней части автобуса"],"explanation":"Свод законов штата Коннектикут, раздел 14-279, требует, чтобы транспортные средства останавливались не ближе 10 футов от передней части при приближении и не ближе 10 футов от задней части при обгоне или следовании за зарегистрированным школьным автобусом с мигающими красными сигнальными огнями."},"63":{"q":"После остановки неисправного коммерческого транспортного средства на дороге с односторонним движением или разделённом шоссе в Коннектикуте, где водитель должен разместить три светоотражающих предупреждающих треугольника?","options":["На 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта","На 10 футов, 50 футов и 150 футов позади транспортного средства","На 25 футов, 75 футов и 125 футов в сторону приближающегося транспорта","На 5 футов, 50 футов и 500 футов в сторону приближающегося транспорта"],"explanation":"Руководство Connecticut CDL Manual (отражая 49 CFR 392.22) указывает, что на дороге с односторонним движением или разделённом шоссе предупреждающие устройства размещаются на 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта позади остановившегося транспортного средства."},"64":{"q":"В течение скольких минут водитель с CDL в Коннектикуте должен выставить аварийные предупреждающие устройства после остановки коммерческого транспортного средства на дороге или обочине?","options":["В течение 10 минут","В течение 30 минут","В течение 5 минут","Немедленно, до выхода из кабины"],"explanation":"Руководство Connecticut CDL Manual гласит, что если вам пришлось остановиться на дороге или обочине, вы должны включить аварийную сигнализацию и выставить аварийные предупреждающие устройства в течение 10 минут."},"65":{"q":"Какой перечень правильно определяет транспортные средства в Коннектикуте, которые должны ОСТАНАВЛИВАТЬСЯ на каждом железнодорожном переезде на одном уровне?","options":["Автобусы с пассажирами, транспорт для перевозки школьников и коммерческие транспортные средства с цистернами или перевозящие опасные грузы","Все коммерческие транспортные средства тяжелее 10 000 фунтов независимо от груза","Только пустые автоцистерны и эвакуаторы","Только транспортные средства, буксирующие прицеп"],"explanation":"Свод законов штата Коннектикут, раздел 14-250, требует, чтобы водитель каждого коммерческого транспортного средства, перевозящего пассажиров, служебного автобуса или транспорта, используемого для перевозки школьников, а также каждого коммерческого транспортного средства с цистерной или перевозящего опасные грузы, останавливался на расстоянии от 15 до 50 футов от ближайшего рельса перед пересечением путей."},"66":{"q":"Каково максимальное установленное ограничение скорости, с которым коммерческое транспортное средство может законно двигаться по межштатной автомагистрали в Коннектикуте?","options":["65 mph — то же максимальное значение, что и для легковых автомобилей","55 mph — особое пониженное ограничение для всех грузовиков по всему штату","70 mph на сельских межштатных автомагистралях","60 mph для любого транспортного средства тяжелее 26 000 фунтов"],"explanation":"Максимальное установленное ограничение скорости в Коннектикуте составляет 65 mph (CGS Sec. 14-219 / 14-218a), и штат не устанавливает отдельного, более низкого ограничения скорости для грузовиков по всему штату — грузовики и легковые автомобили имеют одинаковый максимум 65 mph там, где он установлен. Водители по-прежнему обязаны соблюдать любые более низкие установленные ограничения."},"67":{"q":"На двухполосной дороге в Коннектикуте с движением в обоих направлениях (неразделённой), где водитель коммерческого транспортного средства должен разместить три предупреждающих треугольника после остановки?","options":["В пределах 10 футов от транспортного средства, а также в 100 футах впереди и в 100 футах позади него","На 10 футов, 100 футов и 200 футов только позади транспортного средства","В 50 футах впереди и в 50 футах позади транспортного средства","В пределах 10 футов спереди и сзади, а также в 250 футах в каждом направлении"],"explanation":"Руководство Connecticut CDL Manual предписывает, что на двухполосной дороге с двусторонним движением или неразделённом шоссе следует разместить один треугольник в пределах 10 футов от транспортного средства и по одному в 100 футах позади и в 100 футах впереди, на обочине или в полосе, где вы остановились."},"68":{"q":"Согласно правилу Коннектикута о движении по правой стороне, где должно двигаться транспортное средство, идущее медленнее обычной скорости потока?","options":["По правой полосе или как можно ближе к правому краю проезжей части","По любой полосе, пока включена аварийная сигнализация","По центральной полосе трёхполосной дороги","По левой полосе, чтобы держаться в стороне от вливающегося потока"],"explanation":"Свод законов штата Коннектикут, раздел 14-230, требует, чтобы транспортные средства двигались по правой стороне, а любое транспортное средство, движущееся медленнее обычной скорости потока, двигалось по доступной правой полосе или как можно ближе к правому бордюру или краю проезжей части."},"69":{"q":"Какое наказание налагает Коннектикут за управление коммерческим транспортным средством на парквее штата, где такие транспортные средства запрещены?","options":["Штраф $500 за каждое нарушение","Только письменное предупреждение при первом нарушении","Штраф $35 плюс два штрафных балла","Обязательное приостановление действия прав на 30 дней"],"explanation":"Коннектикут увеличил наказание за управление запрещённым коммерческим транспортным средством на парквее (Merritt, Wilbur Cross, Milford) до $500 за каждое нарушение. CT DOT Parkway Restrictions; полномочия по ограничениям на парквеях — CGS Chapter 249 / Sec. 14-298."},"70":{"q":"Помимо аварийных транспортных средств, закон Коннектикута \"Move Over\" также требует от водителей снижать скорость и перестраиваться для какого из перечисленного, остановившегося на обочине?","options":["Неаварийное транспортное средство, неподвижно стоящее на обочине","Только обозначенные полицейские патрульные машины","Только транспортные средства с выставленными красными сигнальными огнями","Пешеходов, ожидающих на автобусной остановке"],"explanation":"Свод законов штата Коннектикут, раздел 14-283b, был расширен и охватывает не только аварийные транспортные средства (включая ремонтные машины и эвакуаторы) с мигающими огнями, но и любое неаварийное транспортное средство, неподвижно стоящее на обочине; водители должны снизить скорость и перестроиться, когда это безопасно."},"71":{"q":"Каков в Коннектикуте установленный законом предел веса, выше которого транспортному средству, как правило, требуется разрешение DOT на перевес?","options":["80,000 фунтов полной массы транспортного средства","73,280 фунтов полной массы транспортного средства","100,000 фунтов полной массы транспортного средства","65,000 фунтов полной массы транспортного средства"],"explanation":"Коннектикут следует федеральному законному максимуму в 80,000 фунтов полной массы транспортного средства (на пяти осях). Грузы, превышающие 80,000 фунтов, требуют разрешения CT DOT на перевес. Положения CT DOT Oversize/Overweight Permit."},"72":{"q":"Какое наказание за повторное нарушение применяется в Коннектикуте за незаконный объезд остановившегося школьного автобуса с мигающими красными огнями (второе или последующее нарушение)?","options":["Не менее $500 и не более $1,000, и/или тюремное заключение до 30 дней","Фиксированный штраф $90 без тюремного заключения","Письменное предупреждение и два штрафных балла","Фиксированный штраф $450, идентичный наказанию за первое нарушение"],"explanation":"Свод законов штата Коннектикут, раздел 14-279, устанавливает штраф $450 за первое нарушение в виде объезда остановившегося школьного автобуса, а за каждое последующее нарушение — не менее $500 и не более $1,000, либо тюремное заключение не более 30 дней, либо и то и другое."},"73":{"q":"Какова максимальная законная высота транспортного средства в Коннектикуте, прежде чем потребуется разрешение на негабарит?","options":["13'6\"","12 футов 0 дюймов","14 футов 6 дюймов","13 футов 0 дюймов"],"explanation":"Законные предельные габариты в Коннектикуте составляют 8 футов 6 дюймов в ширину и 13'6\" в высоту (при длине полуприцепа 53 фута). Превышение высоты 13'6\" требует разрешения CT DOT на негабарит. Положения CT DOT Oversize/Overweight Permit."},"74":{"q":"Водитель с CDL приближается к железнодорожному переезду в Коннектикуте, перевозя ПУСТУЮ цистерну, которая в последний раз использовалась для опасных грузов. Что должен сделать водитель?","options":["Остановиться на расстоянии от 15 до 50 футов от ближайшего рельса, поскольку правило применяется к цистернам как загруженным, так и пустым","Продолжать движение без остановки, поскольку цистерна пуста","Остановиться, только если виден поезд","Снизить скорость до 5 mph, но продолжить пересечение без полной остановки"],"explanation":"Свод законов штата Коннектикут, раздел 14-250, и руководство CT CDL Manual требуют, чтобы транспортные средства с цистернами, использовавшимися для опасных грузов, останавливались на расстоянии от 15 до 50 футов от ближайшего рельса, независимо от того, загружена цистерна ИЛИ пуста, и пересекали пути только тогда, когда их можно проехать без остановки."},"75":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Коннектикуте?","options":["Департамент транспортных средств Коннектикута (DMV)","Департамент транспорта Коннектикута (CTDOT)","Федеральное управление безопасности автоперевозчиков (FMCSA)","Полиция штата Коннектикут, отдел безопасности коммерческого транспорта"],"explanation":"В Коннектикуте Департамент транспортных средств (DMV) выдаёт CDL и проводит тестирование знаний и навыков. CTDOT занимается разрешениями на негабарит/перевес, а FMCSA устанавливает федеральные стандарты, но само удостоверение является документом штатного DMV. Источник: CT DMV, 'Get a commercial driver's license' (portal.ct.gov/dmv)."},"76":{"q":"Каков в Коннектикуте минимальный возраст для получения CDL для внутриштатной эксплуатации (только в пределах штата)?","options":["18 лет","16 лет","21 год","25 лет"],"explanation":"Коннектикут требует, чтобы водителю было не менее 18 лет для управления коммерческим транспортным средством внутри штата (только в пределах Коннектикута). Водителю должно быть не менее 21 года для междуштатных перевозок или для перевозки опасных грузов. Источник: CT DMV, 'Get a commercial driver's license' / 'Get a commercial learner's permit.'"},"77":{"q":"Каков в Коннектикуте минимальный возраст для управления коммерческим транспортным средством в междуштатных перевозках или для перевозки опасных грузов?","options":["21 год","18 лет","19 лет","23 года"],"explanation":"Коннектикут, следуя федеральному стандарту, требует, чтобы водителю было не менее 21 года для управления коммерческим транспортным средством за пределами штата (междуштатные перевозки) или для перевозки опасных грузов в количествах, требующих табличек. Водители 18-20 лет ограничены внутриштатной эксплуатацией. Источник: CT DMV CLP/CDL pages; 49 CFR 391.11."},"78":{"q":"Прежде чем новый соискатель сможет сдать практический экзамен CDL на удостоверение класса A или класса B в Коннектикуте, какое обучение должно быть пройдено?","options":["Базовое обучение водителей начального уровня (ELDT) — теория плюс вождение — у провайдера, зарегистрированного в FMCSA","Только 160-часовая программа одобренного штатом профессионального училища","Курс безопасного вождения, одобренный Connecticut DMV","Восьмичасовой онлайн-курс ознакомления с опасными грузами"],"explanation":"С 7 февраля 2022 года соискатель начального уровня должен пройти обязательное базовое обучение водителей начального уровня (ELDT) — как теорию (знания), так и практику вождения (BTW) — у провайдера из реестра FMCSA Training Provider Registry, прежде чем сдавать практический экзамен на класс A/B (а также перед экзаменами на дополнения P, S или H, если применимо). Источник: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR Part 380 Subpart F."},"79":{"q":"Соискатель должен пройти базовое обучение водителей начального уровня перед сдачей теоретического экзамена на какое из этих дополнений в Коннектикуте?","options":["Дополнение на опасные грузы (H)","Дополнение на цистерны (N)","Дополнение на двойные/тройные прицепы (T)","Только класс комбинированного транспорта (без буквенного дополнения)"],"explanation":"ELDT должно быть пройдено перед ТЕОРЕТИЧЕСКИМ экзаменом на дополнение по опасным грузам (H) (для H нет практического экзамена). ELDT также требуется перед практическими экзаменами на дополнения для пассажирского транспорта (P) и школьных автобусов (S). Дополнения N и T не подпадают под требование ELDT. Источник: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR 380.609."},"80":{"q":"Какой документ новый соискатель CDL должен получить ПЕРВЫМ в процессе лицензирования в Коннектикуте, до полного CDL?","options":["Коммерческое ученическое разрешение (CLP)","Освобождение от медосмотра DOT, выданное DMV","Разрешение на эксплуатацию автоперевозчика (номер MC)","Временный сертификат на междуштатные перевозки"],"explanation":"Процесс начинается со сдачи необходимых теоретических экзаменов для получения коммерческого ученического разрешения (CLP). Затем соискатель практикуется, проходит ELDT и сдаёт практический экзамен, чтобы преобразовать CLP в CDL. Источник: CT DMV, 'Get a commercial learner's permit' and 'Get a commercial driver's license.'"},"81":{"q":"Как долго действует коммерческое ученическое разрешение (CLP) в Коннектикуте с даты выдачи?","options":["Один год","60 дней","Шесть месяцев","Два года"],"explanation":"CLP в Коннектикуте действует один год с даты выдачи. Если владелец не получает CDL в течение этого года, все необходимые экзамены нужно пересдать, чтобы получить новое разрешение. Источник: CT DMV, 'Get a commercial learner's permit.'"},"82":{"q":"Как долго в Коннектикуте соискатель должен иметь CLP, прежде чем получить право сдавать практический экзамен CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 10 дней","Не менее 60 дней"],"explanation":"Соискатель должен иметь CLP не менее 14 дней перед сдачей практического экзамена CDL. Этот федеральный минимальный период ожидания применяется в Коннектикуте. Источник: CT DMV, 'Get a commercial learner's permit'; 49 CFR 383.25(a)(3)."},"83":{"q":"Общий теоретический экзамен CDL в Коннектикуте состоит из 50 вопросов. Сколько нужно ответить правильно, чтобы сдать?","options":["40 правильных (80%)","35 правильных (70%)","45 правильных (90%)","30 правильных (60%)"],"explanation":"Общий теоретический экзамен в Коннектикуте состоит из 50 вопросов с вариантами ответов и требует 40 правильных ответов (80%) для прохождения. Источник: CT DMV, 'Get a commercial learner's permit.'"},"84":{"q":"Из скольких отдельных частей состоит практический экзамен CDL в Коннектикуте?","options":["Из трёх частей","Из двух частей","Из четырёх частей","Из пяти частей"],"explanation":"Практический экзамен CDL состоит из трёх частей: предрейсового осмотра транспортного средства, базового экзамена на навыки управления транспортным средством и экзамена по вождению на дороге. Все три должны быть сданы, чтобы получить CDL. Источник: CT DMV CDL testing; 49 CFR 383.113."},"85":{"q":"Что из перечисленного является одной из трёх обязательных частей практического экзамена CDL в Коннектикуте?","options":["Предрейсовый осмотр транспортного средства","Общий теоретический экзамен из 50 вопросов","Медицинский осмотр DOT","Письменный экзамен на дополнение по пневматическим тормозам"],"explanation":"Три части практического экзамена — это предрейсовый осмотр транспортного средства, базовое управление транспортным средством и вождение на дороге. Общий теоретический экзамен и экзамен по пневматическим тормозам являются ПИСЬМЕННЫМИ теоретическими экзаменами (сдаваемыми для CLP), а медосмотр DOT — это медицинское обследование; ничто из этого не является частью практического экзамена. Источник: CT DMV; 49 CFR 383.113."},"86":{"q":"Во время дорожного экзамена CDL в Коннектикуте часть, где соискатель демонстрирует манёвры, такие как движение задним ходом по прямой или со смещением на огороженной площадке, называется:","options":["Базовый экзамен на навыки управления транспортным средством","Экзамен по предрейсовому осмотру","Экзамен по вождению на дороге","Экзамен по комбинированному транспортному средству"],"explanation":"Манёвры задним ходом и позиционирование, выполняемые вне дорог общего пользования, являются частью базового экзамена на навыки управления транспортным средством — второго из трёх компонентов практического экзамена. Предрейсовый — это осмотр, а дорожный экзамен проводится в условиях движения. Источник: CT DMV; 49 CFR 383.113(b)."},"87":{"q":"Если соискатель CDL в Коннектикуте не сдаёт или не проходит теоретический экзамен по пневматическим тормозам, что происходит с удостоверением?","options":["Накладывается ограничение 'L', запрещающее управление любым коммерческим транспортным средством с пневматическими тормозами","Соискателю полностью отказывают в CDL до сдачи экзамена по пневматическим тормозам","Добавляется ограничение 'K', ограничивающее водителя внутриштатной эксплуатацией","Ничего — пневматические тормоза необязательны и не оставляют ограничения"],"explanation":"Водитель, не сдавший теоретический экзамен по пневматическим тормозам (и связанные с ним проверки навыков), получает ограничение 'L', которое запрещает управление любым коммерческим транспортным средством с пневматическими тормозами. Источник: CT DMV CLP/CDL information; 49 CFR 383.95."},"88":{"q":"Федеральные правила CDL, применяемые в Коннектикуте, требуют, чтобы каждый владелец CDL/CLP прошёл \"самосертификацию\". Сколько категорий типов вождения для самосертификации определяет федеральная система?","options":["Четыре","Две","Три","Шесть"],"explanation":"Федеральная система самосертификации определяет четыре категории: междуштатная без исключений (NI), междуштатная с исключениями (EI), внутриштатная без исключений (NA) и внутриштатная с исключениями (EA). Онлайн-самосертификация Коннектикута практически предлагает два варианта без исключений, которые использует большинство водителей (NI и NA). Источник: 49 CFR 383.71(b); CT DMV self-certification."},"89":{"q":"Водитель в Коннектикуте, который самосертифицируется как 'Non-Excepted Interstate' (NI), делает какое заявление о своей деятельности и медицинском статусе?","options":["Он осуществляет перевозки за пределами штата и должен соответствовать федеральному требованию о медицинском сертификате DOT","Он работает только в пределах Коннектикута и освобождён от медицинских требований DOT","Он осуществляет перевозки за пределами штата, но освобождён от любого медицинского сертификата","Он работает только в пределах Коннектикута и должен иметь разрешение на перевозку опасных грузов"],"explanation":"Non-Excepted Interstate (NI) означает, что водитель управляет коммерческим транспортным средством в междуштатных перевозках (внутри и за пределами Коннектикута) и подпадает под действие федеральных требований о медицинской сертификации DOT и должен им соответствовать. Источник: CT DMV self-certification; 49 CFR 383.71(b)."},"90":{"q":"Водитель в Коннектикуте, который самосертифицируется как 'Non-Excepted Intrastate' (NA), удостоверяет, что он будет:","options":["Управлять коммерческим транспортным средством только в пределах границ Коннектикута","Осуществлять перевозки за пределами штата по федеральному медицинскому освобождению","Осуществлять перевозки по всей стране без какой-либо медицинской сертификации","Управлять только сельхозтехникой, освобождённой от правил CDL"],"explanation":"Non-Excepted Intrastate (NA) удостоверяет управление коммерческим транспортным средством только в пределах Коннектикута. Такие водители могут иметь ограничение 'K', ограничивающее их внутриштатным вождением, и должны соответствовать медицинским/квалификационным стандартам водителей Коннектикута. Источник: CT DMV self-certification (dmvselfservice.ct.gov)."},"91":{"q":"Как владелец CDL/CLP завершает этап самосертификации в Connecticut DMV?","options":["Подаёт её через онлайн-систему самообслуживания DMV и приносит распечатанное подтверждение по электронной почте в DMV","Просит медицинского эксперта отправить бумажную сертификацию в штаб-квартиру FMCSA","Самосертифицируется только во время дорожного экзамена, устно экзаменатору","Подаёт сертификацию в Департамент труда Коннектикута"],"explanation":"Водитель самосертифицируется онлайн через портал самообслуживания Connecticut DMV (dmvselfservice.ct.gov), получает подтверждение по электронной почте и приносит это распечатанное подтверждение в DMV при подаче заявления, продлении, повышении категории или изменении типа вождения. Источник: CT DMV self-certification."},"92":{"q":"Какую форму должен использовать сертифицированный медицинский эксперт для документирования медосмотра DOT владельца CDL в Коннектикуте, и как она попадает в DMV?","options":["Форму MCSA-5876, загружаемую экспертом через National Registry и отправляемую в DMV в электронном виде","Форму R-229a, отправляемую соискателем по почте в DMV в течение 30 дней","Форму MCSA-5876, доставляемую водителем лично и сканируемую в любом отделении DMV","Рукописную справку от врача, отправляемую соискателем по факсу в FMCSA"],"explanation":"Медосмотр DOT должен быть зафиксирован на форме MCSA-5876 (Medical Examiner's Certificate) экспертом, внесённым в National Registry of Certified Medical Examiners; эксперт загружает результаты через National Registry, и они передаются в Connecticut DMV в электронном виде. Источник: CT DMV, 'Getting medical certification for CDL.'"},"93":{"q":"Что происходит с CDL в Коннектикуте, если владелец не поддерживает действующий медицинский сертификат DOT в DMV?","options":["После уведомления о понижении категории удостоверение понижается до некоммерческого класса D","CDL аннулируется навсегда и не может быть восстановлено","Автоматически начисляется федеральный гражданский штраф $500 каждый месяц","Ничего не меняется до наступления обычной даты продления"],"explanation":"Если действующий медицинский сертификат не поддерживается, медицинский статус водителя становится 'Not Certified'; DMV отправляет уведомление о понижении категории, и если новый действующий сертификат не получен в электронном виде к указанной дате, CDL понижается до класса D (некоммерческого). Источник: CT DMV, 'Getting medical certification for CDL.'"},"94":{"q":"Как часто нужно продлевать коммерческое водительское удостоверение в Коннектикуте?","options":["Каждые четыре года","Каждые шесть лет","Каждые два года","Каждые восемь лет"],"explanation":"CDL в Коннектикуте выдаётся с четырёхлетним циклом продления (продлевается примерно ко дню рождения владельца), что короче стандартного срока действия некоммерческого удостоверения. Источник: CT DMV, 'Renew a CDL (commercial) license'; Conn. Gen. Stat. § 14-44h."}},"tr":{"0":{"q":"Connecticut yasalarına göre, özel bir izin olmadan Connecticut karayollarında çalışmasına izin verilen bir ticari aracın (aynalar gibi güvenlik donanımları hariç) azami genişliği nedir?","options":["96 inç (8 fit)","102 inç (8 fit 6 inç)","108 inç (9 fit)","120 inç (10 fit)"],"explanation":"Connecticut Genel Kanunları Sec. 14-262, azami yasal araç genişliğini, aynalar gibi güvenlik donanımları sayılmadan 102 inç (8 fit 6 inç) olarak belirler. CTDOT Araç Boyut ve Ağırlık Sınırlamaları belgesi Genişliği 102.37 inç olarak listeler. Kaynak: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"1":{"q":"Connecticut'ta, Ulaştırma Komisyoneri'nden özel bir yükseklik izni gerekmeden önce bir aracın yük dahil olabileceği azami yükseklik nedir?","options":["12 fit 6 inç","13 fit 0 inç","13 fit 6 inç","14 fit 0 inç"],"explanation":"Connecticut Genel Kanunları Sec. 14-264, yükü ile birlikte yüksekliği 13 fit 6 inç'i aşan bir aracın özel yazılı bir izin olmadan kullanılmasını yasaklar (gevşek saman veya ot yükü hariç). Kaynak: CGS Sec. 14-264; CTDOT Vehicle Size and Weight Limitations."},"2":{"q":"Connecticut'ta, izin olmadan çalışan tek üniteli (düz) bir kamyonun yük dahil azami uzunluğu nedir?","options":["40 fit","45 fit","48 fit","53 fit"],"explanation":"Connecticut Genel Kanunları Sec. 14-262, tek üniteli bir aracı yük dahil azami 45 fit uzunlukla sınırlar. Kaynak: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations (\"Single unit vehicle 45 feet\")."},"3":{"q":"Genel (kısıtlanmamış) Connecticut karayollarında tek bir yarı römork çeken bir çekici için, yarı römorkun azami yasal uzunluğu nedir?","options":["45 fit","48 fit","53 fit","57 fit"],"explanation":"Genel karayollarında Connecticut, toplam uzunluk sınırı olmaksızın bir çekici ve 48 fitlik yarı römork kombinasyonuna izin verir, ancak römorkun kendisi 48 fit ile sınırlıdır. Kaynak: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"4":{"q":"Connecticut'ın belirlenmiş (kısıtlı) karayolu sisteminde, kingpin'den en arkadaki dingilin merkezine olan mesafe hangi rakamı aşmadığı sürece 53 fitlik bir yarı römorka izin verilir?","options":["41 fit","43 fit","45 fit","48 fit"],"explanation":"Belirlenmiş karayolu sisteminde Connecticut, toplam uzunluk sınırı olmaksızın bir çekici ve 53 fitlik yarı römorka izin verir, ancak kingpin'den en arkadaki dingilin merkezine olan mesafe 43 fit'i aşmamalıdır. Kaynak: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"5":{"q":"Connecticut'ın belirlenmiş karayolu sisteminde, ikiz (çiftli) römork çeken bir çekicinin her römorku azami hangi uzunlukta olabilir?","options":["27 fit","28 fit","33 fit","40 fit"],"explanation":"Belirlenmiş karayolu sisteminde Connecticut, toplam uzunluk sınırı olmaksızın bir çekici ve ikiz römork kombinasyonuna izin verir, ancak her römork 28 fit ile sınırlıdır. Kaynak: CTDOT Vehicle Size and Weight Limitations (Restricted to the Designated Highway System)."},"6":{"q":"Köprü formülü gereklilikleri karşılandığında, 5 dingilli bir kombinasyonun fazla ağırlık izni olmadan Connecticut karayollarında taşıyabileceği azami brüt araç ağırlığı nedir?","options":["73,000 pound","80,000 pound","88,000 pound","90,000 pound"],"explanation":"Connecticut'ın uygulanabilir azami ağırlığı, ilk ve son dingil arasında 51 fit ile 5 dingil üzerinde 80,000 pound olup, Federal Köprü Formülü gereklilikleri karşılandığında izin verilir. Kaynak: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"7":{"q":"Connecticut'ta, bir dingil komşu dingillerden 6 fit veya daha fazla aralıklı olduğunda tek bir dingile izin verilen azami ağırlık nedir?","options":["18,000 pound","20,000 pound","22,400 pound","24,000 pound"],"explanation":"Connecticut, dingiller 6 fit veya daha fazla aralıklı olduğunda dingil başına 22,400 pound'a izin verir; 6 fitten daha az aralıklı dingiller ise dingil başına 18,000 pound ile sınırlıdır. Kaynak: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"8":{"q":"Connecticut ağırlık kurallarına göre, bir dingil komşu bir dingilden 6 fitten DAHA AZ aralıklı olduğunda herhangi bir tek dingile izin verilen azami ağırlık nedir?","options":["16,000 pound","18,000 pound","20,000 pound","22,400 pound"],"explanation":"Connecticut, 6 fitten daha az aralıklı dingilleri dingil başına 18,000 pound ile sınırlar; yalnızca 6 fit veya daha fazla aralıkta 22,400 pound'a izin verilir. Kaynak: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a."},"9":{"q":"Bir Connecticut kombinasyon aracının brüt ağırlığı 73,000 pound'u aştığında (80,000 pound'a kadar), hangi ek gereklilik karşılanmalıdır?","options":["Araç yalnızca dolu kauçuk lastikler kullanmalıdır","Tüm Federal Köprü Formülü gereklilikleri karşılanmalıdır","Araç yalnızca geceleri seyahat etmelidir","Araca bir polis eskortu eşlik etmelidir"],"explanation":"CTDOT'a göre, 73,000 pound'un üzerindeki ağırlıklar için yalnızca Federal Köprü Formülü'nün tüm gereklilikleri karşılandığında azami 80,000 pound brüt ağırlığa izin verilir. Kaynak: CTDOT Vehicle Size and Weight Limitations (Gross Vehicle Weights Over 73,000 pounds)."},"10":{"q":"Connecticut'ta, herhangi bir aracın lastikleri tarafından yola aktarılan azami izinli ağırlık lastik genişliğine dayanır. Bu sınır nedir?","options":["Lastik genişliğinin inç başına 500 pound","Lastik genişliğinin inç başına 600 pound","Lastik genişliğinin inç başına 700 pound","Lastik genişliğinin inç başına 800 pound"],"explanation":"Connecticut, lastik yüklemesini lastik genişliğinin inç başına 600 pound (azami) ile sınırlar. Kaynak: CTDOT Vehicle Size and Weight Limitations (Tires - Load per inch width of tire 600 pounds maximum)."},"11":{"q":"Connecticut'ta, hiçbir dingil ağırlığı 18,000 pound'u aşmadığında 2 dingilli düz bir kamyon için izin verilen azami brüt ağırlık nedir?","options":["32,000 pound","36,000 pound","40,000 pound","53,800 pound"],"explanation":"Connecticut, dingil ağırlığı 18,000 pound'u aşmadığında 2 dingilli bir araca 36,000 pound'a kadar izin verir (o dingil koşulu olmadan rakam 32,000 pound'dur). Kaynak: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a."},"12":{"q":"Connecticut'ta bir çekici-yarı römork kombinasyonu için, kombinasyon 3 dingile sahip olduğunda azami brüt ağırlık nedir?","options":["53,800 pound","58,400 pound","67,400 pound","73,000 pound"],"explanation":"Connecticut, 3 dingilli bir çekici-yarı römork kombinasyonunu azami 58,400 pound olarak belirler; 4 dingilli bir kombinasyon 67,400 pound ve 5 veya daha fazla dingilli olanlar 73,000 pound'a kadardır. Kaynak: CTDOT Vehicle Size and Weight Limitations (Tractor Semitrailer)."},"13":{"q":"Connecticut'ın ardışık dingil grubuna izin verilen azami brüt ağırlığı belirlemek için uyguladığı federal ağırlık standardı şu adla bilinir:","options":["Federal Dingil Açıklığı Kuralı","Federal Köprü Formülü","Federal Brüt Kombinasyon Standardı","Federal Tandem Ağırlık Tablosu"],"explanation":"Connecticut, dingil gruplarına izin verilen ağırlığı belirlemek için Federal Köprü Formülü'nü uygular; 73,000 pound'un üzerinden 80,000 pound'a kadar olan brüt ağırlıklar için karşılanması gerekir. Kaynak: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"14":{"q":"Connecticut'ta, gabari dışı/fazla ağırlıklı (uyumsuz araç) izinlerini kim verir ve başvurular hangi sistem üzerinden yapılır?","options":["Ulaştırma Komisyoneri, DMV tarafından yönetilen Ticari Araç Operasyonları (CVO) WebPortal aracılığıyla","Aracın geçtiği her kasabanın yerel polis departmanı","Federal Motorlu Taşıyıcı Güvenliği İdaresi çevrimiçi portalı","Enerji ve Çevre Koruma Departmanı, kağıt başvuru ile"],"explanation":"CGS Sec. 14-270 uyarınca, Ulaştırma Komisyoneri uyumsuz (gabari dışı/fazla ağırlıklı) araçlar için özel izinler verir; başvurular CT DMV tarafından yönetilen Connecticut Ticari Araç Operasyonları (CVO) WebPortal üzerinden işlenir. Kaynak: CGS Sec. 14-270; CTDOT Oversize/Overweight Permit FAQ."},"15":{"q":"Standart bir Connecticut tek seferlik gabari dışı/fazla ağırlıklı izni genellikle hangi süre için geçerlidir ve seyahat hangi saatlerle sınırlıdır?","options":["30 gün; günün veya gecenin herhangi bir saati","3 gün; yalnızca gündüz saatleri","7 gün; yalnızca gece","1 gün; yoğun saatler hariç"],"explanation":"CTDOT, 3 günlük bir süre için geçerli tek seferlik gabari dışı/fazla ağırlıklı izinler verir; seyahat gündüz saatleriyle sınırlıdır (genellikle gün doğumundan yarım saat sonrasından gün batımından yarım saat öncesine kadar). Kaynak: CTDOT Vehicle Size and Weight Limitations; CTDOT Oversize/Overweight Permit FAQ."},"16":{"q":"Connecticut yasalarına (CGS Sec. 14-267a) göre, fazla ağırlık miktarına dayalı olarak fazla ağırlıklı bir ticari araç kullanmanın cezası nedir?","options":["Fazla ağırlığın her 100 pound'u için $1","Fazla ağırlığın her 100 pound'u (veya kesri) için $3","Fazla ağırlığın her 100 pound'u için $10","Fazla ağırlıktan bağımsız olarak sabit $500"],"explanation":"Connecticut Genel Kanunları Sec. 14-267a, fazla ağırlık cezasını fazla ağırlığın her yüz pound'u veya kesri için üç dolar olarak belirler. Kaynak: CGS Sec. 14-267a."},"17":{"q":"Connecticut, belirli tarımsal taşımacılık için özel bir ağırlık tahsisi sağlar. Dökme süt toplama tankeri veya tarımsal ürün taşıyan bir araç için izin verilen azami brüt araç ağırlığı nedir (federal yasanın izin verdiği yerlerde)?","options":["80,000 pound","88,000 pound","100,000 pound","120,000 pound"],"explanation":"Connecticut Genel Kanunları Sec. 14-267a, federal yasanın izin verdiği yerlerde, dökme süt toplama tankerleri ve tarımsal ürün (yem, tohum, gübre ve tarım ürünleri) taşıyan araçlar için 100,000 pound'a kadar izin verilen bir brüt ağırlık belirler. Kaynak: CGS Sec. 14-267a."},"18":{"q":"CGS Sec. 14-267a uyarınca, iki ardışık tandem dingil setine sahip bir araç için, bu tandemlere 68,000 pound'luk bir brüt yüke yalnızca iki setin ilk ve son dingili arasındaki mesafe en az kaç olursa izin verilir:","options":["30 fit","34 fit","36 fit","40 fit"],"explanation":"Connecticut Genel Kanunları Sec. 14-267a, iki ardışık tandem dingil setinin, bu ardışık tandem setlerinin ilk ve son dingilleri arasındaki toplam mesafe 36 fit veya daha fazla olması koşuluyla brüt 68,000 pound taşımasına izin verir. Kaynak: CGS Sec. 14-267a."},"19":{"q":"Connecticut'ta, tek bir aracı Class B CDL kategorisine yerleştiren asgari Brüt Araç Ağırlık Derecesi (GVWR) nedir?","options":["16,001 pound veya daha fazla","26,001 pound veya daha fazla","10,001 pound veya daha fazla","33,001 pound veya daha fazla"],"explanation":"Bir Connecticut Class B CDL, GVWR'si 26,001 pound veya daha fazla olan herhangi bir tek aracı ve 10,000 pound'u aşmayan bir üniteyi çeken böyle herhangi bir aracı kullanmaya yetki verir. Kaynak: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"20":{"q":"Connecticut kurallarına göre, çekilen ünitenin GVWR'si hangi rakamı aştığı sürece GVWR'si 26,001 pound veya daha fazla olan bir araç kombinasyonunu kullanmak için Class A CDL gereklidir?","options":["5,000 pound","26,001 pound","10,000 pound","15,000 pound"],"explanation":"Bir Connecticut Class A CDL, çekilen aracın GVWR'sinin 10,000 pound'u aştığı, GVWR'si 26,001 pound veya daha fazla olan kombinasyonları kapsar. Kaynak: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"21":{"q":"Bir Connecticut sürücüsü, sürücü dahil 20 yolcu taşımak üzere tasarlanmış 26,001 pound GVWR'nin altında tek bir aracı kullanıyor. Hangi CDL sınıfı geçerlidir?","options":["Class A","Class B","Class C","CDL gerekmez"],"explanation":"Bir Connecticut Class C CDL, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanan veya plakartlanmış tehlikeli madde taşıyan, 26,001 pound GVWR'nin altındaki tek bir aracı (veya 10,000 pound'u aşmayan bir üniteyi çeken) kapsar. Kaynak: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"22":{"q":"Eyalet içi (yalnızca Connecticut içinde) operasyonla sınırlı bir Connecticut CDL'si almak için asgari yaş nedir?","options":["16","18","19","21"],"explanation":"Connecticut, eyalet içi bir CDL (yalnızca Connecticut içinde operasyon) için başvuru sahibinin en az 18 yaşında olmasını gerektirir. Kaynak: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"23":{"q":"Bir Connecticut CDL'si ile eyaletler arası ticarette ticari bir motorlu aracı kullanmak için gereken asgari yaş nedir?","options":["18","19","20","21"],"explanation":"Connecticut, eyaletler arası operasyon (Connecticut içinde ve dışında) için başvuru sahibinin en az 21 yaşında olmasını gerektirir. Kaynak: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"24":{"q":"Connecticut, plakart gerektiren miktarlarda tehlikeli madde taşıyan bir aracı kullanmak için hangi onayı gerektirir?","options":["N onayı","H onayı","T onayı","X onayı"],"explanation":"Connecticut, plakartlanmış tehlikeli madde taşıyan bir aracı kullanmak için H (Tehlikeli Maddeler) onayını gerektirir. Kaynak: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"25":{"q":"Connecticut'ta, N (tank/sıvı dökme) onayı, hangi asgari kapasitede derecelendirilmiş kalıcı olarak monte edilmiş bir kargo tankı için gereklidir?","options":["100 galon veya daha fazla","119 galon veya daha fazla","500 galon veya daha fazla","1,000 galon veya daha fazla"],"explanation":"Connecticut, kalıcı olarak monte edilmiş 119 galon veya daha fazla derecelendirilmiş bir kargo tankında (veya 1,000 galon veya daha fazla derecelendirilmiş taşınabilir bir tankta) sıvı veya sıvılaştırılmış gaz taşımak üzere tasarlanmış bir araç için N onayını gerektirir. Kaynak: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"26":{"q":"Class A CDL gerektiren bir araçla birden fazla römork çekmek için hangi Connecticut onayı gereklidir?","options":["P onayı","N onayı","T onayı","S onayı"],"explanation":"Connecticut, bir Class A CDL aracı birden fazla römork çektiğinde T (Çiftli/Üçlü) onayını gerektirir. Kaynak: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"27":{"q":"Bir Connecticut sürücüsüne S (okul otobüsü) onayı verilmeden önce, sürücünün ayrıca hangi diğer onaya sahip olması gerekir?","options":["H (Tehlikeli Maddeler)","N (Tank)","P (Yolcu)","T (Çiftli/Üçlü)"],"explanation":"Connecticut'ta okul otobüsü (S) onayı, sahibinin Yolcu (P) onayına sahip olmasını ve kabul edilebilir bir sürüş kaydı tutmasını da gerektirir. Kaynak: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"28":{"q":"Connecticut'ta uygulanan federal kurallara göre, bir başvuru sahibinin CDL beceri (yol) testine girmeye hak kazanmadan önce bir Ticari Öğrenici İzni (CLP) ne kadar süre tutması gerekir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Bir başvuru sahibi, CLP'nin ilk verilmesini takip eden 14 gün içinde CDL beceri testine giremez; izin asgari 14 gün tutulmalıdır. Kaynak: 49 CFR 383.25(e), Connecticut DMV tarafından uygulanır."},"29":{"q":"Bir Connecticut Ticari Öğrenici İzni (CLP), verildiği tarihten itibaren ne kadar süre geçerlidir?","options":["90 gün","180 gün","Bir yıl","İki yıl"],"explanation":"Bir Connecticut CLP, verildiği tarihten itibaren bir yıl boyunca aktif kalır; bu süre içinde bir CDL alınmazsa başvuru sahibi gerekli testleri yeniden yapmak zorundadır. Kaynak: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"30":{"q":"7 Şubat 2022'den itibaren geçerli olmak üzere, Connecticut'ta teste girmeden önce FMCSA kayıtlı bir sağlayıcı aracılığıyla Başlangıç Düzeyi Sürücü Eğitimini (ELDT) kimin tamamlaması gerekir?","options":["Yalnızca hazmat onayı için başvuranlar","Mevcut bir CDL'yi yenileyen herkes","İlk kez CDL başvurusu yapanlar, Class B'den Class A'ya yükseltenler ve ilk kez H, P veya S onayı için başvuranlar","Yalnızca 21 yaşın altındaki sürücüler"],"explanation":"7 Şubat 2022'den bu yana, ELDT, ilk kez CDL başvurusu yapanlar, bir Class B'yi Class A'ya yükselten sürücüler ve ilk kez H, P veya S onayı için başvuranlar için gereklidir; eğitim FMCSA Eğitim Sağlayıcı Kaydı'ndaki bir sağlayıcı tarafından verilir. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380); CT DMV CDL sayfaları (portal.ct.gov/dmv)."},"31":{"q":"Bir Connecticut başvuru sahibi için Başlangıç Düzeyi Sürücü Eğitimi (ELDT) hangi sistem aracılığıyla tamamlanmalıdır?","options":["Connecticut DMV eğitim portalı","FMCSA Eğitim Sağlayıcı Kaydı (TPR)","TSA kayıt sistemi","İlaç ve Alkol Takas Merkezi"],"explanation":"ELDT, sürücünün tamamladığını FMCSA'ya bildiren FMCSA Eğitim Sağlayıcı Kaydı'nda (TPR) listelenen bir sağlayıcı ile tamamlanmalıdır. Kaynak: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov); CT DMV CDL sayfaları."},"32":{"q":"Tehlikeli maddeler (H) onayı için, ELDT gerekliliği hangi tür eğitimden oluşur?","options":["Yalnızca teori eğitimi","Yalnızca direksiyon başında eğitim","Hem teori hem direksiyon başında eğitim","Hazmat için ELDT gerekmez"],"explanation":"Hazmat (H) onayı ELDT gerekliliği yalnızca teoriktir; Class A/B ve P ile S onaylarının aksine direksiyon başında bir bileşen yoktur. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380); FMCSA Training Provider Registry."},"33":{"q":"Bilgi ve ELDT gerekliliklerinin yanı sıra, bir Connecticut başvuru sahibinin hazmat (H) onayını almak için geçmesi gereken ek federal tarama nedir?","options":["Yalnızca bir DOT fizik muayenesi","Parmak izi alımı dahil bir TSA Güvenlik Tehdit Değerlendirmesi","Bir eyalet kredi kontrolü","Yalnızca görme muayenesi"],"explanation":"Bir hazmat onayı, bilgi testi ve ELDT teori eğitimine ek olarak, bir geçmiş kontrolü ve parmak izi alımını içeren TSA Güvenlik Tehdit Değerlendirmesi'nin geçilmesini gerektirir. Kaynak: TSA HazMat Endorsement Threat Assessment Program; CT DMV onay sayfaları."},"34":{"q":"Connecticut DMV, REAL ID ile uyumlu olarak bir Ticari Öğrenici İzni başvurusu yaparken hangi belge setini gerektirir?","options":["Kimlik kanıtı, Sosyal Güvenlik numarası, yasal ABD varlığı ve iki Connecticut ikamet kanıtı","Yalnızca bir pasaport","Bir doğum belgesi ve bir fatura","Yalnızca mevcut Connecticut sürücü belgesi"],"explanation":"Connecticut, REAL ID belgelerini gerektirir: kimlik kanıtı, Sosyal Güvenlik numarası, yasal ABD varlığı ve iki Connecticut ikamet kanıtı, ayrıca öz-sertifikasyon onayı ve R-229a başvuru formu. Kaynak: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"35":{"q":"Hem eyalet içinde hem dışında ticari bir araç kullanacak ve bir DOT tıbbi kartı taşıması gereken bir Connecticut sürücüsü hangi kategori altında öz-sertifikasyon yapmalıdır?","options":["İstisna Tutulan Eyaletler Arası (EI)","İstisna Tutulmayan Eyaletler Arası (NI)","İstisna Tutulan Eyalet İçi (EA)","İstisna Tutulmayan Eyalet İçi (NA)"],"explanation":"İstisna Tutulmayan Eyaletler Arası (NI), Connecticut içinde ve dışında sürüşü kapsar ve federal DOT tıbbi sertifika gerekliliklerinin karşılanmasını gerektirir. Kaynak: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)."},"36":{"q":"Hangi Connecticut öz-sertifikasyon kategorisi, yalnızca Connecticut içinde çalışan ve federal DOT tıbbi kart gerekliliklerini karşılaması gerekmeyen bir sürücü için geçerlidir?","options":["İstisna Tutulmayan Eyaletler Arası (NI)","İstisna Tutulmayan Eyalet İçi (NA)","İstisna Tutulan Eyalet İçi (EA)","İstisna Tutulan Eyaletler Arası (EI)"],"explanation":"İstisna Tutulan Eyalet İçi (EA), yalnızca Connecticut içinde çalışan ve federal DOT tıbbi sertifika gerekliliğinden muaf olan sürücüler için geçerlidir. Kaynak: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)."},"37":{"q":"Bir Connecticut CDL işlemini işleme koymadan önce, DMV bir başvuru sahibinin durumunu hangi federal sistemde doğrular?","options":["TSA PreCheck veritabanı","FMCSA İlaç ve Alkol Takas Merkezi","Yalnızca Ulusal Sürücü Kaydı","Seçici Hizmet Sistemi"],"explanation":"Connecticut başvuru sahipleri FMCSA İlaç ve Alkol Takas Merkezi'ne kayıt olmalıdır ve DMV, CDL işlemini işleme koymadan önce başvuru sahibinin Takas Merkezi durumunu kontrol eder. Kaynak: CT DMV CDL sayfaları (portal.ct.gov/dmv); FMCSA Drug and Alcohol Clearinghouse."},"38":{"q":"Connecticut, tehlikeli maddeler (H) onayı için hangi asgari yaşı ve hangi vatandaşlık/göçmenlik durumunu gerektirir?","options":["18 yaş, yalnızca ABD vatandaşı","21 yaş, ABD vatandaşı, yasal daimi ikamet sahibi veya geçerli bir İstihdam Yetki Belgesi sahibi","19 yaş, herhangi bir yasal ikamet eden","21 yaş, yalnızca ABD vatandaşı"],"explanation":"Connecticut, hazmat (H) başvuru sahiplerinin en az 21 yaşında olmasını ve bir ABD vatandaşı, yasal daimi ikamet sahibi olmasını veya geçerli bir İstihdam Yetki Belgesi'ne sahip olmasını gerektirir. Kaynak: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"39":{"q":"Connecticut'ta, bir kişinin ticari bir motorlu aracı (CMV) yasal olarak kullanabileceği azami kan alkol konsantrasyonu (BAC) nedir?","options":["0.04%","0.08%","0.02%","0.00%"],"explanation":"Connecticut, federal CMV standardını izler: bir CMV'yi 0.04% veya daha fazla BAC ile kullanmak yasa dışıdır (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"40":{"q":"Connecticut'ta bir CMV kullanarak, bir sürücünün otomatik olarak kimyasal alkol testine onay verdiği kabul edilir. Bu ilkeye ne denir?","options":["Zımni rıza","Muhtemel sebep","Açık feragat","İdari inceleme"],"explanation":"Connecticut'ın zımni rıza yasası, ehliyetli herhangi bir operatörün bir kan, nefes veya idrar testine rıza gösterdiğini kabul eder (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"41":{"q":"Bir Connecticut CDL sahibi, bir CMV'yi 0.04% veya daha fazla BAC ile kullanmak gibi ilk büyük bir suçtan mahkum edilir. CDL ne kadar süreyle diskalifiye edilir?","options":["En az 1 yıl","En az 90 gün","En az 6 ay","En az 3 yıl"],"explanation":"İlk büyük bir suç, CDL'yi en az bir yıl diskalifiye eder (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"42":{"q":"Connecticut kurallarına göre, ilk büyük bir suç (0.04 BAC veya test reddi gibi) sürücü tehlikeli maddeler için plakartlanmış bir CMV kullanırken meydana gelirse, diskalifiye en az:","options":["3 yıl","1 yıl","5 yıl","18 ay"],"explanation":"Plakartlanmış bir HazMat CMV kullanırken işlenen ilk büyük bir suç, CDL'yi en az üç yıl diskalifiye eder (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"43":{"q":"İkinci büyük bir suçtan (örneğin, ikinci bir DUI veya test reddi) mahkum edilen bir sürücü için Connecticut diskalifiye cezası nedir?","options":["Ömür boyu diskalifiye","10 yıllık diskalifiye","5 yıllık diskalifiye","3 yıllık diskalifiye"],"explanation":"İkinci büyük bir suç, CDL'nin ömür boyu diskalifiye edilmesiyle sonuçlanır (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"44":{"q":"Bir Connecticut CDL sahibi ilk kez bir kimyasal alkol testine girmeyi reddeder. Bu reddetme için CDL ne kadar süreyle diskalifiye edilir?","options":["1 yıl","6 ay","60 gün","3 yıl"],"explanation":"Bir kimyasal teste girmeyi reddetmek (zımni rıza ihlali), ilk suçta CDL'yi bir yıl diskalifiye eder (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"45":{"q":"Connecticut'ın zımni rıza yasasına göre, bir kişi bir kimyasal testi reddederse, normal (ticari olmayan) operatör ehliyeti en az ne kadar süreyle askıya alınmaya tabidir:","options":["6 ay","30 gün","1 yıl","90 gün"],"explanation":"Bir kimyasal testi reddetmek, operatör ehliyetini en az altı ay süreyle askıya alınmaya tabi kılar; askıya alınırsa CDL de diskalifiye edilir (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"46":{"q":"Connecticut'ta, 0.04%'in altında tespit edilebilir miktarda alkolle bulunan bir CMV sürücüsü hangi acil işleme tabidir?","options":["24 saatliğine hizmet dışı bırakılır","60 gün diskalifiye edilir","DUI'den tutuklanır","Başka işlem yapılmadan $500 para cezası verilir"],"explanation":"0.04%'in altında tespit edilebilir herhangi bir alkol, 24 saatliğine hizmet dışı bırakılmayla sonuçlanır (CT CDL Manual 1.3.2; 49 CFR 392.5)."},"47":{"q":"Aşağıdakilerden hangisi bir Connecticut CDL sahibi için ciddi bir trafik ihlali olarak sınıflandırılır?","options":["Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak","Bir CMV'de ilk DUI","Bir demiryolu geçidinde durmamak","Bir hizmet dışı emrini ihlal etmek"],"explanation":"Ciddi trafik ihlalleri aşırı hız (sınırın 15 mph veya daha fazla üzerinde), dikkatsiz sürüş ve düzensiz şerit değiştirmeyi içerir; DUI ve OOS ihlalleri ayrı kategorilerdir (CT CDL Manual 1.3.3)."},"48":{"q":"Bir Connecticut CDL sahibi üç yıllık bir süre içinde iki ciddi trafik ihlali işler. Asgari diskalifiye:","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"Üç yıl içinde iki ciddi trafik ihlali, CDL'yi en az 60 gün diskalifiye eder (CT CDL Manual 1.3.3; 49 CFR 383.51)."},"49":{"q":"Bir Connecticut CDL sahibi üç yıllık bir süre içinde üç veya daha fazla ciddi trafik ihlali işlerse, asgari diskalifiye:","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"Üç yıl içinde üç veya daha fazla ciddi trafik ihlali, CDL'yi en az 120 gün diskalifiye eder (CT CDL Manual 1.3.3; 49 CFR 383.51)."},"50":{"q":"Aşağıdakilerden hangisi Connecticut'ın ciddi trafik ihlalleri listesine DAHİL DEĞİLDİR?","options":["Belirtilen hız sınırının 8 mph üzerinde sürmek","Uygunsuz veya düzensiz şerit değiştirme","Bir aracı çok yakından takip etmek","Dikkatsiz sürüş"],"explanation":"Ciddi ihlaller, sınırın 15 mph veya daha fazla üzerinde hız yapmayı gerektirir; 8 mph üzerinde nitelik kazanmaz, ancak düzensiz şerit değiştirme, yakın takip ve dikkatsiz sürüş kazanır (CT CDL Manual 1.3.3)."},"51":{"q":"Bir Connecticut CDL sahibi 10 yıllık bir süre içinde üçüncü bir hizmet dışı emir ihlali işler. Asgari diskalifiye:","options":["3 yıl","1 yıl","2 yıl","180 gün"],"explanation":"10 yıl içinde üçüncü veya sonraki bir hizmet dışı emir ihlali, CDL'yi en az 3 yıl (5 yıla kadar) diskalifiye eder (CT CDL Manual 1.3.4; 49 CFR 383.51)."},"52":{"q":"Bir CMV kullanırken bir demiryolu-karayolu hemzemin geçit ihlalinden bir sürücünün İLK mahkumiyeti için Connecticut diskalifiyesi nedir?","options":["En az 60 gün","En az 30 gün","En az 120 gün","En az 180 gün"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, CDL'yi en az 60 gün diskalifiye eder (CT CDL Manual 1.3.5; 49 CFR 383.51)."},"53":{"q":"Üç yıl içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali için, bir Connecticut CDL sahibi en az ne kadar süreyle diskalifiye edilir:","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"Üç yıl içinde ikinci bir hemzemin geçit ihlali, CDL'yi en az 120 gün diskalifiye eder (CT CDL Manual 1.3.5; 49 CFR 383.51)."},"54":{"q":"Connecticut ve federal CMV kurallarına göre, bir CMV kullanırken elde tutulan/kullanılan bir cep telefonu tutma/kullanma ihlalinden iki veya daha fazla kez mahkum edilen bir sürücü, ikinci suç için 60 günlük bir diskalifiye ve üç yıl içinde üç veya daha fazla suç için ne kadar süreyle diskalifiye ile karşı karşıya kalır?","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"Bir CMV kullanırken elde tutulan cep telefonu kullanımı, ikinci suç için 60 günlük ve üç yıl içinde üç veya daha fazlası için 120 günlük bir diskalifiye getirir (CT CDL Manual 2.9.4; 49 CFR 383.51)."},"55":{"q":"Herhangi bir trafik ihlalinden (park hariç) mahkum edildikten sonra, bir Connecticut CDL sahibi işverenini kaç gün içinde bilgilendirmelidir?","options":["30 gün","2 gün","10 gün","60 gün"],"explanation":"Bir CDL sahibi, kullanılan araçtan bağımsız olarak, herhangi bir trafik ihlalinden mahkumiyetin 30 günü içinde işverenini bilgilendirmelidir (CT CDL Manual 1.4; 49 CFR 383.31)."},"56":{"q":"Connecticut'ın demir yolu geçidi yasasına göre, bir otobüs, okul otobüsü veya plakartlı tehlikeli madde/kargo tankı taşıyan ticari araç, hemzemin geçitte rayları geçmeden önce nerede durmak zorundadır?","options":["En yakın raya 15 feet'ten az, 50 feet'ten fazla olmayan bir mesafede","En yakın raya tam olarak 25 feet mesafede","En yakın raya 10 feet'ten az, 40 feet'ten fazla olmayan bir mesafede","En yakın raya 50 feet'ten az, 100 feet'ten fazla olmayan bir mesafede"],"explanation":"Connecticut General Statutes Sec. 14-250 ve CT CDL Manual, otobüslerin, yolcu taşıyan araçların, okul taşıma araçlarının ve kargo tankı ya da tehlikeli madde taşıyan CMV'lerin en yakın raya 15 feet'ten az, 50 feet'ten fazla olmayan bir mesafede durmasını ve geçmeden önce bakıp dinlemesini şart koşar."},"57":{"q":"Connecticut'ta bir sürücü çok şeritli bir karayolunda ışıkları yanıp sönen, duran bir acil durum aracına yaklaştığında, eyaletin Move Over (Şerit Değiştir) yasası sürücünün ne yapmasını gerektirir?","options":["Hızını makul bir seviyeye düşürmek ve, bitişik şeritteyse, güvenli olduğunda bir şerit yana geçmek","Acil durum aracı bölgeyi terk edene kadar tamamen durmak","Belirtilen hız sınırını korumak ama korna çalmak","Yalnızca acil durum aracı bir polis arabasıysa bir şerit yana geçmek"],"explanation":"Connecticut General Statutes Sec. 14-283b ('Move Over' yasası), sürücülerin derhal sınırın altında makul bir hıza yavaşlamasını ve banketin bitişiğindeki şeritte ilerlerken, bu hareket güvensiz olmadıkça bir şerit yana geçmesini şart koşar."},"58":{"q":"Connecticut'ta eyaletin böyle belirlediği, aynı yönde üç veya daha fazla şeride sahip bölünmüş kontrollü erişimli bir karayolunda, hangi aracın en sol şeritte sürülmesi yasaktır?","options":["Ticari olarak tescil edilmiş bir kamyon","İçinde tek kişi bulunan bir binek otomobil","Bir motosiklet","Bir çağrıya yanıt veren bir ambulans"],"explanation":"Connecticut General Statutes Sec. 14-230a, Office of the State Traffic Administration'ın böyle belirlediği yerlerde, aynı yönde üç veya daha fazla şeride sahip bölünmüş kontrollü erişimli karayollarının en sol şeridinde ticari olarak tescil edilmiş araçların, otobüslerin, römorklu araçların ve okul otobüslerinin sürülmesini yasaklar; ceza $88'dir."},"59":{"q":"Connecticut'ta hangi yollar tır ve kapalı kasa kamyon gibi ticari araçları yasaklar?","options":["Merritt, Wilbur Cross ve Milford Parkway'leri (Route 15 koridoru)","Interstate 95 ve Interstate 84","100'ün üzerinde numaralandırılmış tüm eyalet yolları","Route 9 ve Route 2 ekspres yolları"],"explanation":"Connecticut'ın parkway'leri - Merritt Parkway ve Wilbur Cross Parkway (Route 15) ile Milford Parkway - büyük ölçüde tarihi alçak üst geçitler nedeniyle ticari araçları, römorkları ve büyük boyutlu araçları yasaklar. CT DOT Parkway Restrictions; parkway ihlali cezası ihlal başına $500'dır."},"60":{"q":"Connecticut'ta şeritlerin bir güvenlik adası veya fiziksel bariyerle ayrıldığı bir karayolunda, bir okul otobüsü kırmızı ışıkları yanıp sönerek durduğunda, bariyerin KARŞI tarafındaki bir sürücü ne yapmalıdır?","options":["Sürücü durmadan devam edebilir","Sürücü kırmızı ışıklar kapanana kadar durmalıdır","Sürücü yalnızca otobüsün kapısı açıksa durmalıdır","Sürücü 15 mph'e yavaşlamalı ancak durmasına gerek yoktur"],"explanation":"Connecticut General Statutes Sec. 14-279, şeritlerin bir güvenlik adası veya fiziksel bariyerle ayrıldığı bir karayolunda, o bariyerin karşı tarafındaki bir sürücünün bir okul otobüsü için durmadan devam edebileceğini öngörür. Yalnızca boyalı bir çizgi bu istisnaya GİRMEZ - her iki yön de durmalıdır."},"61":{"q":"Connecticut'ta yalnızca boyalı bir orta çizgiyle (fiziksel bariyer olmadan) ayrılmış bir yolda, karşı tarafta kırmızı ışıkları yanıp sönerek duran bir okul otobüsüyle karşılaşan bir sürücü ne yapmalıdır?","options":["Durmalı, çünkü boyalı bir çizgi bölünmüş karayolu istisnasına girmez","Durmadan azaltılmış hızda devam etmeli","Karşı yönden gelen trafik olduğu için kısıtlama olmadan devam etmeli","Yalnızca çocuklar gözle görülür şekilde karşıdan karşıya geçiyorsa durmalı"],"explanation":"Connecticut General Statutes Sec. 14-279 uyarınca, durmama istisnası yalnızca şeritleri bir güvenlik adası veya fiziksel bariyerin ayırdığı yerlerde geçerlidir. Yalnızca boyalı bir çizgi varsa, her iki taraftaki araçlar yanıp sönen kırmızı ışıklı bir okul otobüsü için tam olarak durmalıdır."},"62":{"q":"Connecticut'ta bir sürücü, durmuş ve kırmızı ışıkları yanıp sönen bir okul otobüsüne önden ne kadar yaklaşabilir, hangi mesafede durmak zorundadır?","options":["Otobüsün önünden 10 feet'ten az olmayan bir mesafede","Otobüsün önünden 5 feet'ten az olmayan bir mesafede","Otobüsün önünden 20 feet'ten az olmayan bir mesafede","Otobüsün önünden 25 feet'ten az olmayan bir mesafede"],"explanation":"Connecticut General Statutes Sec. 14-279, yanıp sönen kırmızı sinyal ışıkları gösteren tescilli bir okul otobüsüne yaklaşırken araçların önden 10 feet'ten az olmayan, sollarken veya takip ederken ise arkadan 10 feet'ten az olmayan bir mesafede durmasını şart koşar."},"63":{"q":"Connecticut'ta tek yönlü veya bölünmüş bir karayolunda arızalı bir CMV'yi durdurduktan sonra, sürücü üç adet yansıtıcı uyarı üçgenini nereye yerleştirmelidir?","options":["Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e","Aracın arkasına 10 feet, 50 feet ve 150 feet'e","Yaklaşan trafiğe doğru 25 feet, 75 feet ve 125 feet'e","Yaklaşan trafiğe doğru 5 feet, 50 feet ve 500 feet'e"],"explanation":"Connecticut CDL Manual (49 CFR 392.22'yi yansıtarak), tek yönlü veya bölünmüş bir karayolunda, uyarı cihazlarının durdurulmuş aracın arkasında yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e yerleştirilmesini yönlendirir."},"64":{"q":"Connecticut'ta bir CDL sürücüsü, yol üzerinde veya bankette bir CMV'yi durdurduktan sonra kaç dakika içinde acil durum uyarı cihazlarını yerleştirmek zorundadır?","options":["10 dakika içinde","30 dakika içinde","5 dakika içinde","Hemen, kabinden çıkmadan önce"],"explanation":"Connecticut CDL Manual, bir yol veya bankette durmanız gerekirse, dörtlü flaşörleri açmanız ve acil durum uyarı cihazlarını 10 dakika içinde yerleştirmeniz gerektiğini belirtir."},"65":{"q":"Hangi liste, Connecticut'ta her demir yolu hemzemin geçidinde DURMAK zorunda olan araçları doğru şekilde tanımlar?","options":["Yolcu taşıyan otobüsler, okul taşıma araçları ve kargo tankı bulunan ya da tehlikeli madde taşıyan CMV'ler","Yükü ne olursa olsun 10,000 pound üzerindeki tüm ticari araçlar","Yalnızca boş tanker kamyonları ve çekiciler","Yalnızca römork çeken araçlar"],"explanation":"Connecticut General Statutes Sec. 14-250, yolcu taşıyan her CMV'nin, servis otobüsünün veya okul çocuklarını taşımak için kullanılan aracın ve kargo tankı bulunan ya da tehlikeli madde taşıyan her CMV'nin operatörünün, geçmeden önce en yakın raya 15 ila 50 feet mesafede durmasını şart koşar."},"66":{"q":"Bir CMV'nin Connecticut'taki bir interstate karayolunda yasal olarak ilerleyebileceği en yüksek belirtilen hız sınırı nedir?","options":["65 mph, binek araçlara uygulanan aynı azami sınır","55 mph, eyalet genelinde tüm kamyonlar için özel bir daha düşük sınır","Kırsal interstate'lerde 70 mph","26,000 pound üzerindeki herhangi bir araç için 60 mph"],"explanation":"Connecticut'ın azami belirtilen hız sınırı 65 mph'dir (CGS Sec. 14-219 / 14-218a) ve eyalet, kamyonlar için ayrı, daha düşük bir eyalet çapında hız sınırı belirlemez - kamyonlar ve otomobiller belirtilen yerlerde aynı 65 mph azami sınırını paylaşır. Sürücüler yine de belirtilen daha düşük sınırlara uymalıdır."},"67":{"q":"Connecticut'ta her iki yönde trafiği taşıyan iki şeritli bir yolda (bölünmemiş), bir CMV sürücüsü durduktan sonra üç uyarı üçgenini nereye yerleştirmelidir?","options":["Aracın 10 feet yakınına ve önüne 100 feet, arkasına 100 feet'e","Yalnızca aracın arkasına 10 feet, 100 feet ve 200 feet'e","Yalnızca aracın önüne 50 feet ve arkasına 50 feet'e","Önüne ve arkasına 10 feet yakınına ve her yöne 250 feet'e"],"explanation":"Connecticut CDL Manual, iki şeritli, çift yönlü veya bölünmemiş bir karayolunda, bir üçgeni aracın 10 feet yakınına ve birer üçgeni de durduğunuz banket veya şeritte 100 feet arkaya ve 100 feet öne yerleştirmenizi öğütler."},"68":{"q":"Connecticut'ın sağdan git kuralı uyarınca, normal trafik hızından daha yavaş ilerleyen bir araç nerede sürülmelidir?","options":["Sağdaki şeritte veya karayolunun sağ kenarına mümkün olduğunca yakın","Flaşörlerini kullandığı sürece herhangi bir şeritte","Üç şeritli bir yolun orta şeridinde","Trafiğe karışmaktan kaçınmak için sol şeritte"],"explanation":"Connecticut General Statutes Sec. 14-230, araçların sağdan sürülmesini ve normal trafik hızından daha yavaş ilerleyen herhangi bir aracın mevcut sağdaki şeritte veya sağ kaldırıma ya da kenara mümkün olduğunca yakın sürülmesini şart koşar."},"69":{"q":"Connecticut, bu tür araçların yasak olduğu bir eyalet parkway'inde ticari motorlu araç kullanmak için hangi cezayı uygular?","options":["Her ihlal için $500 ceza","İlk suçta yalnızca yazılı uyarı","İki puanla birlikte $35 ceza","30 günlük zorunlu ehliyet askıya alınması"],"explanation":"Connecticut, bir parkway'de (Merritt, Wilbur Cross, Milford) yasak bir ticari aracı kullanma cezasını ihlal başına $500'a yükseltti. CT DOT Parkway Restrictions; CGS Chapter 249 / Sec. 14-298 parkway kısıtlama yetkisi."},"70":{"q":"Acil durum araçlarının yanı sıra, Connecticut'ın Move Over yasası sürücülerin aşağıdakilerden hangisi bankette durduğunda yavaşlamasını ve yana geçmesini de gerektirir?","options":["Bankette duran, acil durum aracı olmayan bir araç","Yalnızca işaretli polis araçları","Yalnızca kırmızı işaret fişekleri yerleştirilmiş araçlar","Bir otobüs durağında bekleyen yayalar"],"explanation":"Connecticut General Statutes Sec. 14-283b, yalnızca ışıkları yanıp sönen acil durum araçlarını (bakım araçları ve çekiciler dahil) değil, aynı zamanda bankette duran ve konumlanan herhangi bir acil durum aracı olmayan aracı da kapsayacak şekilde genişletildi; sürücüler güvenli olduğunda yavaşlamalı ve yana geçmelidir."},"71":{"q":"Connecticut'ta bir aracın genellikle bir DOT aşırı yük izni gerektirdiği yasal ağırlık sınırı nedir?","options":["80,000 pound brüt araç ağırlığı","73,280 pound brüt araç ağırlığı","100,000 pound brüt araç ağırlığı","65,000 pound brüt araç ağırlığı"],"explanation":"Connecticut, 80,000 pound brüt araç ağırlığı (beş aks üzerinde) federal yasal azami sınırını izler. 80,000 pound'u aşan yükler bir CT DOT aşırı yük izni gerektirir. CT DOT Oversize/Overweight Permit düzenlemeleri."},"72":{"q":"Connecticut'ta kırmızı ışıkları yanıp sönen durmuş bir okul otobüsünü yasadışı bir şekilde geçmek için (ikinci veya sonraki bir ihlal) hangi sonraki suç cezası uygulanır?","options":["$500'dan az, $1,000'dan fazla olmayan ve/veya 30 güne kadar hapis","Hapis olmaksızın sabit $90'lık bir kabahat","Bir uyarı mektubu ve iki ehliyet puanı","İlk suçla aynı sabit $450 ceza"],"explanation":"Connecticut General Statutes Sec. 14-279, durmuş bir okul otobüsünü geçmenin ilk suçu için $450 ceza belirler ve her sonraki suç için $500'dan az, $1,000'dan fazla olmayan ceza ya da 30 günden fazla olmayan hapis ya da her ikisini birden öngörür."},"73":{"q":"Connecticut'ta bir büyük boyut izni gerekmeden önceki azami yasal araç yüksekliği nedir?","options":["13 feet 6 inches","12 feet 0 inches","14 feet 6 inches","13 feet 0 inches"],"explanation":"Connecticut'ın yasal boyut azami sınırları 8 feet 6 inches genişlik ve 13 feet 6 inches yüksekliktir (53 feet'lik bir yarı römork uzunluğuyla). Yükseklikte 13 feet 6 inches'i aşmak bir CT DOT büyük boyut izni gerektirir. CT DOT Oversize/Overweight Permit düzenlemeleri."},"74":{"q":"Bir CDL sürücüsü Connecticut'ta, en son tehlikeli maddeler için kullanılmış BOŞ bir kargo tankı çekerek bir demir yolu geçidine yaklaşır. Sürücü ne yapmalıdır?","options":["En yakın raya 15 ila 50 feet mesafede durmalı, çünkü kural kargo tankları için yüklü ya da boş fark etmeksizin geçerlidir","Tank boş olduğu için durmadan devam etmeli","Yalnızca bir tren görünürse durmalı","5 mph'e yavaşlamalı ama tam durmadan karşıya geçmeli"],"explanation":"Connecticut General Statutes Sec. 14-250 ve CT CDL Manual, tehlikeli maddeler için kullanılan kargo tankları bulunan araçların, tank yüklü VEYA boş olsun, en yakın raya 15 ila 50 feet mesafede durmasını ve yalnızca raylar durmadan geçilebildiğinde geçmesini şart koşar."},"75":{"q":"Connecticut'ta Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Connecticut Department of Motor Vehicles (DMV)","Connecticut Department of Transportation (CTDOT)","Federal Motor Carrier Safety Administration (FMCSA)","Connecticut State Police, Commercial Vehicle Safety Division"],"explanation":"Connecticut'ta Department of Motor Vehicles (DMV), CDL'leri verir ve bilgi ile beceri sınavlarını yürütür. CTDOT büyük boyut/aşırı yük izinlerini ele alır ve FMCSA federal standartları belirler, ancak belgenin kendisi bir eyalet DMV kimlik belgesidir. Kaynak: CT DMV, 'Get a commercial driver's license' (portal.ct.gov/dmv)."},"76":{"q":"Connecticut'ta intrastate (yalnızca eyalet içi) operasyon için bir CDL almanın asgari yaşı nedir?","options":["18 yaşında","16 yaşında","21 yaşında","25 yaşında"],"explanation":"Connecticut, bir CMV'yi intrastate (yalnızca Connecticut içinde) kullanmak için bir sürücünün en az 18 yaşında olmasını gerektirir. Bir sürücünün interstate sürmek veya tehlikeli madde taşımak için en az 21 yaşında olması gerekir. Kaynak: CT DMV, 'Get a commercial driver's license' / 'Get a commercial learner's permit.'"},"77":{"q":"Connecticut'ta interstate ticarette bir ticari motorlu araç kullanmanın veya tehlikeli madde taşımanın asgari yaşı nedir?","options":["21 yaşında","18 yaşında","19 yaşında","23 yaşında"],"explanation":"Connecticut, federal standardı izleyerek, bir sürücünün bir CMV'yi eyalet sınırları ötesinde (interstate) kullanmak veya plakart gerektiren miktarlarda tehlikeli madde taşımak için en az 21 yaşında olmasını gerektirir. 18-20 yaş arası sürücüler intrastate operasyonla sınırlıdır. Kaynak: CT DMV CLP/CDL sayfaları; 49 CFR 391.11."},"78":{"q":"Connecticut'ta yeni bir başvuru sahibi Class A veya Class B belgesi için CDL beceri sınavına girmeden önce, hangi eğitimin tamamlanması gerekir?","options":["FMCSA'da kayıtlı bir sağlayıcıdan Entry-Level Driver Training (ELDT) — teori artı direksiyon başında","Yalnızca 160 saatlik eyalet onaylı bir meslek okulu programı","Connecticut DMV onaylı bir defansif sürüş kursu","Sekiz saatlik çevrimiçi bir tehlikeli madde farkındalık kursu"],"explanation":"7 Şubat 2022'den itibaren, başlangıç seviyesi bir başvuru sahibi, Class A/B beceri sınavına girmeden önce (ve uygun olduğunda P, S veya H onayı sınavlarından önce) FMCSA Training Provider Registry'de yer alan bir sağlayıcı aracılığıyla zorunlu Entry-Level Driver Training (ELDT) — hem teori (bilgi) hem de direksiyon başında (BTW) — tamamlamalıdır. Kaynak: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR Part 380 Subpart F."},"79":{"q":"Connecticut'ta bir başvuru sahibinin aşağıdaki onaylardan hangisinin bilgi sınavına girmeden önce Entry-Level Driver Training'i tamamlaması gerekir?","options":["Hazardous Materials (H) onayı","Tank Vehicle (N) onayı","Double/Triple Trailers (T) onayı","Yalnızca Combination (onay harfi olmayan) sınıfı"],"explanation":"ELDT, Hazardous Materials (H) onayı BİLGİ sınavından önce tamamlanmalıdır (H'nin beceri sınavı yoktur). ELDT ayrıca Passenger (P) ve School Bus (S) onaylarının beceri sınavlarından önce de gereklidir. N ve T onayları ELDT'ye tabi değildir. Kaynak: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR 380.609."},"80":{"q":"Connecticut lisanslama sürecinde, tam CDL'den önce yeni bir CDL başvuru sahibinin İLK olarak hangi belgeyi alması gerekir?","options":["Bir Commercial Learner's Permit (CLP)","DMV'den bir DOT fizik muayenesi muafiyeti","Bir taşıyıcı işletme yetkisi (MC numarası)","Geçici bir interstate taşıma sertifikası"],"explanation":"Süreç, bir Commercial Learner's Permit (CLP) almak için gerekli bilgi sınavlarını geçmekle başlar. Başvuru sahibi daha sonra pratik yapar, ELDT'yi tamamlar ve CLP'yi bir CDL'ye dönüştürmek için beceri sınavına girer. Kaynak: CT DMV, 'Get a commercial learner's permit' ve 'Get a commercial driver's license.'"},"81":{"q":"Bir Connecticut Commercial Learner's Permit (CLP), veriliş tarihinden itibaren ne kadar süre geçerlidir?","options":["Bir yıl","60 gün","Altı ay","İki yıl"],"explanation":"Bir Connecticut CLP, veriliş tarihinden itibaren bir yıl geçerlidir. Sahibi o yıl içinde CDL'yi almazsa, yeni bir izin almak için tüm gerekli sınavlar yeniden yapılmalıdır. Kaynak: CT DMV, 'Get a commercial learner's permit.'"},"82":{"q":"Connecticut'ta bir başvuru sahibinin CDL beceri sınavına girme hakkına sahip olmadan önce CLP'yi ne kadar süre elinde tutması gerekir?","options":["En az 14 gün","En az 30 gün","En az 10 gün","En az 60 gün"],"explanation":"Bir başvuru sahibi, CDL beceri sınavına girmeden önce CLP'yi en az 14 gün elinde tutmalıdır. Bu federal asgari bekleme süresi Connecticut'ta uygulanır. Kaynak: CT DMV, 'Get a commercial learner's permit'; 49 CFR 383.25(a)(3)."},"83":{"q":"Connecticut CDL genel bilgi sınavı 50 sorudan oluşur. Geçmek için kaç tanesinin doğru cevaplanması gerekir?","options":["40 doğru (%80)","35 doğru (%70)","45 doğru (%90)","30 doğru (%60)"],"explanation":"Connecticut genel bilgi sınavı 50 çoktan seçmeli soruya sahiptir ve geçmek için 40 doğru cevap (%80) gerektirir. Kaynak: CT DMV, 'Get a commercial learner's permit.'"},"84":{"q":"Connecticut CDL beceri sınavı kaç ayrı bölümden oluşur?","options":["Üç bölüm","İki bölüm","Dört bölüm","Beş bölüm"],"explanation":"CDL beceri sınavının üç bölümü vardır: sefer öncesi araç muayenesi, temel araç kontrol becerileri sınavı ve yol üzerinde sürüş sınavı. CDL'yi kazanmak için üçünün de geçilmesi gerekir. Kaynak: CT DMV CDL testing; 49 CFR 383.113."},"85":{"q":"Aşağıdakilerden hangisi Connecticut CDL beceri sınavının üç gerekli bölümünden biridir?","options":["Sefer öncesi araç muayenesi","50 soruluk genel bilgi sınavı","DOT fizik muayenesi","Hava frenleri yazılı onay sınavı"],"explanation":"Üç beceri sınavı bölümü, sefer öncesi araç muayenesi, temel araç kontrolü ve yol üzerinde sürüştür. Genel bilgi ve hava frenleri sınavları YAZILI bilgi sınavlarıdır (CLP için girilir) ve DOT fizik muayenesi bir tıbbi muayenedir — bunların hiçbiri beceri sınavının bir parçası değildir. Kaynak: CT DMV; 49 CFR 383.113."},"86":{"q":"Connecticut CDL yol sınavı sırasında, başvuru sahibinin kontrollü bir alanda düz hat geri gitme veya ofset geri gitme gibi manevralar yaptığı bölüm şu şekilde adlandırılır:","options":["Temel araç kontrol becerileri sınavı","Sefer öncesi muayene sınavı","Yol üzerinde sürüş sınavı","Combination araç sınavı"],"explanation":"Kamuya açık yolların dışında yapılan geri gitme ve konumlandırma manevraları, üç beceri sınavı bileşeninin ikincisi olan temel araç kontrol becerileri sınavının bir parçasıdır. Sefer öncesi muayenedir ve yol üzerinde sınav trafikte yapılır. Kaynak: CT DMV; 49 CFR 383.113(b)."},"87":{"q":"Bir Connecticut CDL başvuru sahibi hava frenleri bilgi sınavına girmez veya geçmezse, belgeye ne olur?","options":["Hava frenli herhangi bir CMV'nin kullanımını yasaklayan bir 'L' kısıtlaması konur","Hava frenleri geçilene kadar başvuru sahibine CDL tamamen reddedilir","Sürücüyü intrastate operasyonla sınırlayan bir 'K' kısıtlaması eklenir","Hiçbir şey — hava frenleri isteğe bağlıdır ve hiçbir kısıtlama bırakmaz"],"explanation":"Hava frenleri bilgi sınavını (ve ilgili beceri kontrollerini) geçemeyen bir sürücü, hava frenli herhangi bir CMV'yi kullanmasını yasaklayan bir 'L' kısıtlaması alır. Kaynak: CT DMV CLP/CDL bilgileri; 49 CFR 383.95."},"88":{"q":"Connecticut'ta uygulanan federal CDL kuralları, her CDL/CLP sahibinin 'öz beyanda bulunmasını' (self-certify) gerektirir. Federal çerçeve kaç öz beyan sürüş türü kategorisi tanımlar?","options":["Dört","İki","Üç","Altı"],"explanation":"Federal öz beyan çerçevesi dört kategori tanımlar: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Connecticut'ın çevrimiçi öz beyanı pratikte çoğu sürücünün kullandığı iki istisnasız seçeneği sunar (NI ve NA). Kaynak: 49 CFR 383.71(b); CT DMV self-certification."},"89":{"q":"Kendisini 'Non-Excepted Interstate' (NI) olarak öz beyan eden bir Connecticut sürücüsü, operasyonu ve tıbbi durumu hakkında hangi beyanı yapmaktadır?","options":["Eyalet sınırları ötesinde çalışırlar ve federal DOT tıbbi sertifika gerekliliğini karşılamalıdırlar","Yalnızca Connecticut içinde çalışırlar ve DOT tıbbi gerekliliklerinden muaftırlar","Eyalet sınırları ötesinde çalışırlar ancak herhangi bir tıbbi sertifikadan muaftırlar","Yalnızca Connecticut içinde çalışırlar ve bir tehlikeli madde izni taşımalıdırlar"],"explanation":"Non-Excepted Interstate (NI), sürücünün interstate ticarette (Connecticut içinde ve dışında) bir CMV kullandığı ve federal DOT tıbbi sertifika gerekliliklerine tabi olduğu ve bunları karşılaması gerektiği anlamına gelir. Kaynak: CT DMV self-certification; 49 CFR 383.71(b)."},"90":{"q":"Kendisini 'Non-Excepted Intrastate' (NA) olarak öz beyan eden bir Connecticut sürücüsü, neyi yapacağını beyan etmektedir:","options":["Bir ticari motorlu aracı yalnızca Connecticut sınırları içinde kullanmak","Federal bir tıbbi muafiyet altında eyalet sınırları ötesinde çalışmak","Herhangi bir tıbbi sertifika olmadan ülke çapında çalışmak","Yalnızca CDL kurallarından muaf tarım ekipmanı kullanmak"],"explanation":"Non-Excepted Intrastate (NA), bir CMV'nin yalnızca Connecticut içinde kullanımını beyan eder. Bu tür sürücüler onları intrastate sürüşle sınırlayan bir 'K' kısıtlaması taşıyabilir ve Connecticut'ın tıbbi/sürücü uygunluk standartlarını karşılamalıdır. Kaynak: CT DMV self-certification (dmvselfservice.ct.gov)."},"91":{"q":"Bir CDL/CLP sahibi, Connecticut DMV ile öz beyan adımını nasıl tamamlar?","options":["DMV çevrimiçi self-service sistemi aracılığıyla gönderir ve basılı e-posta onayını DMV'ye getirir","Tıbbi muayene uzmanının kağıt bir sertifikayı FMCSA genel merkezine postalamasını sağlar","Yalnızca yol sınavı sırasında, sınav görevlisine sözlü olarak öz beyanda bulunur","Sertifikayı Connecticut Department of Labor'a dosyalar"],"explanation":"Sürücü, Connecticut DMV self-service portalı (dmvselfservice.ct.gov) aracılığıyla çevrimiçi öz beyanda bulunur, bir e-posta onayı alır ve başvuru, yenileme, yükseltme yaparken ya da sürüş türünü değiştirirken o basılı onayı DMV'ye getirir. Kaynak: CT DMV self-certification."},"92":{"q":"Bir sertifikalı tıbbi muayene uzmanı, bir Connecticut CDL sahibinin DOT fizik muayenesini belgelemek için hangi formu kullanmalıdır ve bu nasıl DMV'ye ulaşır?","options":["Form MCSA-5876, muayene uzmanı tarafından National Registry aracılığıyla yüklenir ve DMV'ye elektronik olarak gönderilir","Form R-229a, başvuru sahibi tarafından 30 gün içinde DMV'ye postalanır","Form MCSA-5876, sürücü tarafından elden taşınır ve herhangi bir DMV şubesinde taranır","El yazısı bir doktor notu, başvuru sahibi tarafından FMCSA'ya fakslanır"],"explanation":"DOT tıbbi muayenesi, National Registry of Certified Medical Examiners'da listelenen bir muayene uzmanı tarafından Form MCSA-5876 (Medical Examiner's Certificate) üzerine kaydedilmelidir; muayene uzmanı sonuçları National Registry aracılığıyla yükler ve bunlar Connecticut DMV'ye elektronik olarak iletilir. Kaynak: CT DMV, 'Getting medical certification for CDL.'"},"93":{"q":"Sahibi, DMV'de geçerli bir DOT tıbbi sertifikasını dosyada tutmazsa bir Connecticut CDL'sine ne olur?","options":["Bir düşürme bildiriminden sonra, belge ticari olmayan bir Class D belgesine düşürülür","CDL kalıcı olarak iptal edilir ve yeniden verilemez","Her ay otomatik olarak $500 federal idari para cezası uygulanır","Düzenli yenileme tarihi gelene kadar hiçbir şey değişmez"],"explanation":"Geçerli bir tıbbi sertifika sürdürülmezse, sürücünün tıbbi durumu 'Not Certified' olur; DMV bir düşürme bildirimi gönderir ve belirtilen tarihe kadar elektronik olarak yeni geçerli bir sertifika alınmazsa, CDL bir Class D (ticari olmayan) belgesine düşürülür. Kaynak: CT DMV, 'Getting medical certification for CDL.'"},"94":{"q":"Bir Connecticut Commercial Driver License ne sıklıkla yenilenmelidir?","options":["Her dört yılda bir","Her altı yılda bir","Her iki yılda bir","Her sekiz yılda bir"],"explanation":"Bir Connecticut CDL, standart ticari olmayan belge süresinden daha kısa olan dört yıllık bir yenileme döngüsünde (sahibinin doğum günü civarında yenilenerek) verilir. Kaynak: CT DMV, 'Renew a CDL (commercial) license'; Conn. Gen. Stat. § 14-44h."}},"es":{"0":{"q":"Según la ley de Connecticut, ¿cuál es el ancho máximo de un vehículo comercial (sin contar dispositivos de seguridad como los espejos) que se permite circular por las carreteras de Connecticut sin un permiso especial?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","120 pulgadas (10 pies)"],"explanation":"La Sección 14-262 de los Estatutos Generales de Connecticut establece el ancho máximo legal del vehículo en 102 pulgadas (8 pies 6 pulgadas), sin contar dispositivos de seguridad como los espejos. La hoja de Limitaciones de Tamaño y Peso de Vehículos del CTDOT indica un ancho de 102.37 pulgadas. Fuente: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"1":{"q":"En Connecticut, ¿cuál es la altura máxima, incluida la carga, que puede tener un vehículo antes de que se requiera un permiso especial de altura del Comisionado de Transporte?","options":["12 pies 6 pulgadas","13 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 0 pulgadas"],"explanation":"La Sección 14-264 de los Estatutos Generales de Connecticut prohíbe operar un vehículo cuya altura, con su carga, supere los 13 pies 6 pulgadas sin un permiso especial por escrito (excepto una carga de heno o paja sueltos). Fuente: CGS Sec. 14-264; CTDOT Vehicle Size and Weight Limitations."},"2":{"q":"En Connecticut, ¿cuál es la longitud máxima, incluida la carga, de un camión de una sola unidad (camión rígido) que opera sin permiso?","options":["40 pies","45 pies","48 pies","53 pies"],"explanation":"La Sección 14-262 de los Estatutos Generales de Connecticut limita un vehículo de una sola unidad a una longitud máxima, incluida la carga, de 45 pies. Fuente: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations (\"Single unit vehicle 45 feet\")."},"3":{"q":"Para un tractor que remolca un solo semirremolque en carreteras generales (no restringidas) de Connecticut, ¿cuál es la longitud legal máxima del semirremolque?","options":["45 pies","48 pies","53 pies","57 pies"],"explanation":"En las carreteras generales, Connecticut permite una combinación de tractor y semirremolque de 48 pies sin límite de longitud total, pero el remolque en sí está limitado a 48 pies. Fuente: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"4":{"q":"En el sistema de carreteras designadas (restringidas) de Connecticut, se permite un semirremolque de 53 pies siempre que la distancia desde el pivote de enganche (kingpin) hasta el centro del eje trasero más alejado no supere qué medida?","options":["41 pies","43 pies","45 pies","48 pies"],"explanation":"En el sistema de carreteras designadas, Connecticut permite un tractor y un semirremolque de 53 pies sin límite de longitud total, pero la distancia desde el pivote de enganche hasta el centro del eje trasero más alejado no debe superar los 43 pies. Fuente: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations."},"5":{"q":"En el sistema de carreteras designadas de Connecticut, un tractor que remolca remolques dobles (gemelos) puede tener cada remolque con qué longitud máxima?","options":["27 pies","28 pies","33 pies","40 pies"],"explanation":"En el sistema de carreteras designadas, Connecticut permite una combinación de tractor y remolques dobles sin límite de longitud total, pero cada remolque está limitado a 28 pies. Fuente: CTDOT Vehicle Size and Weight Limitations (Restricted to the Designated Highway System)."},"6":{"q":"¿Cuál es el peso bruto vehicular máximo que puede transportar una combinación de 5 ejes en las carreteras de Connecticut sin un permiso de sobrepeso, cuando se cumplen los requisitos de la fórmula de puentes?","options":["73,000 libras","80,000 libras","88,000 libras","90,000 libras"],"explanation":"El peso máximo práctico de Connecticut es de 80,000 libras sobre 5 ejes con 51 pies entre el primer y el último eje, permitido cuando se cumplen los requisitos de la Fórmula Federal de Puentes (Federal Bridge Formula). Fuente: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"7":{"q":"En Connecticut, ¿cuál es el peso máximo permitido sobre un solo eje cuando ese eje está separado 6 pies o más de los ejes adyacentes?","options":["18,000 libras","20,000 libras","22,400 libras","24,000 libras"],"explanation":"Connecticut permite 22,400 libras por eje cuando los ejes están separados 6 pies o más; los ejes separados menos de 6 pies están limitados a 18,000 libras por eje. Fuente: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"8":{"q":"Según las normas de peso de Connecticut, ¿cuál es el peso máximo permitido sobre cualquier eje individual cuando ese eje está separado MENOS de 6 pies de un eje adyacente?","options":["16,000 libras","18,000 libras","20,000 libras","22,400 libras"],"explanation":"Connecticut limita los ejes separados menos de 6 pies a 18,000 libras por eje; solo con una separación de 6 pies o más se permiten 22,400 libras. Fuente: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a."},"9":{"q":"Cuando el peso bruto de un vehículo combinado de Connecticut supera las 73,000 libras (hasta 80,000 libras), ¿qué requisito adicional debe cumplirse?","options":["El vehículo debe usar únicamente neumáticos de caucho macizo","Deben cumplirse todos los requisitos de la Fórmula Federal de Puentes","El vehículo debe circular solo de noche","Una escolta policial debe acompañar al vehículo"],"explanation":"Según el CTDOT, un peso bruto máximo de 80,000 libras se permite únicamente cuando se cumplen todos los requisitos de la Fórmula Federal de Puentes (Federal Bridge Formula) para pesos superiores a 73,000 libras. Fuente: CTDOT Vehicle Size and Weight Limitations (Gross Vehicle Weights Over 73,000 pounds)."},"10":{"q":"En Connecticut, el peso máximo permitido que los neumáticos de cualquier vehículo transmiten a la carretera se basa en el ancho del neumático. ¿Cuál es ese límite?","options":["500 libras por pulgada de ancho del neumático","600 libras por pulgada de ancho del neumático","700 libras por pulgada de ancho del neumático","800 libras por pulgada de ancho del neumático"],"explanation":"Connecticut limita la carga del neumático a 600 libras por pulgada de ancho del neumático (máximo). Fuente: CTDOT Vehicle Size and Weight Limitations (Tires - Load per inch width of tire 600 pounds maximum)."},"11":{"q":"¿Cuál es el peso bruto máximo permitido en Connecticut para un camión rígido de 2 ejes cuando ninguno de los ejes supera las 18,000 libras?","options":["32,000 libras","36,000 libras","40,000 libras","53,800 libras"],"explanation":"Connecticut permite un vehículo de 2 ejes de hasta 36,000 libras cuando el peso por eje no supera las 18,000 libras (32,000 libras es la cifra sin esa condición de eje). Fuente: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a."},"12":{"q":"Para una combinación de tractor y semirremolque en Connecticut, ¿cuál es el peso bruto máximo cuando la combinación tiene 3 ejes?","options":["53,800 libras","58,400 libras","67,400 libras","73,000 libras"],"explanation":"Connecticut establece un máximo de 58,400 libras para una combinación de tractor y semirremolque de 3 ejes; una combinación de 4 ejes es de 67,400 libras y la de 5 o más ejes hasta 73,000 libras. Fuente: CTDOT Vehicle Size and Weight Limitations (Tractor Semitrailer)."},"13":{"q":"El estándar federal de peso que Connecticut aplica para determinar el peso bruto máximo permitido sobre un grupo de ejes consecutivos se conoce como:","options":["Regla Federal de Separación de Ejes (Federal Axle Spread Rule)","Fórmula Federal de Puentes (Federal Bridge Formula)","Estándar Federal de Combinación Bruta (Federal Gross Combination Standard)","Tabla Federal de Peso de Ejes en Tándem (Federal Tandem Weight Table)"],"explanation":"Connecticut aplica la Fórmula Federal de Puentes (Federal Bridge Formula) para determinar el peso permitido en los grupos de ejes; debe cumplirse para pesos brutos superiores a 73,000 libras hasta 80,000 libras. Fuente: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a."},"14":{"q":"En Connecticut, ¿quién emite los permisos para vehículos sobredimensionados/con sobrepeso (vehículos no conformes) y a través de qué sistema se presentan las solicitudes?","options":["El Comisionado de Transporte, a través del WebPortal de Operaciones de Vehículos Comerciales (CVO) administrado por el DMV","El departamento de policía local de cada pueblo por el que pasa el vehículo","El portal en línea de la Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Energía y Protección Ambiental, mediante solicitud en papel"],"explanation":"Según la CGS Sec. 14-270, el Comisionado de Transporte emite permisos especiales para vehículos no conformes (sobredimensionados/con sobrepeso); las solicitudes se tramitan a través del WebPortal de Operaciones de Vehículos Comerciales (CVO) de Connecticut, administrado por el CT DMV. Fuente: CGS Sec. 14-270; CTDOT Oversize/Overweight Permit FAQ."},"15":{"q":"Un permiso estándar de Connecticut de un solo viaje para vehículos sobredimensionados/con sobrepeso generalmente es válido por qué período, y la circulación está restringida a qué horario?","options":["30 días; cualquier hora del día o de la noche","3 días; solo durante las horas de luz diurna","7 días; solo de noche","1 día; excluidas las horas pico"],"explanation":"El CTDOT emite permisos de un solo viaje para vehículos sobredimensionados/con sobrepeso válidos por un período de 3 días, con circulación limitada a las horas de luz diurna (generalmente desde media hora después del amanecer hasta media hora antes del atardecer). Fuente: CTDOT Vehicle Size and Weight Limitations; CTDOT Oversize/Overweight Permit FAQ."},"16":{"q":"Según la ley de Connecticut (CGS Sec. 14-267a), ¿cuál es la multa por operar un vehículo comercial con sobrepeso, según la cantidad de exceso de peso?","options":["$1 por cada 100 libras de exceso de peso","$3 por cada 100 libras (o fracción de las mismas) de exceso de peso","$10 por cada 100 libras de exceso de peso","Una tarifa fija de $500 sin importar el exceso de peso"],"explanation":"La Sección 14-267a de los Estatutos Generales de Connecticut establece la multa por sobrepeso en tres dólares por cada cien libras, o fracción de las mismas, de exceso de peso. Fuente: CGS Sec. 14-267a."},"17":{"q":"Connecticut ofrece una concesión especial de peso para cierto transporte agrícola. ¿Cuál es el peso bruto vehicular máximo permitido para una cisterna de recolección de leche a granel o para un vehículo que transporta productos agrícolas (donde la ley federal lo permita)?","options":["80,000 libras","88,000 libras","100,000 libras","120,000 libras"],"explanation":"La Sección 14-267a de los Estatutos Generales de Connecticut establece un peso bruto permitido de hasta 100,000 libras para cisternas de recolección de leche a granel y vehículos que transportan productos agrícolas (alimento para ganado, semillas, fertilizantes y productos de la agricultura), donde la ley federal lo permita. Fuente: CGS Sec. 14-267a."},"18":{"q":"Según la CGS Sec. 14-267a, para un vehículo con dos conjuntos consecutivos de ejes en tándem, se permite una carga bruta de 68,000 libras sobre esos tándems solo si la distancia entre el primer y el último eje de los dos conjuntos es de al menos:","options":["30 pies","34 pies","36 pies","40 pies"],"explanation":"La Sección 14-267a de los Estatutos Generales de Connecticut permite que dos conjuntos consecutivos de ejes en tándem transporten una carga bruta de 68,000 libras siempre que la distancia total entre el primer y el último eje de esos conjuntos consecutivos en tándem sea de 36 pies o más. Fuente: CGS Sec. 14-267a."},"19":{"q":"En Connecticut, ¿cuál es la Calificación de Peso Bruto Vehicular (GVWR) mínima que coloca a un solo vehículo en la categoría de CDL Clase B?","options":["16,001 libras o más","26,001 libras o más","10,001 libras o más","33,001 libras o más"],"explanation":"Una CDL Clase B de Connecticut autoriza conducir cualquier vehículo individual con un GVWR de 26,001 libras o más, y cualquier vehículo de ese tipo que remolque una unidad que no supere las 10,000 libras. Fuente: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"20":{"q":"Según las normas de Connecticut, se requiere una CDL Clase A para conducir una combinación de vehículos con un GVWR de 26,001 libras o más siempre que el GVWR de la unidad remolcada supere qué cifra?","options":["5,000 libras","26,001 libras","10,000 libras","15,000 libras"],"explanation":"Una CDL Clase A de Connecticut cubre combinaciones con un GVWR de 26,001 libras o más donde el GVWR del vehículo remolcado supera las 10,000 libras. Fuente: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"21":{"q":"Un conductor de Connecticut opera un vehículo individual de menos de 26,001 libras de GVWR diseñado para transportar 20 pasajeros incluido el conductor. ¿Qué clase de CDL aplica?","options":["Clase A","Clase B","Clase C","No se requiere CDL"],"explanation":"Una CDL Clase C de Connecticut cubre un vehículo individual de menos de 26,001 libras de GVWR (o que remolca una unidad que no supere las 10,000 libras) diseñado para transportar 16 o más pasajeros incluido el conductor, o que transporta materiales peligrosos que requieren rótulos (placards). Fuente: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"22":{"q":"¿Cuál es la edad mínima para obtener una CDL de Connecticut restringida a la operación intraestatal (solo dentro de Connecticut)?","options":["16","18","19","21"],"explanation":"Connecticut exige que el solicitante tenga al menos 18 años para una CDL intraestatal (operación solo dentro de Connecticut). Fuente: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"23":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo motorizado comercial en el comercio interestatal con una CDL de Connecticut?","options":["18","19","20","21"],"explanation":"Connecticut exige que el solicitante tenga al menos 21 años para la operación interestatal (dentro y fuera de Connecticut). Fuente: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"24":{"q":"¿Qué endoso exige Connecticut para conducir un vehículo que transporta materiales peligrosos en cantidades que requieren rótulos (placards)?","options":["Endoso N","Endoso H","Endoso T","Endoso X"],"explanation":"Connecticut exige el endoso H (Materiales Peligrosos / HazMat) para operar un vehículo que transporta materiales peligrosos con rótulos. Fuente: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"25":{"q":"En Connecticut, el endoso N (cisterna/líquidos a granel) se requiere para una cisterna de carga montada permanentemente con qué capacidad mínima?","options":["100 galones o más","119 galones o más","500 galones o más","1,000 galones o más"],"explanation":"Connecticut exige el endoso N para un vehículo diseñado para transportar un líquido o gas licuado en una cisterna de carga montada permanentemente con una capacidad de 119 galones o más (o una cisterna portátil con capacidad de 1,000 galones o más). Fuente: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"26":{"q":"¿Qué endoso de Connecticut se requiere para remolcar más de un remolque con un vehículo que requiere una CDL Clase A?","options":["Endoso P","Endoso N","Endoso T","Endoso S"],"explanation":"Connecticut exige el endoso T (Dobles/Triples) cuando un vehículo con CDL Clase A remolca más de un remolque. Fuente: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"27":{"q":"Antes de que se pueda emitir un endoso S (autobús escolar) a un conductor de Connecticut, ¿qué otro endoso debe tener también el conductor?","options":["H (Materiales Peligrosos)","N (Cisterna)","P (Pasajeros)","T (Dobles/Triples)"],"explanation":"En Connecticut, el endoso de autobús escolar (S) también requiere que el titular tenga el endoso de Pasajeros (P) y mantenga un historial de conducción aceptable. Fuente: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"28":{"q":"Según las normas federales aplicadas en Connecticut, ¿durante cuánto tiempo debe un solicitante tener un Permiso de Aprendiz Comercial (CLP) antes de ser elegible para tomar el examen de habilidades (de manejo) de la CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"Un solicitante no puede tomar el examen de habilidades de la CDL durante los 14 días posteriores a la emisión inicial del CLP; el permiso debe conservarse un mínimo de 14 días. Fuente: 49 CFR 383.25(e), aplicado por el Connecticut DMV."},"29":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Connecticut a partir de la fecha de emisión?","options":["90 días","180 días","Un año","Dos años"],"explanation":"Un CLP de Connecticut permanece activo durante un año a partir de la fecha de emisión; si no se obtiene una CDL dentro de ese período, el solicitante debe volver a tomar los exámenes requeridos. Fuente: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"30":{"q":"A partir del 7 de febrero de 2022, ¿quién debe completar la Capacitación para Conductores Principiantes (ELDT) a través de un proveedor registrado ante la FMCSA antes de presentar el examen en Connecticut?","options":["Solo los solicitantes de un endoso de materiales peligrosos (hazmat)","Cualquier persona que renueve una CDL existente","Solicitantes de CDL por primera vez, quienes ascienden de Clase B a Clase A, y solicitantes por primera vez de los endosos H, P o S","Solo conductores menores de 21 años"],"explanation":"Desde el 7 de febrero de 2022, la ELDT se requiere para solicitantes de CDL por primera vez, conductores que ascienden de una Clase B a una Clase A, y solicitantes por primera vez de los endosos H, P o S, con la capacitación impartida por un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA (FMCSA Training Provider Registry). Fuente: FMCSA ELDT rule (49 CFR Part 380); CT DMV CDL pages (portal.ct.gov/dmv)."},"31":{"q":"La Capacitación para Conductores Principiantes (ELDT) de un solicitante de Connecticut debe completarse a través de qué sistema?","options":["El portal de capacitación del DMV de Connecticut","El Registro de Proveedores de Capacitación de la FMCSA (TPR)","El sistema de inscripción de la TSA","El Centro de Información sobre Drogas y Alcohol (Drug and Alcohol Clearinghouse)"],"explanation":"La ELDT debe completarse con un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA (TPR), el cual reporta la finalización del conductor a la FMCSA. Fuente: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov); CT DMV CDL pages."},"32":{"q":"Para el endoso de materiales peligrosos (H), el requisito de ELDT consiste en qué tipo de capacitación?","options":["Solo capacitación teórica","Solo capacitación detrás del volante","Tanto capacitación teórica como detrás del volante","No se requiere ELDT para materiales peligrosos (hazmat)"],"explanation":"El requisito de ELDT para el endoso de materiales peligrosos (H) es solo teórico; no hay un componente detrás del volante, a diferencia de las Clases A/B y los endosos P y S. Fuente: FMCSA ELDT rule (49 CFR Part 380); FMCSA Training Provider Registry."},"33":{"q":"Además de los requisitos de conocimientos y de ELDT, ¿qué evaluación federal adicional debe aprobar un solicitante de Connecticut para recibir el endoso de materiales peligrosos (H)?","options":["Solo un examen físico del DOT","Una Evaluación de Amenazas a la Seguridad de la TSA, que incluye la toma de huellas dactilares","Una verificación de crédito estatal","Un examen únicamente de la vista"],"explanation":"Un endoso de materiales peligrosos requiere aprobar la Evaluación de Amenazas a la Seguridad de la TSA, que incluye una verificación de antecedentes y la toma de huellas dactilares, además del examen de conocimientos y la capacitación teórica de ELDT. Fuente: TSA HazMat Endorsement Threat Assessment Program; CT DMV endorsement pages."},"34":{"q":"¿Qué conjunto de documentos requiere el DMV de Connecticut al solicitar un Permiso de Aprendiz Comercial, en concordancia con REAL ID?","options":["Prueba de identidad, número de Seguro Social, presencia legal en EE. UU. y dos pruebas de residencia en Connecticut","Solo un pasaporte","Un certificado de nacimiento y una factura de servicios","Solo la licencia de conducir actual de Connecticut"],"explanation":"Connecticut requiere documentación REAL ID: prueba de identidad, número de Seguro Social, presencia legal en EE. UU. y dos pruebas de residencia en Connecticut, además de la confirmación de autocertificación y el formulario de solicitud R-229a. Fuente: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"35":{"q":"Un conductor de Connecticut que operará un vehículo comercial tanto dentro como fuera del estado y debe portar una tarjeta médica del DOT debe autocertificarse bajo qué categoría?","options":["Interestatal Exceptuado (EI)","Interestatal No Exceptuado (NI)","Intraestatal Exceptuado (EA)","Intraestatal No Exceptuado (NA)"],"explanation":"La categoría Interestatal No Exceptuado (NI) cubre la conducción dentro y fuera de Connecticut y requiere cumplir con los requisitos del certificado médico federal del DOT. Fuente: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)."},"36":{"q":"¿Qué categoría de autocertificación de Connecticut aplica a un conductor que opera únicamente dentro de Connecticut y no está obligado a cumplir con los requisitos de la tarjeta médica federal del DOT?","options":["Interestatal No Exceptuado (NI)","Intraestatal No Exceptuado (NA)","Intraestatal Exceptuado (EA)","Interestatal Exceptuado (EI)"],"explanation":"La categoría Intraestatal Exceptuado (EA) aplica a conductores que operan únicamente dentro de Connecticut y que están exentos del requisito del certificado médico federal del DOT. Fuente: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)."},"37":{"q":"Antes de procesar una transacción de CDL de Connecticut, el DMV verifica el estatus del solicitante en qué sistema federal?","options":["La base de datos de TSA PreCheck","El Centro de Información sobre Drogas y Alcohol de la FMCSA (Drug and Alcohol Clearinghouse)","Únicamente el Registro Nacional de Conductores (National Driver Register)","El Sistema de Servicio Selectivo"],"explanation":"Los solicitantes de Connecticut deben registrarse en el Centro de Información sobre Drogas y Alcohol de la FMCSA (Drug and Alcohol Clearinghouse), y el DMV verifica el estatus del solicitante en el Clearinghouse antes de procesar la transacción de la CDL. Fuente: CT DMV CDL pages (portal.ct.gov/dmv); FMCSA Drug and Alcohol Clearinghouse."},"38":{"q":"¿Cuál es la edad mínima y qué estatus de ciudadanía/inmigración exige Connecticut para el endoso de materiales peligrosos (H)?","options":["18 años, solo ciudadano estadounidense","21 años, ciudadano estadounidense, residente permanente legal o titular de un Documento de Autorización de Empleo válido","19 años, cualquier residente legal","21 años, solo ciudadano estadounidense"],"explanation":"Connecticut exige que los solicitantes del endoso de materiales peligrosos (H) tengan al menos 21 años y sean ciudadanos estadounidenses, residentes permanentes legales o titulares de un Documento de Autorización de Empleo válido. Fuente: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"39":{"q":"En Connecticut, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.04%","0.08%","0.02%","0.00%"],"explanation":"Connecticut sigue el estándar federal para CMV: es ilegal operar un CMV con un BAC de 0.04% o más (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"40":{"q":"Al operar un CMV en Connecticut, se considera automáticamente que un conductor ha dado su consentimiento para someterse a pruebas químicas de alcohol. ¿Cómo se llama este principio?","options":["Consentimiento implícito","Causa probable","Renuncia expresa","Revisión administrativa"],"explanation":"La ley de consentimiento implícito de Connecticut considera que cualquier operador con licencia ha dado su consentimiento para una prueba de sangre, aliento u orina (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"41":{"q":"Un titular de CDL de Connecticut es declarado culpable de una primera infracción grave, como conducir un CMV con un BAC de 0.04% o más. ¿Por cuánto tiempo queda descalificada la CDL?","options":["Al menos 1 año","Al menos 90 días","Al menos 6 meses","Al menos 3 años"],"explanation":"Una primera infracción grave descalifica la CDL por al menos un año (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"42":{"q":"Según las normas de Connecticut, si una primera infracción grave (como un BAC de 0.04 o la negativa a someterse a una prueba) ocurre mientras el conductor opera un CMV con rótulos (placards) de materiales peligrosos, la descalificación es de al menos:","options":["3 años","1 año","5 años","18 meses"],"explanation":"Una primera infracción grave mientras se opera un CMV con rótulos de materiales peligrosos (HazMat) descalifica la CDL por al menos tres años (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"43":{"q":"¿Cuál es la sanción de descalificación de Connecticut para un conductor declarado culpable de una segunda infracción grave (por ejemplo, una segunda conducción bajo los efectos del alcohol o negativa a una prueba)?","options":["Descalificación de por vida","Descalificación de 10 años","Descalificación de 5 años","Descalificación de 3 años"],"explanation":"Una segunda infracción grave resulta en la descalificación de por vida de la CDL (CT CDL Manual 1.3.2; 49 CFR 383.51)."},"44":{"q":"Un titular de CDL de Connecticut se niega a someterse a una prueba química de alcohol por primera vez. ¿Por cuánto tiempo queda descalificada la CDL por esta negativa?","options":["1 año","6 meses","60 días","3 años"],"explanation":"Negarse a someterse a una prueba química (violación del consentimiento implícito) descalifica la CDL por un año en la primera infracción (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"45":{"q":"Según la ley de consentimiento implícito de Connecticut, si una persona se niega a una prueba química, la licencia de operador regular (no comercial) está sujeta a suspensión por no menos de:","options":["6 meses","30 días","1 año","90 días"],"explanation":"Negarse a una prueba química somete la licencia de operador a una suspensión de no menos de seis meses; si se suspende, la CDL también queda descalificada (CT CDL Manual 1.3.2; CGS Sec. 14-227b)."},"46":{"q":"En Connecticut, un conductor de CMV en quien se detecta una cantidad medible de alcohol por debajo de 0.04% está sujeto a qué acción inmediata?","options":["Puesto fuera de servicio por 24 horas","Descalificado por 60 días","Arrestado por conducir bajo los efectos del alcohol","Multado con $500 sin acción adicional"],"explanation":"Cualquier cantidad detectable de alcohol por debajo de 0.04% resulta en ser puesto fuera de servicio por 24 horas (CT CDL Manual 1.3.2; 49 CFR 392.5)."},"47":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito grave para un titular de CDL de Connecticut?","options":["Exceder en 15 mph o más el límite de velocidad indicado","Una primera conducción bajo los efectos del alcohol en un CMV","No detenerse en un cruce ferroviario","Violar una orden de fuera de servicio"],"explanation":"Las infracciones de tránsito graves incluyen exceso de velocidad (15 mph o más por encima del límite), conducción imprudente y cambios de carril erráticos; la conducción bajo los efectos del alcohol y las violaciones de fuera de servicio (OOS) son categorías aparte (CT CDL Manual 1.3.3)."},"48":{"q":"Un titular de CDL de Connecticut comete dos infracciones de tránsito graves dentro de un período de tres años. La descalificación mínima es:","options":["60 días","30 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves dentro de tres años descalifican la CDL por al menos 60 días (CT CDL Manual 1.3.3; 49 CFR 383.51)."},"49":{"q":"Si un titular de CDL de Connecticut comete tres o más infracciones de tránsito graves dentro de un período de tres años, la descalificación mínima es:","options":["120 días","60 días","180 días","1 año"],"explanation":"Tres o más infracciones de tránsito graves dentro de tres años descalifican la CDL por al menos 120 días (CT CDL Manual 1.3.3; 49 CFR 383.51)."},"50":{"q":"¿Cuál de estas NO está incluida en la lista de infracciones de tránsito graves de Connecticut?","options":["Conducir 8 mph por encima del límite de velocidad indicado","Cambios de carril indebidos o erráticos","Seguir a un vehículo demasiado de cerca","Conducción imprudente"],"explanation":"Las infracciones graves requieren exceder en 15 mph o más el límite; 8 mph por encima no califica, mientras que los cambios de carril erráticos, seguir demasiado de cerca y la conducción imprudente sí (CT CDL Manual 1.3.3)."},"51":{"q":"Un titular de CDL de Connecticut comete una tercera violación de una orden de fuera de servicio dentro de un período de 10 años. La descalificación mínima es:","options":["3 años","1 año","2 años","180 días"],"explanation":"Una tercera violación o subsiguiente de una orden de fuera de servicio dentro de 10 años descalifica la CDL por al menos 3 años (hasta 5) (CT CDL Manual 1.3.4; 49 CFR 383.51)."},"52":{"q":"¿Cuál es la descalificación de Connecticut para la PRIMERA condena de un conductor por una infracción en un cruce a nivel entre vía férrea y carretera mientras opera un CMV?","options":["Al menos 60 días","Al menos 30 días","Al menos 120 días","Al menos 180 días"],"explanation":"Una primera infracción en un cruce a nivel entre vía férrea y carretera descalifica la CDL por al menos 60 días (CT CDL Manual 1.3.5; 49 CFR 383.51)."},"53":{"q":"Por una SEGUNDA infracción en un cruce a nivel entre vía férrea y carretera dentro de tres años, un titular de CDL de Connecticut queda descalificado por al menos:","options":["120 días","60 días","180 días","1 año"],"explanation":"Una segunda infracción en un cruce a nivel dentro de tres años descalifica la CDL por al menos 120 días (CT CDL Manual 1.3.5; 49 CFR 383.51)."},"54":{"q":"Según las normas para CMV de Connecticut y federales, un conductor declarado culpable de dos o más violaciones por sostener/usar un teléfono móvil de mano mientras opera un CMV enfrenta una descalificación de 60 días por la segunda infracción y de cuánto tiempo por tres o más infracciones dentro de tres años?","options":["120 días","60 días","180 días","1 año"],"explanation":"El uso de un teléfono móvil de mano mientras se conduce un CMV conlleva una descalificación de 60 días por una segunda infracción y de 120 días por tres o más dentro de tres años (CT CDL Manual 2.9.4; 49 CFR 383.51)."},"55":{"q":"Después de ser declarado culpable de cualquier infracción de tránsito (que no sea de estacionamiento), ¿dentro de cuántos días debe un titular de CDL de Connecticut notificar a su empleador?","options":["30 días","2 días","10 días","60 días"],"explanation":"Un titular de CDL debe notificar a su empleador dentro de los 30 días posteriores a la condena por cualquier infracción de tránsito, sin importar el vehículo conducido (CT CDL Manual 1.4; 49 CFR 383.31)."},"56":{"q":"Según la ley de cruces ferroviarios de Connecticut, ¿dónde debe detenerse un autobús, un autobús escolar o un vehículo comercial con tanque de carga o materiales peligrosos con rótulo antes de cruzar las vías a nivel?","options":["A no menos de 15 pies ni más de 50 pies del riel más cercano","Exactamente a 25 pies del riel más cercano","A no menos de 10 pies ni más de 40 pies del riel más cercano","A no menos de 50 pies ni más de 100 pies del riel más cercano"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-250, y el Manual de CDL de Connecticut exigen que los autobuses, los vehículos que transportan pasajeros, los vehículos de transporte escolar y los CMV con tanques de carga o materiales peligrosos se detengan a no menos de 15 pies ni más de 50 pies del riel más cercano, y luego miren y escuchen antes de cruzar."},"57":{"q":"Cuando un conductor en Connecticut se aproxima a un vehículo de emergencia detenido con luces intermitentes en una autopista de varios carriles, ¿qué exige la ley estatal de \"Move Over\" (Cámbiese de carril) que haga el conductor?","options":["Reducir la velocidad a un nivel razonable y, si va en el carril adyacente, cambiarse un carril cuando sea seguro","Detenerse por completo hasta que el vehículo de emergencia despeje la escena","Mantener el límite de velocidad indicado pero tocar la bocina","Cambiarse un carril solo si el vehículo de emergencia es una patrulla de policía"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-283b (la ley \"Move Over\"), exigen que los operadores reduzcan de inmediato a una velocidad razonable por debajo del límite y, cuando circulen por el carril adyacente al acotamiento, se cambien un carril a menos que ese movimiento no sea seguro."},"58":{"q":"En una autopista dividida de acceso limitado en Connecticut con tres o más carriles en la misma dirección donde el estado así lo designa, ¿a qué vehículo se le prohíbe circular por el carril del extremo izquierdo?","options":["Un camión registrado comercialmente","Un automóvil de pasajeros con un solo ocupante","Una motocicleta","Una ambulancia respondiendo a una llamada"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-230a, prohíben a los vehículos registrados comercialmente, los autobuses de motor, los vehículos con remolques y los autobuses escolares circular por el carril del extremo izquierdo en autopistas divididas de acceso limitado con tres o más carriles (en la misma dirección) donde la Oficina de Administración de Tránsito Estatal (Office of the State Traffic Administration) así lo designe; la multa es de $88."},"59":{"q":"¿Qué vías en Connecticut prohíben los vehículos comerciales, como los tractocamiones y los camiones de caja?","options":["Las Merritt, Wilbur Cross y Milford Parkways (corredor de la Ruta 15)","La Interestatal 95 y la Interestatal 84","Todas las rutas estatales con número superior a 100","Las autopistas Ruta 9 y Ruta 2"],"explanation":"Las parkways de Connecticut —la Merritt Parkway y la Wilbur Cross Parkway (Ruta 15) y la Milford Parkway— prohíben los vehículos comerciales, los remolques y los vehículos sobredimensionados, en gran parte debido a los pasos elevados históricos de poca altura. CT DOT Parkway Restrictions; la multa por infracción en parkway es de $500 por cada infracción."},"60":{"q":"En una autopista de Connecticut donde los carriles están separados por una isla de seguridad o una barrera física, ¿qué debe hacer un conductor que va por el lado OPUESTO de la barrera cuando un autobús escolar está detenido con las luces rojas intermitentes encendidas?","options":["El conductor puede continuar sin detenerse","El conductor debe detenerse hasta que se apaguen las luces rojas","El conductor debe detenerse solo si el autobús tiene la puerta abierta","El conductor debe reducir a 15 mph pero no necesita detenerse"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-279, establecen que en una autopista con carriles separados por una isla de seguridad o una barrera física, un conductor que va por el lado opuesto de esa barrera puede continuar sin detenerse ante un autobús escolar. Una línea pintada por sí sola NO califica: ambas direcciones deben detenerse."},"61":{"q":"En una vía de Connecticut separada únicamente por una línea central pintada (sin barrera física), ¿qué debe hacer un conductor al encontrarse con un autobús escolar detenido que muestra luces rojas intermitentes en el lado opuesto?","options":["Detenerse, porque una línea pintada no califica para la excepción de autopista dividida","Continuar a velocidad reducida sin detenerse","Continuar sin restricción, ya que se trata de tránsito en sentido contrario","Detenerse solo si hay niños cruzando visiblemente"],"explanation":"Según los Estatutos Generales de Connecticut, Sec. 14-279, la excepción de no detenerse aplica únicamente cuando una isla de seguridad o una barrera física separa los carriles. Con solo una línea pintada, los vehículos de ambos lados deben detenerse por completo ante un autobús escolar con luces rojas intermitentes."},"62":{"q":"¿A qué distancia puede acercarse por el frente un conductor en Connecticut a un autobús escolar detenido con luces rojas intermitentes antes de estar obligado a detenerse?","options":["A no menos de 10 pies del frente del autobús","A no menos de 5 pies del frente del autobús","A no menos de 20 pies del frente del autobús","A no menos de 25 pies del frente del autobús"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-279, exigen que los vehículos se detengan a no menos de 10 pies del frente al aproximarse, y a no menos de 10 pies de la parte trasera al rebasar o seguir a un autobús escolar registrado que muestra luces rojas intermitentes de señalización."},"63":{"q":"Después de detener un CMV averiado en una autopista de un solo sentido o dividida en Connecticut, ¿dónde debe colocar el conductor los tres triángulos reflectantes de advertencia?","options":["A 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima","A 10 pies, 50 pies y 150 pies detrás del vehículo","A 25 pies, 75 pies y 125 pies hacia el tránsito que se aproxima","A 5 pies, 50 pies y 500 pies hacia el tránsito que se aproxima"],"explanation":"El Manual de CDL de Connecticut (que refleja 49 CFR 392.22) indica que en una autopista de un solo sentido o dividida, los dispositivos de advertencia se coloquen a 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima, detrás del vehículo detenido."},"64":{"q":"¿Dentro de cuántos minutos debe un conductor con CDL en Connecticut colocar los dispositivos de advertencia de emergencia después de detener un CMV en la carretera o el acotamiento?","options":["Dentro de 10 minutos","Dentro de 30 minutos","Dentro de 5 minutos","De inmediato, antes de salir de la cabina"],"explanation":"El Manual de CDL de Connecticut establece que si debe detenerse en una carretera o acotamiento, debe encender las luces intermitentes de emergencia (cuatro direccionales) y colocar los dispositivos de advertencia de emergencia dentro de 10 minutos."},"65":{"q":"¿Cuál lista identifica correctamente los vehículos de Connecticut que deben DETENERSE en cada cruce ferroviario a nivel?","options":["Los autobuses que transportan pasajeros, los vehículos de transporte escolar y los CMV con tanques de carga o que transportan materiales peligrosos","Todos los vehículos comerciales de más de 10,000 libras sin importar la carga","Solo los camiones cisterna vacíos y las grúas de remolque","Solo los vehículos que remolcan un remolque"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-250, exigen que el operador de cada CMV que transporta pasajeros, autobús de servicio o vehículo utilizado para transportar niños de escuela, y cada CMV con tanque de carga o que transporta materiales peligrosos, se detenga de 15 a 50 pies del riel más cercano antes de cruzar."},"66":{"q":"¿Cuál es el límite de velocidad máximo indicado al que un CMV puede circular legalmente en una autopista interestatal de Connecticut?","options":["65 mph, el mismo máximo que aplica a los vehículos de pasajeros","55 mph, un límite especial más bajo para todos los camiones en todo el estado","70 mph en las interestatales rurales","60 mph para cualquier vehículo de más de 26,000 libras"],"explanation":"El límite de velocidad máximo indicado en Connecticut es de 65 mph (CGS Sec. 14-219 / 14-218a), y el estado no establece un límite de velocidad para camiones separado y más bajo a nivel estatal: los camiones y los automóviles comparten el mismo máximo de 65 mph donde esté indicado. Los conductores aún deben obedecer cualquier límite indicado más bajo."},"67":{"q":"En una carretera de dos carriles de Connecticut que lleva tránsito en ambas direcciones (sin dividir), ¿dónde debe colocar un conductor de CMV los tres triángulos de advertencia después de detenerse?","options":["A menos de 10 pies del vehículo, y a 100 pies adelante y 100 pies detrás de él","A 10 pies, 100 pies y 200 pies detrás del vehículo únicamente","A 50 pies adelante y 50 pies detrás del vehículo únicamente","A menos de 10 pies adelante y atrás, y a 250 pies en cada dirección"],"explanation":"El Manual de CDL de Connecticut instruye que en una autopista de dos carriles, de doble sentido o sin dividir, se coloque un triángulo a menos de 10 pies del vehículo y uno a 100 pies detrás y otro a 100 pies adelante, sobre el acotamiento o en el carril donde se detuvo."},"68":{"q":"Según la regla de mantenerse a la derecha de Connecticut, ¿dónde debe conducirse un vehículo que se desplaza más lento que la velocidad normal del tránsito?","options":["En el carril de la derecha o lo más cerca posible del borde derecho de la autopista","En cualquier carril, siempre que use las luces intermitentes","En el carril central de una carretera de tres carriles","En el carril izquierdo para mantenerse fuera del tránsito que se incorpora"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-230, exigen que los vehículos se conduzcan por la derecha, y que cualquier vehículo que avance a menos de la velocidad normal del tránsito se conduzca en el carril de la derecha disponible, o lo más cerca posible del bordillo o borde derecho."},"69":{"q":"¿Qué sanción impone Connecticut por operar un vehículo comercial de motor en una parkway estatal donde dichos vehículos están prohibidos?","options":["Una multa de $500 por cada infracción","Solo una advertencia por escrito en la primera infracción","Una multa de $35 más dos puntos","Suspensión obligatoria de la licencia por 30 días"],"explanation":"Connecticut aumentó la sanción por operar un vehículo comercial prohibido en una parkway (Merritt, Wilbur Cross, Milford) a $500 por cada infracción. CT DOT Parkway Restrictions; autoridad de restricción de parkways de CGS Chapter 249 / Sec. 14-298."},"70":{"q":"Además de los vehículos de emergencia, la ley \"Move Over\" de Connecticut también exige que los conductores reduzcan la velocidad y se cambien de carril para cuál de los siguientes que esté detenido en el acotamiento?","options":["Un vehículo no de emergencia que esté detenido en el acotamiento","Solo las patrullas de policía rotuladas","Solo los vehículos con bengalas rojas colocadas","Los peatones que esperan en una parada de autobús"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-283b, se ampliaron para cubrir no solo los vehículos de emergencia (incluidos vehículos de mantenimiento y grúas) con luces intermitentes, sino también cualquier vehículo no de emergencia que esté detenido y ubicado en el acotamiento; los conductores deben reducir la velocidad y cambiarse de carril cuando sea seguro."},"71":{"q":"En Connecticut, ¿cuál es el límite de peso legal por encima del cual un vehículo generalmente requiere un permiso de sobrepeso del DOT?","options":["80,000 libras de peso bruto del vehículo","73,280 libras de peso bruto del vehículo","100,000 libras de peso bruto del vehículo","65,000 libras de peso bruto del vehículo"],"explanation":"Connecticut sigue el máximo legal federal de 80,000 libras de peso bruto del vehículo (sobre cinco ejes). Las cargas que excedan las 80,000 libras requieren un permiso de sobrepeso del CT DOT. Reglamentos de permisos de sobredimensión/sobrepeso del CT DOT."},"72":{"q":"¿Cuál sanción por infracción subsiguiente aplica en Connecticut por rebasar ilegalmente un autobús escolar detenido con luces rojas intermitentes (una segunda infracción o posterior)?","options":["No menos de $500 ni más de $1,000, y/o hasta 30 días de encarcelamiento","Una infracción fija de $90 sin cárcel","Una carta de advertencia y dos puntos en la licencia","Una multa fija de $450, idéntica a la de la primera infracción"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-279, establecen una multa de $450 por una primera infracción de rebasar un autobús escolar detenido, y por cada infracción subsiguiente, no menos de $500 ni más de $1,000, o encarcelamiento de no más de 30 días, o ambos."},"73":{"q":"¿Cuál es la altura máxima legal del vehículo en Connecticut antes de que se requiera un permiso de sobredimensión?","options":["13 pies 6 pulgadas","12 pies 0 pulgadas","14 pies 6 pulgadas","13 pies 0 pulgadas"],"explanation":"Los máximos dimensionales legales de Connecticut son 8 pies 6 pulgadas de ancho y 13 pies 6 pulgadas de alto (con una longitud de semirremolque de 53 pies). Exceder los 13 pies 6 pulgadas de altura requiere un permiso de sobredimensión del CT DOT. Reglamentos de permisos de sobredimensión/sobrepeso del CT DOT."},"74":{"q":"Un conductor con CDL se aproxima a un cruce ferroviario en Connecticut transportando un tanque de carga VACÍO que se usó por última vez para materiales peligrosos. ¿Qué debe hacer el conductor?","options":["Detenerse de 15 a 50 pies del riel más cercano, porque la regla aplica a los tanques de carga, ya sea que estén cargados o vacíos","Continuar sin detenerse, ya que el tanque está vacío","Detenerse solo si hay un tren visible","Reducir a 5 mph pero continuar a través del cruce sin una parada completa"],"explanation":"Los Estatutos Generales de Connecticut, Sec. 14-250, y el Manual de CDL de Connecticut exigen que los vehículos con tanques de carga usados para materiales peligrosos se detengan de 15 a 50 pies del riel más cercano, ya sea que el tanque esté cargado O vacío, y que crucen solo cuando se puedan despejar las vías sin detenerse."},"75":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Connecticut?","options":["El Departamento de Vehículos Motorizados de Connecticut (Connecticut DMV)","El Departamento de Transporte de Connecticut (CTDOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","La Policía Estatal de Connecticut, División de Seguridad de Vehículos Comerciales"],"explanation":"En Connecticut, el Departamento de Vehículos Motorizados (DMV) emite las CDL y administra las pruebas de conocimientos y de habilidades. El CTDOT gestiona los permisos de sobredimensión/sobrepeso y la FMCSA establece las normas federales, pero la licencia en sí es una credencial del DMV estatal. Fuente: CT DMV, 'Get a commercial driver's license' (portal.ct.gov/dmv)."},"76":{"q":"En Connecticut, ¿cuál es la edad mínima para obtener una CDL para operación intraestatal (solo dentro del estado)?","options":["18 años","16 años","21 años","25 años"],"explanation":"Connecticut exige que un conductor tenga al menos 18 años para operar un CMV intraestatalmente (solo dentro de Connecticut). Un conductor debe tener al menos 21 años para conducir interestatalmente o para transportar materiales peligrosos. Fuente: CT DMV, 'Get a commercial driver's license' / 'Get a commercial learner's permit.'"},"77":{"q":"En Connecticut, ¿cuál es la edad mínima para operar un vehículo comercial de motor en el comercio interestatal o para transportar materiales peligrosos?","options":["21 años","18 años","19 años","23 años"],"explanation":"Connecticut, siguiendo la norma federal, exige que un conductor tenga al menos 21 años para conducir un CMV a través de las fronteras estatales (interestatal) o para transportar cantidades de materiales peligrosos que requieran rótulo. Los conductores de 18 a 20 años están limitados a la operación intraestatal. Fuente: páginas de CLP/CDL del CT DMV; 49 CFR 391.11."},"78":{"q":"Antes de que un nuevo solicitante pueda tomar la prueba de habilidades de CDL para una licencia Clase A o Clase B en Connecticut, ¿qué capacitación debe haberse completado?","options":["La Capacitación para Conductores de Nivel Inicial (ELDT) —teoría más práctica al volante— de un proveedor registrado ante la FMCSA","Únicamente un programa de escuela de oficios aprobado por el estado de 160 horas","Un curso de manejo defensivo aprobado por el Connecticut DMV","Un curso en línea de ocho horas de concientización sobre materiales peligrosos"],"explanation":"A partir del 7 de febrero de 2022, un solicitante de nivel inicial debe completar la Capacitación obligatoria para Conductores de Nivel Inicial (ELDT) —tanto la teoría (conocimientos) como la práctica al volante (BTW)— a través de un proveedor que figure en el Registro de Proveedores de Capacitación de la FMCSA antes de tomar la prueba de habilidades de Clase A/B (y antes de las pruebas de endoso P, S o H, según corresponda). Fuente: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR Part 380 Subpart F."},"79":{"q":"Un solicitante debe completar la Capacitación para Conductores de Nivel Inicial antes de tomar la prueba de conocimientos para cuál de estos endosos en Connecticut?","options":["El endoso de Materiales Peligrosos (H)","El endoso de Vehículo Cisterna (N)","El endoso de Remolques Dobles/Triples (T)","Únicamente la clase de Combinación (sin letra de endoso)"],"explanation":"La ELDT debe completarse antes de la prueba de CONOCIMIENTOS del endoso de Materiales Peligrosos (H) (el H no tiene prueba de habilidades). La ELDT también se requiere antes de las pruebas de habilidades para los endosos de Pasajeros (P) y Autobús Escolar (S). Los endosos N y T no están sujetos a la ELDT. Fuente: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR 380.609."},"80":{"q":"¿Qué documento debe obtener PRIMERO un nuevo solicitante de CDL en el proceso de licenciamiento de Connecticut, antes de la CDL completa?","options":["Un Permiso de Aprendiz Comercial (CLP)","Una exención del examen físico del DOT por parte del DMV","Una autoridad operativa de autotransportista (número MC)","Un certificado temporal de transporte interestatal"],"explanation":"El proceso comienza con aprobar las pruebas de conocimientos requeridas para obtener un Permiso de Aprendiz Comercial (CLP). Luego, el solicitante practica, completa la ELDT y toma la prueba de habilidades para convertir el CLP en una CDL. Fuente: CT DMV, 'Get a commercial learner's permit' y 'Get a commercial driver's license.'"},"81":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Connecticut a partir de su fecha de emisión?","options":["Un año","60 días","Seis meses","Dos años"],"explanation":"Un CLP de Connecticut es válido por un año a partir de la fecha de emisión. Si el titular no obtiene la CDL dentro de ese año, deben volver a tomarse todas las pruebas requeridas para obtener un nuevo permiso. Fuente: CT DMV, 'Get a commercial learner's permit.'"},"82":{"q":"En Connecticut, ¿por cuánto tiempo debe un solicitante tener el CLP antes de ser elegible para tomar la prueba de habilidades de CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 10 días","Al menos 60 días"],"explanation":"Un solicitante debe tener el CLP por un mínimo de 14 días antes de tomar la prueba de habilidades de CDL. Este período de espera mínimo federal se aplica en Connecticut. Fuente: CT DMV, 'Get a commercial learner's permit'; 49 CFR 383.25(a)(3)."},"83":{"q":"La prueba de conocimientos generales de CDL de Connecticut consta de 50 preguntas. ¿Cuántas deben responderse correctamente para aprobar?","options":["40 correctas (80%)","35 correctas (70%)","45 correctas (90%)","30 correctas (60%)"],"explanation":"La prueba de conocimientos generales de Connecticut tiene 50 preguntas de opción múltiple y requiere 40 respuestas correctas (80%) para aprobar. Fuente: CT DMV, 'Get a commercial learner's permit.'"},"84":{"q":"¿De cuántas partes separadas se compone la prueba de habilidades de CDL de Connecticut?","options":["Tres partes","Dos partes","Cuatro partes","Cinco partes"],"explanation":"La prueba de habilidades de CDL tiene tres partes: la inspección del vehículo previa al viaje, la prueba de habilidades básicas de control del vehículo y la prueba de manejo en carretera. Las tres deben aprobarse para obtener la CDL. Fuente: pruebas de CDL del CT DMV; 49 CFR 383.113."},"85":{"q":"¿Cuál de las siguientes es una de las tres partes requeridas de la prueba de habilidades de CDL de Connecticut?","options":["La inspección del vehículo previa al viaje","La prueba de conocimientos generales de 50 preguntas","El examen físico del DOT","La prueba escrita de endoso de frenos de aire"],"explanation":"Las tres partes de la prueba de habilidades son la inspección del vehículo previa al viaje, el control básico del vehículo y el manejo en carretera. Las pruebas de conocimientos generales y de frenos de aire son pruebas ESCRITAS de conocimientos (que se toman para el CLP), y el examen físico del DOT es un examen médico: ninguna de estas es parte de la prueba de habilidades. Fuente: CT DMV; 49 CFR 383.113."},"86":{"q":"Durante la prueba de manejo de CDL de Connecticut, la parte en la que el solicitante demuestra maniobras como un retroceso en línea recta o un retroceso desplazado en un área controlada se llama:","options":["La prueba de habilidades básicas de control del vehículo","La prueba de inspección previa al viaje","La prueba de manejo en carretera","La prueba de vehículo de combinación"],"explanation":"Las maniobras de retroceso y posicionamiento realizadas fuera de las vías públicas son parte de la prueba de habilidades básicas de control del vehículo, el segundo de los tres componentes de la prueba de habilidades. La previa al viaje es la inspección, y la prueba en carretera se realiza en el tránsito. Fuente: CT DMV; 49 CFR 383.113(b)."},"87":{"q":"Si un solicitante de CDL de Connecticut no toma o no aprueba la prueba de conocimientos de frenos de aire, ¿qué le sucede a la licencia?","options":["Se coloca una restricción 'L', que prohíbe la operación de cualquier CMV equipado con frenos de aire","Se le niega por completo una CDL al solicitante hasta que apruebe lo de frenos de aire","Se agrega una restricción 'K' que limita al conductor a la operación intraestatal","Nada: los frenos de aire son opcionales y no dejan ninguna restricción"],"explanation":"Un conductor que no apruebe la prueba de conocimientos de frenos de aire (y las verificaciones de habilidades relacionadas) recibe una restricción 'L', que prohíbe operar cualquier CMV equipado con frenos de aire. Fuente: información de CLP/CDL del CT DMV; 49 CFR 383.95."},"88":{"q":"Las reglas federales de CDL aplicadas en Connecticut exigen que cada titular de CDL/CLP se 'autocertifique'. ¿Cuántas categorías de tipo de manejo de autocertificación define el marco federal?","options":["Cuatro","Dos","Tres","Seis"],"explanation":"El marco federal de autocertificación define cuatro categorías: Interestatal No Exceptuado (NI), Interestatal Exceptuado (EI), Intraestatal No Exceptuado (NA) e Intraestatal Exceptuado (EA). La autocertificación en línea de Connecticut presenta en la práctica las dos opciones no exceptuadas que la mayoría de los conductores usan (NI y NA). Fuente: 49 CFR 383.71(b); autocertificación del CT DMV."},"89":{"q":"Un conductor de Connecticut que se autocertifica como 'Interestatal No Exceptuado' (NI) está haciendo cuál afirmación sobre su operación y su estado médico?","options":["Opera a través de las fronteras estatales y debe cumplir con el requisito federal del certificado médico del DOT","Opera solo dentro de Connecticut y está exento de los requisitos médicos del DOT","Opera a través de las fronteras estatales pero está exento de cualquier certificado médico","Opera solo dentro de Connecticut y debe portar un permiso de materiales peligrosos"],"explanation":"Interestatal No Exceptuado (NI) significa que el conductor opera un CMV en el comercio interestatal (dentro y fuera de Connecticut) y está sujeto a los requisitos federales de certificación médica del DOT y debe cumplirlos. Fuente: autocertificación del CT DMV; 49 CFR 383.71(b)."},"90":{"q":"Un conductor de Connecticut que se autocertifica como 'Intraestatal No Exceptuado' (NA) está certificando que:","options":["Operará un vehículo comercial de motor solo dentro de los límites de Connecticut","Operará a través de las fronteras estatales bajo una exención médica federal","Operará a nivel nacional sin ninguna certificación médica","Operará solo equipo agrícola exento de las reglas de CDL"],"explanation":"Intraestatal No Exceptuado (NA) certifica la operación de un CMV solo dentro de Connecticut. Dichos conductores pueden portar una restricción 'K' que los limita al manejo intraestatal y deben cumplir con las normas médicas/de calificación de conductor de Connecticut. Fuente: autocertificación del CT DMV (dmvselfservice.ct.gov)."},"91":{"q":"¿Cómo completa un titular de CDL/CLP el paso de autocertificación con el Connecticut DMV?","options":["Lo presenta a través del sistema de autoservicio en línea del DMV y lleva la confirmación impresa del correo electrónico al DMV","Hace que el examinador médico envíe por correo una certificación en papel a la sede de la FMCSA","Se autocertifica solo al momento de la prueba de manejo, verbalmente ante el examinador","Presenta la certificación ante el Departamento de Trabajo de Connecticut"],"explanation":"El conductor se autocertifica en línea a través del portal de autoservicio del Connecticut DMV (dmvselfservice.ct.gov), recibe una confirmación por correo electrónico y lleva esa confirmación impresa al DMV al solicitar, renovar, actualizar o cambiar el tipo de manejo. Fuente: autocertificación del CT DMV."},"92":{"q":"¿Qué formulario debe usar un examinador médico certificado para documentar el examen físico del DOT de un titular de CDL de Connecticut, y cómo llega al DMV?","options":["El Formulario MCSA-5876, cargado por el examinador a través del National Registry y enviado al DMV electrónicamente","El Formulario R-229a, enviado por correo por el solicitante al DMV dentro de 30 días","El Formulario MCSA-5876, llevado en mano por el conductor y escaneado en cualquier sucursal del DMV","Una nota manuscrita del médico, enviada por fax por el solicitante a la FMCSA"],"explanation":"El examen médico del DOT debe registrarse en el Formulario MCSA-5876 (Certificado del Examinador Médico) por un examinador que figure en el Registro Nacional de Examinadores Médicos Certificados (National Registry of Certified Medical Examiners); el examinador carga los resultados a través del National Registry, y estos se transmiten al Connecticut DMV electrónicamente. Fuente: CT DMV, 'Getting medical certification for CDL.'"},"93":{"q":"¿Qué le sucede a una CDL de Connecticut si el titular no mantiene un certificado médico del DOT válido archivado en el DMV?","options":["Después de un aviso de degradación, la licencia se degrada a una licencia no comercial Clase D","La CDL se revoca permanentemente y no puede reinstaurarse","Se evalúa automáticamente una sanción civil federal de $500 cada mes","Nada cambia hasta que llega la fecha de renovación regular"],"explanation":"Si no se mantiene un certificado médico válido, el estado médico del conductor pasa a ser 'No Certificado'; el DMV envía un aviso de degradación, y si no se recibe electrónicamente un nuevo certificado válido para la fecha indicada, la CDL se degrada a una licencia Clase D (no comercial). Fuente: CT DMV, 'Getting medical certification for CDL.'"},"94":{"q":"¿Con qué frecuencia debe renovarse una Licencia de Conducir Comercial de Connecticut?","options":["Cada cuatro años","Cada seis años","Cada dos años","Cada ocho años"],"explanation":"Una CDL de Connecticut se emite en un ciclo de renovación de cuatro años (renovándose alrededor del cumpleaños del titular), más corto que el plazo estándar de una licencia no comercial. Fuente: CT DMV, 'Renew a CDL (commercial) license'; Conn. Gen. Stat. § 14-44h."}},"hi":{"0":{"q":"कनेक्टिकट कानून के तहत, बिना किसी विशेष परमिट के कनेक्टिकट के राजमार्गों पर चलने की अनुमति वाले एक वाणिज्यिक वाहन की अधिकतम चौड़ाई क्या है (दर्पण जैसे सुरक्षा उपकरणों को छोड़कर)?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"कनेक्टिकट जनरल स्टैच्यूट्स Sec. 14-262 अधिकतम कानूनी वाहन चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है, जिसमें दर्पण जैसे सुरक्षा उपकरण शामिल नहीं हैं। CTDOT वाहन आकार और वजन सीमाएँ शीट चौड़ाई 102.37 inches सूचीबद्ध करती है। स्रोत: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations।"},"1":{"q":"कनेक्टिकट में, परिवहन आयुक्त (Commissioner of Transportation) से विशेष ऊँचाई परमिट की आवश्यकता पड़ने से पहले, भार सहित किसी वाहन की अधिकतम ऊँचाई कितनी हो सकती है?","options":["12 feet 6 inches","13 feet 0 inches","13 feet 6 inches","14 feet 0 inches"],"explanation":"कनेक्टिकट जनरल स्टैच्यूट्स Sec. 14-264 ऐसे वाहन के संचालन पर रोक लगाता है जिसकी ऊँचाई उसके भार सहित 13 feet 6 inches से अधिक हो, बिना विशेष लिखित परमिट के (खुली घास या भूसे के भार को छोड़कर)। स्रोत: CGS Sec. 14-264; CTDOT Vehicle Size and Weight Limitations।"},"2":{"q":"कनेक्टिकट में, बिना परमिट के चलने वाले एकल-इकाई (सीधे) ट्रक की भार सहित अधिकतम लंबाई कितनी है?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"कनेक्टिकट जनरल स्टैच्यूट्स Sec. 14-262 एकल-इकाई वाहन की भार सहित अधिकतम लंबाई 45 feet तक सीमित करता है। स्रोत: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations (\"Single unit vehicle 45 feet\")।"},"3":{"q":"सामान्य (गैर-प्रतिबंधित) कनेक्टिकट राजमार्गों पर एकल सेमीट्रेलर खींचने वाले ट्रैक्टर के लिए, सेमीट्रेलर की अधिकतम कानूनी लंबाई कितनी है?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"सामान्य राजमार्गों पर कनेक्टिकट एक ट्रैक्टर और 48-foot सेमीट्रेलर संयोजन की अनुमति बिना किसी कुल लंबाई सीमा के देता है, लेकिन ट्रेलर स्वयं 48 feet तक सीमित है। स्रोत: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations।"},"4":{"q":"कनेक्टिकट की निर्दिष्ट (प्रतिबंधित) राजमार्ग प्रणाली पर, 53-foot सेमीट्रेलर की अनुमति बशर्ते किंगपिन से सबसे पीछे के एक्सल के केंद्र तक की दूरी किस आँकड़े से अधिक न हो?","options":["41 feet","43 feet","45 feet","48 feet"],"explanation":"निर्दिष्ट राजमार्ग प्रणाली पर कनेक्टिकट एक ट्रैक्टर और 53-foot सेमीट्रेलर की अनुमति बिना किसी कुल लंबाई सीमा के देता है, लेकिन किंगपिन-से-सबसे-पीछे-के-एक्सल-के-केंद्र तक की दूरी 43 feet से अधिक नहीं होनी चाहिए। स्रोत: CGS Sec. 14-262; CTDOT Vehicle Size and Weight Limitations।"},"5":{"q":"कनेक्टिकट की निर्दिष्ट राजमार्ग प्रणाली पर, जुड़वाँ (डबल) ट्रेलर खींचने वाले ट्रैक्टर का प्रत्येक ट्रेलर अधिकतम कितनी लंबाई तक का हो सकता है?","options":["27 feet","28 feet","33 feet","40 feet"],"explanation":"निर्दिष्ट राजमार्ग प्रणाली पर, कनेक्टिकट एक ट्रैक्टर और जुड़वाँ ट्रेलर संयोजन की अनुमति बिना किसी कुल लंबाई सीमा के देता है, लेकिन प्रत्येक ट्रेलर 28 feet तक सीमित है। स्रोत: CTDOT Vehicle Size and Weight Limitations (Restricted to the Designated Highway System)।"},"6":{"q":"ब्रिज-फॉर्मूला आवश्यकताओं के पूरा होने पर, बिना ओवरवेट परमिट के एक 5-एक्सल संयोजन कनेक्टिकट के राजमार्गों पर अधिकतम कितना कुल वाहन वजन ले जा सकता है?","options":["73,000 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"कनेक्टिकट का अधिकतम व्यावहारिक वजन 5 एक्सल पर 80,000 pounds है, जिसमें पहले और अंतिम एक्सल के बीच 51 feet हो, जो तब अनुमत है जब Federal Bridge Formula की आवश्यकताएँ पूरी होती हैं। स्रोत: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a।"},"7":{"q":"कनेक्टिकट में, जब एक एकल एक्सल आसन्न एक्सलों से 6 feet या उससे अधिक की दूरी पर हो, तो उस पर अधिकतम कितना वजन अनुमत है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"कनेक्टिकट प्रति एक्सल 22,400 pounds की अनुमति देता है जब एक्सल 6 feet या उससे अधिक की दूरी पर हों; 6 feet से कम दूरी पर रखे गए एक्सल प्रति एक्सल 18,000 pounds तक सीमित हैं। स्रोत: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a।"},"8":{"q":"कनेक्टिकट वजन नियमों के तहत, जब कोई एक्सल किसी आसन्न एक्सल से 6 feet से कम दूरी पर हो, तो उस किसी भी एकल एक्सल पर अधिकतम कितना वजन अनुमत है?","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"explanation":"कनेक्टिकट 6 feet से कम दूरी पर रखे गए एक्सलों को प्रति एक्सल 18,000 pounds तक सीमित करता है; केवल 6 feet या उससे अधिक की दूरी पर ही 22,400 pounds की अनुमति है। स्रोत: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a।"},"9":{"q":"जब किसी कनेक्टिकट संयोजन वाहन का कुल वजन 73,000 pounds से अधिक हो (80,000 pounds तक), तो कौन-सी अतिरिक्त आवश्यकता पूरी होनी चाहिए?","options":["वाहन को केवल ठोस रबर के टायरों का उपयोग करना चाहिए","सभी Federal Bridge Formula आवश्यकताएँ पूरी होनी चाहिए","वाहन को केवल रात में ही यात्रा करनी चाहिए","वाहन के साथ एक पुलिस एस्कॉर्ट होना चाहिए"],"explanation":"CTDOT के अनुसार, अधिकतम 80,000 pounds का कुल वजन केवल तभी अनुमत है जब 73,000 pounds से अधिक वजन के लिए Federal Bridge Formula की सभी आवश्यकताएँ पूरी हों। स्रोत: CTDOT Vehicle Size and Weight Limitations (Gross Vehicle Weights Over 73,000 pounds)।"},"10":{"q":"कनेक्टिकट में, किसी भी वाहन के टायरों द्वारा सड़क पर डाला जाने वाला अधिकतम अनुमत वजन टायर की चौड़ाई पर आधारित होता है। वह सीमा क्या है?","options":["500 pounds per inch of tire width","600 pounds per inch of tire width","700 pounds per inch of tire width","800 pounds per inch of tire width"],"explanation":"कनेक्टिकट टायर भार को 600 pounds per inch of tire width (अधिकतम) तक सीमित करता है। स्रोत: CTDOT Vehicle Size and Weight Limitations (Tires - Load per inch width of tire 600 pounds maximum)।"},"11":{"q":"कनेक्टिकट में एक 2-एक्सल सीधे ट्रक के लिए अधिकतम कितना कुल वजन अनुमत है, जब किसी भी एक्सल का वजन 18,000 pounds से अधिक न हो?","options":["32,000 pounds","36,000 pounds","40,000 pounds","53,800 pounds"],"explanation":"कनेक्टिकट एक 2-एक्सल वाहन को 36,000 pounds तक की अनुमति देता है जब एक्सल का वजन 18,000 pounds से अधिक न हो (उस एक्सल शर्त के बिना आँकड़ा 32,000 pounds है)। स्रोत: CTDOT Commercial Vehicle Limits in Connecticut; CGS Sec. 14-267a।"},"12":{"q":"कनेक्टिकट में एक ट्रैक्टर-सेमीट्रेलर संयोजन के लिए, जब संयोजन में 3 एक्सल हों, तो अधिकतम कितना कुल वजन अनुमत है?","options":["53,800 pounds","58,400 pounds","67,400 pounds","73,000 pounds"],"explanation":"कनेक्टिकट एक 3-एक्सल ट्रैक्टर-सेमीट्रेलर संयोजन को अधिकतम 58,400 pounds निर्धारित करता है; एक 4-एक्सल संयोजन 67,400 pounds और 5-या-अधिक एक्सल 73,000 pounds तक होते हैं। स्रोत: CTDOT Vehicle Size and Weight Limitations (Tractor Semitrailer)।"},"13":{"q":"वह संघीय वजन मानक जिसे कनेक्टिकट लगातार एक्सलों के समूह पर अनुमत अधिकतम कुल वजन निर्धारित करने के लिए लागू करता है, उसे किस नाम से जाना जाता है:","options":["Federal Axle Spread Rule","Federal Bridge Formula","Federal Gross Combination Standard","Federal Tandem Weight Table"],"explanation":"कनेक्टिकट एक्सल समूहों पर अनुमेय वजन निर्धारित करने के लिए Federal Bridge Formula लागू करता है; 73,000 pounds से अधिक और 80,000 pounds तक के कुल वजन के लिए इसे पूरा करना आवश्यक है। स्रोत: CTDOT Vehicle Size and Weight Limitations; CGS Sec. 14-267a।"},"14":{"q":"कनेक्टिकट में, ओवरसाइज़/ओवरवेट (गैर-अनुरूप वाहन) परमिट कौन जारी करता है, और किस प्रणाली के माध्यम से आवेदन प्रस्तुत किए जाते हैं?","options":["परिवहन आयुक्त (Commissioner of Transportation), DMV द्वारा प्रबंधित Commercial Vehicle Operations (CVO) WebPortal के माध्यम से","वाहन जिस प्रत्येक कस्बे से गुजरता है, उसका स्थानीय पुलिस विभाग","Federal Motor Carrier Safety Administration ऑनलाइन पोर्टल","Department of Energy and Environmental Protection, कागज़ी आवेदन द्वारा"],"explanation":"CGS Sec. 14-270 के तहत, परिवहन आयुक्त (Commissioner of Transportation) गैर-अनुरूप (ओवरसाइज़/ओवरवेट) वाहनों के लिए विशेष परमिट जारी करता है; आवेदन CT DMV द्वारा प्रबंधित Connecticut Commercial Vehicle Operations (CVO) WebPortal के माध्यम से संसाधित किए जाते हैं। स्रोत: CGS Sec. 14-270; CTDOT Oversize/Overweight Permit FAQ।"},"15":{"q":"एक मानक कनेक्टिकट सिंगल-ट्रिप ओवरसाइज़/ओवरवेट परमिट आमतौर पर किस अवधि के लिए वैध होता है, और यात्रा किन घंटों तक प्रतिबंधित होती है?","options":["30 days; दिन या रात किसी भी समय","3 days; केवल दिन के उजाले के घंटे","7 days; केवल रात में","1 day; व्यस्त घंटों को छोड़कर"],"explanation":"CTDOT 3-day अवधि के लिए वैध सिंगल-ट्रिप ओवरसाइज़/ओवरवेट परमिट जारी करता है, जिसमें यात्रा दिन के उजाले के घंटों तक सीमित होती है (आमतौर पर सूर्योदय के आधे घंटे बाद से सूर्यास्त के आधे घंटे पहले तक)। स्रोत: CTDOT Vehicle Size and Weight Limitations; CTDOT Oversize/Overweight Permit FAQ।"},"16":{"q":"कनेक्टिकट कानून (CGS Sec. 14-267a) के तहत, अतिरिक्त वजन की मात्रा के आधार पर, एक ओवरवेट वाणिज्यिक वाहन के संचालन के लिए जुर्माना क्या है?","options":["$1 per 100 pounds of excess weight","$3 per 100 pounds (or fraction thereof) of excess weight","$10 per 100 pounds of excess weight","अतिरिक्त वजन की परवाह किए बिना एक निश्चित $500"],"explanation":"कनेक्टिकट जनरल स्टैच्यूट्स Sec. 14-267a ओवरवेट जुर्माना अतिरिक्त वजन के प्रति एक सौ पाउंड, या उसके अंश, के लिए तीन डॉलर निर्धारित करता है। स्रोत: CGS Sec. 14-267a।"},"17":{"q":"कनेक्टिकट कुछ कृषि ढुलाई के लिए एक विशेष वजन भत्ता प्रदान करता है। एक थोक दूध पिकअप टैंकर या कृषि वस्तुओं की ढुलाई करने वाले वाहन (जहाँ संघीय कानून अनुमति देता है) के लिए अधिकतम कितना कुल वाहन वजन अनुमत है?","options":["80,000 pounds","88,000 pounds","100,000 pounds","120,000 pounds"],"explanation":"कनेक्टिकट जनरल स्टैच्यूट्स Sec. 14-267a थोक दूध पिकअप टैंकरों और कृषि वस्तुओं (चारा, बीज, उर्वरक और कृषि उत्पादों) की ढुलाई करने वाले वाहनों के लिए 100,000 pounds तक का अनुमेय कुल वजन निर्धारित करता है, जहाँ संघीय कानून अनुमति देता है। स्रोत: CGS Sec. 14-267a।"},"18":{"q":"CGS Sec. 14-267a के तहत, टैंडम एक्सलों के दो लगातार सेटों वाले वाहन के लिए, उन टैंडमों पर 68,000 pounds का कुल भार केवल तभी अनुमत है जब दोनों सेटों के पहले और अंतिम एक्सल के बीच की दूरी कम से कम हो:","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"कनेक्टिकट जनरल स्टैच्यूट्स Sec. 14-267a टैंडम एक्सलों के दो लगातार सेटों को कुल 68,000 pounds ले जाने की अनुमति देता है बशर्ते उन लगातार टैंडम सेटों के पहले और अंतिम एक्सल के बीच की कुल दूरी 36 feet या उससे अधिक हो। स्रोत: CGS Sec. 14-267a।"},"19":{"q":"कनेक्टिकट में, वह न्यूनतम Gross Vehicle Weight Rating (GVWR) क्या है जो किसी एकल वाहन को Class B CDL श्रेणी में रखती है?","options":["16,001 pounds or more","26,001 pounds or more","10,001 pounds or more","33,001 pounds or more"],"explanation":"एक कनेक्टिकट Class B CDL किसी भी ऐसे एकल वाहन को चलाने का अधिकार देता है जिसका GVWR 26,001 pounds या उससे अधिक हो, और किसी भी ऐसे वाहन को जो 10,000 pounds से अधिक की इकाई न खींच रहा हो। स्रोत: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)।"},"20":{"q":"कनेक्टिकट नियमों के तहत, 26,001 pounds या उससे अधिक GVWR वाले वाहनों के संयोजन को चलाने के लिए Class A CDL आवश्यक है बशर्ते खींची गई इकाई का GVWR किस आँकड़े से अधिक हो?","options":["5,000 pounds","26,001 pounds","10,000 pounds","15,000 pounds"],"explanation":"एक कनेक्टिकट Class A CDL 26,001 pounds या उससे अधिक GVWR वाले संयोजनों को कवर करता है जहाँ खींचे गए वाहन का GVWR 10,000 pounds से अधिक हो। स्रोत: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)।"},"21":{"q":"एक कनेक्टिकट चालक 26,001 pounds GVWR से कम का एकल वाहन चलाता है जो चालक सहित 20 यात्रियों को ले जाने के लिए डिज़ाइन किया गया है। कौन-सी CDL श्रेणी लागू होती है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं है"],"explanation":"एक कनेक्टिकट Class C CDL 26,001 pounds GVWR से कम के एकल वाहन (या 10,000 pounds से अधिक न खींचने वाली इकाई) को कवर करता है जो चालक सहित 16 या उससे अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है, या जो प्लाकार्डेड खतरनाक सामग्री ले जाता है। स्रोत: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)।"},"22":{"q":"इंट्रास्टेट (केवल कनेक्टिकट के भीतर) संचालन तक सीमित कनेक्टिकट CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16","18","19","21"],"explanation":"कनेक्टिकट के लिए आवश्यक है कि इंट्रास्टेट CDL (केवल कनेक्टिकट के भीतर संचालन) के लिए आवेदक की आयु कम से कम 18 वर्ष हो। स्रोत: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)।"},"23":{"q":"कनेक्टिकट CDL पर अंतरराज्यीय वाणिज्य में एक वाणिज्यिक मोटर वाहन के संचालन के लिए आवश्यक न्यूनतम आयु क्या है?","options":["18","19","20","21"],"explanation":"कनेक्टिकट के लिए आवश्यक है कि अंतरराज्यीय संचालन (कनेक्टिकट के भीतर और बाहर) के लिए आवेदक की आयु कम से कम 21 वर्ष हो। स्रोत: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)।"},"24":{"q":"ऐसे वाहन को चलाने के लिए कनेक्टिकट किस एंडोर्समेंट की आवश्यकता रखता है जो प्लाकार्ड की आवश्यकता वाली मात्रा में खतरनाक सामग्री का परिवहन करता है?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"कनेक्टिकट प्लाकार्डेड खतरनाक सामग्री का परिवहन करने वाले वाहन के संचालन के लिए H (Hazardous Materials) एंडोर्समेंट की आवश्यकता रखता है। स्रोत: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)।"},"25":{"q":"कनेक्टिकट में, N (टैंक/तरल थोक) एंडोर्समेंट किस न्यूनतम क्षमता वाले स्थायी रूप से लगे कार्गो टैंक के लिए आवश्यक है?","options":["100 gallons or more","119 gallons or more","500 gallons or more","1,000 gallons or more"],"explanation":"कनेक्टिकट N एंडोर्समेंट की आवश्यकता ऐसे वाहन के लिए रखता है जो 119 gallons या उससे अधिक रेटेड स्थायी रूप से लगे कार्गो टैंक में तरल या तरल गैस की ढुलाई के लिए डिज़ाइन किया गया हो (या 1,000 gallons या उससे अधिक रेटेड पोर्टेबल टैंक)। स्रोत: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)।"},"26":{"q":"Class A CDL की आवश्यकता वाले वाहन के साथ एक से अधिक ट्रेलर खींचने के लिए कौन-सा कनेक्टिकट एंडोर्समेंट आवश्यक है?","options":["P endorsement","N endorsement","T endorsement","S endorsement"],"explanation":"कनेक्टिकट T (Doubles/Triples) एंडोर्समेंट की आवश्यकता रखता है जब एक Class A CDL वाहन एक से अधिक ट्रेलर खींचता है। स्रोत: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)।"},"27":{"q":"एक कनेक्टिकट चालक को S (स्कूल बस) एंडोर्समेंट जारी किए जाने से पहले, चालक के पास कौन-सा अन्य एंडोर्समेंट भी होना चाहिए?","options":["H (Hazardous Materials)","N (Tank)","P (Passenger)","T (Doubles/Triples)"],"explanation":"कनेक्टिकट में स्कूल बस (S) एंडोर्समेंट के लिए धारक के पास Passenger (P) एंडोर्समेंट होना और एक स्वीकार्य ड्राइविंग रिकॉर्ड बनाए रखना भी आवश्यक है। स्रोत: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)।"},"28":{"q":"कनेक्टिकट में लागू संघीय नियमों के तहत, CDL स्किल्स (रोड) टेस्ट देने के लिए पात्र होने से पहले आवेदक को कितने समय तक Commercial Learner Permit (CLP) रखना होगा?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"explanation":"एक आवेदक CLP के प्रारंभिक जारी होने के बाद 14 दिनों के दौरान CDL स्किल्स टेस्ट नहीं दे सकता; परमिट कम से कम 14 दिन तक रखा जाना चाहिए। स्रोत: 49 CFR 383.25(e), Connecticut DMV द्वारा लागू।"},"29":{"q":"एक कनेक्टिकट Commercial Learner Permit (CLP) जारी होने की तारीख से कितने समय तक वैध रहता है?","options":["90 days","180 days","एक वर्ष","दो वर्ष"],"explanation":"एक कनेक्टिकट CLP जारी होने की तारीख से एक वर्ष तक सक्रिय रहता है; यदि उस अवधि के भीतर CDL प्राप्त नहीं किया जाता है तो आवेदक को आवश्यक परीक्षाएँ फिर से देनी होंगी। स्रोत: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)।"},"30":{"q":"7 फरवरी, 2022 से प्रभावी, कनेक्टिकट में परीक्षा देने से पहले किसे FMCSA-पंजीकृत प्रदाता के माध्यम से Entry-Level Driver Training (ELDT) पूरा करना होगा?","options":["केवल हैज़मैट एंडोर्समेंट के आवेदक","मौजूदा CDL का नवीनीकरण करने वाला कोई भी व्यक्ति","पहली बार CDL आवेदक, Class B से Class A में अपग्रेड करने वाले, और पहली बार H, P, या S एंडोर्समेंट आवेदक","केवल 21 वर्ष से कम आयु के चालक"],"explanation":"7 फरवरी, 2022 से, ELDT पहली बार CDL आवेदकों, Class B को Class A में अपग्रेड करने वाले चालकों, और H, P, या S एंडोर्समेंट के लिए पहली बार आवेदकों के लिए आवश्यक है, जिसमें प्रशिक्षण FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता द्वारा दिया जाता है। स्रोत: FMCSA ELDT rule (49 CFR Part 380); CT DMV CDL pages (portal.ct.gov/dmv)।"},"31":{"q":"एक कनेक्टिकट आवेदक के लिए Entry-Level Driver Training (ELDT) किस प्रणाली के माध्यम से पूरा किया जाना चाहिए?","options":["Connecticut DMV training portal","FMCSA Training Provider Registry (TPR)","TSA enrollment system","Drug and Alcohol Clearinghouse"],"explanation":"ELDT को FMCSA Training Provider Registry (TPR) पर सूचीबद्ध प्रदाता के साथ पूरा किया जाना चाहिए, जो चालक के पूरा होने की रिपोर्ट FMCSA को देता है। स्रोत: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov); CT DMV CDL pages।"},"32":{"q":"खतरनाक सामग्री (H) एंडोर्समेंट के लिए, ELDT आवश्यकता में किस प्रकार का प्रशिक्षण शामिल है?","options":["केवल थ्योरी प्रशिक्षण","केवल बिहाइंड-द-व्हील प्रशिक्षण","थ्योरी और बिहाइंड-द-व्हील दोनों प्रशिक्षण","हैज़मैट के लिए किसी ELDT की आवश्यकता नहीं है"],"explanation":"हैज़मैट (H) एंडोर्समेंट की ELDT आवश्यकता केवल-थ्योरी है; इसमें कोई बिहाइंड-द-व्हील घटक नहीं है, जैसा कि Class A/B और P तथा S एंडोर्समेंट में होता है। स्रोत: FMCSA ELDT rule (49 CFR Part 380); FMCSA Training Provider Registry।"},"33":{"q":"ज्ञान और ELDT आवश्यकताओं के अलावा, हैज़मैट (H) एंडोर्समेंट प्राप्त करने के लिए एक कनेक्टिकट आवेदक को कौन-सी अतिरिक्त संघीय जाँच पास करनी होगी?","options":["केवल एक DOT physical","एक TSA Security Threat Assessment जिसमें फिंगरप्रिंटिंग शामिल है","एक राज्य क्रेडिट जाँच","केवल-दृष्टि परीक्षा"],"explanation":"एक हैज़मैट एंडोर्समेंट के लिए ज्ञान परीक्षा और ELDT थ्योरी प्रशिक्षण के अलावा TSA Security Threat Assessment पास करना आवश्यक है, जिसमें एक पृष्ठभूमि जाँच और फिंगरप्रिंटिंग शामिल है। स्रोत: TSA HazMat Endorsement Threat Assessment Program; CT DMV endorsement pages।"},"34":{"q":"Commercial Learner Permit के लिए आवेदन करते समय, REAL ID के अनुरूप, Connecticut DMV किस दस्तावेज़ों के सेट की आवश्यकता रखता है?","options":["पहचान का प्रमाण, Social Security number, वैध U.S. उपस्थिति, और कनेक्टिकट निवास के दो प्रमाण","केवल एक पासपोर्ट","एक जन्म प्रमाणपत्र और एक उपयोगिता बिल","केवल वर्तमान कनेक्टिकट ड्राइवर लाइसेंस"],"explanation":"कनेक्टिकट REAL ID दस्तावेज़ीकरण की आवश्यकता रखता है: पहचान का प्रमाण, Social Security number, वैध U.S. उपस्थिति, और कनेक्टिकट निवास के दो प्रमाण, साथ ही स्व-प्रमाणन पुष्टि और आवेदन फॉर्म R-229a। स्रोत: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)।"},"35":{"q":"एक कनेक्टिकट चालक जो राज्य के भीतर और बाहर दोनों जगह एक वाणिज्यिक वाहन का संचालन करेगा और जिसे DOT medical card रखना आवश्यक है, उसे किस श्रेणी के तहत स्व-प्रमाणन करना चाहिए?","options":["Excepted Interstate (EI)","Non-excepted Interstate (NI)","Excepted Intrastate (EA)","Non-excepted Intrastate (NA)"],"explanation":"Non-excepted Interstate (NI) कनेक्टिकट के भीतर और बाहर ड्राइविंग को कवर करता है और इसके लिए संघीय DOT medical certificate आवश्यकताओं को पूरा करना आवश्यक है। स्रोत: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)।"},"36":{"q":"कौन-सी कनेक्टिकट स्व-प्रमाणन श्रेणी ऐसे चालक पर लागू होती है जो केवल कनेक्टिकट के भीतर संचालन करता है और जिसे संघीय DOT medical card आवश्यकताओं को पूरा करने की आवश्यकता नहीं है?","options":["Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)","Excepted Interstate (EI)"],"explanation":"Excepted Intrastate (EA) ऐसे चालकों पर लागू होता है जो केवल कनेक्टिकट के भीतर संचालन करते हैं और जो संघीय DOT medical certificate आवश्यकता से छूट प्राप्त हैं। स्रोत: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)।"},"37":{"q":"एक कनेक्टिकट CDL लेनदेन को संसाधित करने से पहले, DMV किसी आवेदक की स्थिति को किस संघीय प्रणाली में सत्यापित करता है?","options":["TSA PreCheck database","FMCSA Drug and Alcohol Clearinghouse","केवल National Driver Register","Selective Service System"],"explanation":"कनेक्टिकट आवेदकों को FMCSA Drug and Alcohol Clearinghouse में पंजीकरण करना होगा, और DMV CDL लेनदेन को संसाधित करने से पहले आवेदक की Clearinghouse स्थिति की जाँच करता है। स्रोत: CT DMV CDL pages (portal.ct.gov/dmv); FMCSA Drug and Alcohol Clearinghouse।"},"38":{"q":"खतरनाक सामग्री (H) एंडोर्समेंट के लिए कनेक्टिकट किस न्यूनतम आयु, और किस नागरिकता/आव्रजन स्थिति की आवश्यकता रखता है?","options":["आयु 18, केवल U.S. नागरिक","आयु 21, U.S. नागरिक, वैध स्थायी निवासी, या वैध Employment Authorization Document धारक","आयु 19, कोई भी वैध निवासी","आयु 21, केवल U.S. नागरिक"],"explanation":"कनेक्टिकट हैज़मैट (H) आवेदकों के लिए कम से कम 21 वर्ष का होना और U.S. नागरिक, एक वैध स्थायी निवासी, या एक वैध Employment Authorization Document धारक होना आवश्यक रखता है। स्रोत: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)।"},"39":{"q":"कनेक्टिकट में, अधिकतम कितने रक्त अल्कोहल सांद्रता (BAC) पर कोई व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) का संचालन कर सकता है?","options":["0.04%","0.08%","0.02%","0.00%"],"explanation":"कनेक्टिकट संघीय CMV मानक का पालन करता है: 0.04% या उससे अधिक BAC के साथ CMV का संचालन करना अवैध है (CT CDL Manual 1.3.2; 49 CFR 383.51)।"},"40":{"q":"कनेक्टिकट में एक CMV का संचालन करने पर, एक चालक को स्वचालित रूप से रासायनिक अल्कोहल परीक्षण के लिए सहमति दी हुई माना जाता है। इस सिद्धांत को क्या कहा जाता है?","options":["Implied consent","Probable cause","Express waiver","Administrative review"],"explanation":"कनेक्टिकट का अंतर्निहित सहमति (implied consent) कानून किसी भी लाइसेंस प्राप्त संचालक को रक्त, श्वास, या मूत्र परीक्षण के लिए सहमति दी हुई मानता है (CT CDL Manual 1.3.2; CGS Sec. 14-227b)।"},"41":{"q":"एक कनेक्टिकट CDL धारक को पहले बड़े अपराध, जैसे कि 0.04% या उससे अधिक BAC के साथ CMV चलाने, के लिए दोषी ठहराया जाता है। CDL कितने समय के लिए अयोग्य घोषित किया जाता है?","options":["At least 1 year","At least 90 days","At least 6 months","At least 3 years"],"explanation":"एक पहला बड़ा अपराध CDL को कम से कम एक वर्ष के लिए अयोग्य घोषित करता है (CT CDL Manual 1.3.2; 49 CFR 383.51)।"},"42":{"q":"कनेक्टिकट नियमों के तहत, यदि कोई पहला बड़ा अपराध (जैसे कि 0.04 BAC या परीक्षण से इनकार) तब होता है जब चालक खतरनाक सामग्री के लिए प्लाकार्डेड CMV का संचालन कर रहा हो, तो अयोग्यता कम से कम होती है:","options":["3 years","1 year","5 years","18 months"],"explanation":"प्लाकार्डेड HazMat CMV का संचालन करते समय एक पहला बड़ा अपराध CDL को कम से कम तीन वर्ष के लिए अयोग्य घोषित करता है (CT CDL Manual 1.3.2; 49 CFR 383.51)।"},"43":{"q":"एक दूसरे बड़े अपराध (उदाहरण के लिए, एक दूसरा DUI या परीक्षण से इनकार) के लिए दोषी ठहराए गए चालक के लिए कनेक्टिकट अयोग्यता दंड क्या है?","options":["आजीवन अयोग्यता","10-वर्षीय अयोग्यता","5-वर्षीय अयोग्यता","3-वर्षीय अयोग्यता"],"explanation":"एक दूसरा बड़ा अपराध CDL की आजीवन अयोग्यता का परिणाम होता है (CT CDL Manual 1.3.2; 49 CFR 383.51)।"},"44":{"q":"एक कनेक्टिकट CDL धारक पहली बार रासायनिक अल्कोहल परीक्षण से इनकार करता है। इस इनकार के लिए CDL कितने समय के लिए अयोग्य घोषित किया जाता है?","options":["1 year","6 months","60 days","3 years"],"explanation":"रासायनिक परीक्षण से इनकार करना (अंतर्निहित सहमति का उल्लंघन) पहले अपराध पर CDL को एक वर्ष के लिए अयोग्य घोषित करता है (CT CDL Manual 1.3.2; CGS Sec. 14-227b)।"},"45":{"q":"कनेक्टिकट के अंतर्निहित सहमति कानून के तहत, यदि कोई व्यक्ति रासायनिक परीक्षण से इनकार करता है, तो नियमित (गैर-वाणिज्यिक) संचालक लाइसेंस कितने समय से कम के लिए निलंबन के अधीन नहीं होता:","options":["6 months","30 days","1 year","90 days"],"explanation":"रासायनिक परीक्षण से इनकार करना संचालक लाइसेंस को छह महीने से कम के लिए निलंबन के अधीन नहीं करता; यदि निलंबित किया जाता है, तो CDL भी अयोग्य घोषित किया जाता है (CT CDL Manual 1.3.2; CGS Sec. 14-227b)।"},"46":{"q":"कनेक्टिकट में, 0.04% से कम पता लगाने योग्य मात्रा में अल्कोहल के साथ पाए गए CMV चालक पर कौन-सी तत्काल कार्रवाई की जाती है?","options":["24 घंटे के लिए आउट-ऑफ-सर्विस रखा गया","60 दिनों के लिए अयोग्य","DUI के लिए गिरफ्तार","बिना किसी आगे की कार्रवाई के $500 का जुर्माना"],"explanation":"0.04% से कम कोई भी पता लगाने योग्य अल्कोहल 24 घंटे के लिए आउट-ऑफ-सर्विस रखे जाने का परिणाम होता है (CT CDL Manual 1.3.2; 49 CFR 392.5)।"},"47":{"q":"एक कनेक्टिकट CDL धारक के लिए निम्नलिखित में से कौन-सा एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत है?","options":["पोस्ट की गई सीमा से 15 mph या उससे अधिक की गति","एक CMV में पहला DUI","रेलमार्ग क्रॉसिंग पर रुकने में विफल होना","एक आउट-ऑफ-सर्विस आदेश का उल्लंघन"],"explanation":"गंभीर यातायात उल्लंघनों में अत्यधिक गति (सीमा से 15 mph या उससे अधिक), लापरवाह ड्राइविंग, और अनियमित लेन परिवर्तन शामिल हैं; DUI और OOS उल्लंघन अलग श्रेणियाँ हैं (CT CDL Manual 1.3.3)।"},"48":{"q":"एक कनेक्टिकट CDL धारक तीन-वर्षीय अवधि के भीतर दो गंभीर यातायात उल्लंघन करता है। न्यूनतम अयोग्यता है:","options":["60 days","30 days","120 days","1 year"],"explanation":"तीन वर्षों के भीतर दो गंभीर यातायात उल्लंघन CDL को कम से कम 60 दिनों के लिए अयोग्य घोषित करते हैं (CT CDL Manual 1.3.3; 49 CFR 383.51)।"},"49":{"q":"यदि एक कनेक्टिकट CDL धारक तीन-वर्षीय अवधि के भीतर तीन या अधिक गंभीर यातायात उल्लंघन करता है, तो न्यूनतम अयोग्यता है:","options":["120 days","60 days","180 days","1 year"],"explanation":"तीन वर्षों के भीतर तीन या अधिक गंभीर यातायात उल्लंघन CDL को कम से कम 120 दिनों के लिए अयोग्य घोषित करते हैं (CT CDL Manual 1.3.3; 49 CFR 383.51)।"},"50":{"q":"इनमें से कौन-सा कनेक्टिकट की गंभीर यातायात उल्लंघनों की सूची में शामिल नहीं है?","options":["पोस्ट की गई गति सीमा से 8 mph अधिक ड्राइविंग","अनुचित या अनियमित लेन परिवर्तन","किसी वाहन का बहुत पास से पीछा करना","लापरवाह ड्राइविंग"],"explanation":"गंभीर उल्लंघनों के लिए सीमा से 15 mph या उससे अधिक की गति आवश्यक है; 8 mph अधिक योग्य नहीं है, जबकि अनियमित लेन परिवर्तन, बहुत पास से पीछा करना, और लापरवाह ड्राइविंग योग्य हैं (CT CDL Manual 1.3.3)।"},"51":{"q":"एक कनेक्टिकट CDL धारक 10-वर्षीय अवधि के भीतर एक तीसरा आउट-ऑफ-सर्विस आदेश उल्लंघन करता है। न्यूनतम अयोग्यता है:","options":["3 years","1 year","2 years","180 days"],"explanation":"10 वर्षों के भीतर एक तीसरा या बाद का आउट-ऑफ-सर्विस आदेश उल्लंघन CDL को कम से कम 3 वर्षों (5 तक) के लिए अयोग्य घोषित करता है (CT CDL Manual 1.3.4; 49 CFR 383.51)।"},"52":{"q":"एक CMV का संचालन करते समय एक रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए कनेक्टिकट अयोग्यता क्या है?","options":["At least 60 days","At least 30 days","At least 120 days","At least 180 days"],"explanation":"एक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन CDL को कम से कम 60 दिनों के लिए अयोग्य घोषित करता है (CT CDL Manual 1.3.5; 49 CFR 383.51)।"},"53":{"q":"तीन वर्षों के भीतर एक दूसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए, एक कनेक्टिकट CDL धारक कम से कम कितने समय के लिए अयोग्य घोषित किया जाता है:","options":["120 days","60 days","180 days","1 year"],"explanation":"तीन वर्षों के भीतर एक दूसरा ग्रेड क्रॉसिंग उल्लंघन CDL को कम से कम 120 दिनों के लिए अयोग्य घोषित करता है (CT CDL Manual 1.3.5; 49 CFR 383.51)।"},"54":{"q":"कनेक्टिकट और संघीय CMV नियमों के तहत, एक CMV का संचालन करते समय हाथ में पकड़े/उपयोग किए जाने वाले मोबाइल फोन के दो या अधिक उल्लंघनों के लिए दोषी ठहराए गए चालक को दूसरे अपराध के लिए 60 दिनों की अयोग्यता का सामना करना पड़ता है और तीन वर्षों के भीतर तीन या अधिक अपराधों के लिए कितने समय की?","options":["120 days","60 days","180 days","1 year"],"explanation":"एक CMV चलाते समय हाथ में पकड़े मोबाइल फोन का उपयोग दूसरे अपराध के लिए 60 दिनों की अयोग्यता और तीन वर्षों के भीतर तीन या अधिक के लिए 120 दिनों की अयोग्यता लाता है (CT CDL Manual 2.9.4; 49 CFR 383.51)।"},"55":{"q":"किसी भी यातायात उल्लंघन (पार्किंग के अलावा) के लिए दोषी ठहराए जाने के बाद, एक कनेक्टिकट CDL धारक को कितने दिनों के भीतर अपने नियोक्ता को सूचित करना होगा?","options":["30 days","2 days","10 days","60 days"],"explanation":"एक CDL धारक को किसी भी यातायात उल्लंघन की दोषसिद्धि के 30 दिनों के भीतर अपने नियोक्ता को सूचित करना होगा, चाहे जो भी वाहन चलाया गया हो (CT CDL Manual 1.4; 49 CFR 383.31)।"},"56":{"q":"कनेक्टिकट के रेलरोड-क्रॉसिंग कानून के तहत, बस, स्कूल बस, या प्लेकार्ड लगे हुए हजमैट/कार्गो-टैंक वाणिज्यिक वाहन को समतल (ग्रेड) पर पटरियाँ पार करने से पहले कहाँ रुकना चाहिए?","options":["निकटतम रेल से 15 feet से कम नहीं और 50 feet से अधिक नहीं","निकटतम रेल से ठीक 25 feet","निकटतम रेल से 10 feet से कम नहीं और 40 feet से अधिक नहीं","निकटतम रेल से 50 feet से कम नहीं और 100 feet से अधिक नहीं"],"explanation":"Connecticut General Statutes Sec. 14-250 और CT CDL Manual के अनुसार बसों, यात्रियों को ले जाने वाले वाहनों, स्कूल परिवहन वाहनों, और कार्गो टैंक या हजमैट वाले CMV को निकटतम रेल से 15 feet से कम नहीं और 50 feet से अधिक नहीं की दूरी पर रुकना चाहिए, फिर पार करने से पहले देखना और सुनना चाहिए।"},"57":{"q":"जब कोई कनेक्टिकट चालक बहु-लेन वाले राजमार्ग पर चमकती रोशनी वाले स्थिर आपातकालीन वाहन के पास पहुँचता है, तो राज्य का Move Over कानून चालक से क्या करने की माँग करता है?","options":["गति को उचित स्तर तक कम करे और, यदि निकटवर्ती लेन में हो, तो सुरक्षित होने पर एक लेन हटकर चले","आपातकालीन वाहन के घटनास्थल से हटने तक पूरी तरह रुक जाए","तय गति सीमा बनाए रखे लेकिन हॉर्न बजाए","एक लेन हटकर तभी चले जब आपातकालीन वाहन पुलिस कार हो"],"explanation":"Connecticut General Statutes Sec. 14-283b ('Move Over' कानून) के अनुसार चालकों को तुरंत सीमा से नीचे उचित गति तक धीमा होना चाहिए और, जब शोल्डर से सटी लेन में चल रहे हों, तो एक लेन हटकर चलना चाहिए, बशर्ते वह गतिविधि असुरक्षित न हो।"},"58":{"q":"कनेक्टिकट के एक विभाजित सीमित-पहुँच राजमार्ग पर जहाँ एक ही दिशा में तीन या अधिक लेन हों और राज्य ने ऐसा निर्धारित किया हो, किस वाहन को सबसे बाईं लेन में चलाने से प्रतिबंधित किया गया है?","options":["एक वाणिज्यिक रूप से पंजीकृत ट्रक","एक यात्री कार जिसमें एक सवार हो","एक मोटरसाइकिल","कॉल पर जवाब देती एक एम्बुलेंस"],"explanation":"Connecticut General Statutes Sec. 14-230a वाणिज्यिक रूप से पंजीकृत वाहनों, मोटर बसों, ट्रेलर वाले वाहनों, और स्कूल बसों को विभाजित सीमित-पहुँच राजमार्गों की सबसे बाईं लेन में चलने से रोकता है जहाँ एक ही दिशा में तीन या अधिक लेन हों और Office of the State Traffic Administration ने ऐसा निर्धारित किया हो; जुर्माना $88 है।"},"59":{"q":"कनेक्टिकट में कौन-से मार्ग ट्रैक्टर-ट्रेलर और बॉक्स ट्रक जैसे वाणिज्यिक वाहनों को प्रतिबंधित करते हैं?","options":["Merritt, Wilbur Cross, और Milford Parkways (Route 15 कॉरिडोर)","Interstate 95 और Interstate 84","100 से ऊपर क्रमांकित सभी राज्य मार्ग","Route 9 और Route 2 एक्सप्रेसवे"],"explanation":"कनेक्टिकट के पार्कवे - Merritt Parkway और Wilbur Cross Parkway (Route 15) तथा Milford Parkway - वाणिज्यिक वाहनों, ट्रेलरों, और बड़े आकार के वाहनों को प्रतिबंधित करते हैं, मुख्यतः नीचे के ऐतिहासिक ओवरपास के कारण। CT DOT Parkway Restrictions; पार्कवे-उल्लंघन का जुर्माना $500 प्रति उल्लंघन है।"},"60":{"q":"कनेक्टिकट के एक राजमार्ग पर जहाँ लेन एक सुरक्षा द्वीप (safety island) या भौतिक अवरोध द्वारा अलग की गई हों, अवरोध के विपरीत ओर के चालक को क्या करना चाहिए जब कोई स्कूल बस लाल बत्तियाँ चमकाते हुए रुकी हो?","options":["चालक बिना रुके आगे बढ़ सकता है","चालक को लाल बत्तियाँ बंद होने तक रुकना चाहिए","चालक को तभी रुकना चाहिए जब बस का दरवाजा खुला हो","चालक को 15 mph तक धीमा होना चाहिए पर रुकने की जरूरत नहीं"],"explanation":"Connecticut General Statutes Sec. 14-279 के अनुसार ऐसे राजमार्ग पर जहाँ लेन सुरक्षा द्वीप या भौतिक अवरोध द्वारा अलग हों, उस अवरोध के विपरीत ओर का चालक स्कूल बस के लिए बिना रुके आगे बढ़ सकता है। केवल पेंट की गई रेखा इसके योग्य नहीं होती - दोनों दिशाओं को रुकना चाहिए।"},"61":{"q":"कनेक्टिकट के ऐसे मार्ग पर जो केवल पेंट की गई केंद्र रेखा द्वारा अलग हो (कोई भौतिक अवरोध नहीं), जब विपरीत ओर कोई रुकी हुई स्कूल बस चमकती लाल बत्तियाँ दिखा रही हो तो चालक को क्या करना चाहिए?","options":["रुकें, क्योंकि पेंट की गई रेखा विभाजित-राजमार्ग छूट के योग्य नहीं होती","बिना रुके कम गति से आगे बढ़ें","बिना किसी प्रतिबंध के आगे बढ़ें क्योंकि यह आने वाला यातायात है","तभी रुकें जब बच्चे स्पष्ट रूप से सड़क पार करते दिखें"],"explanation":"Connecticut General Statutes Sec. 14-279 के तहत न-रुकने की छूट केवल वहाँ लागू होती है जहाँ कोई सुरक्षा द्वीप या भौतिक अवरोध लेन को अलग करता हो। केवल पेंट की गई रेखा होने पर, दोनों ओर के वाहनों को चमकती लाल बत्तियों वाली स्कूल बस के लिए पूरी तरह रुकना चाहिए।"},"62":{"q":"कनेक्टिकट का चालक रुकी हुई, लाल-बत्ती चमकाती स्कूल बस के सामने से कितनी नजदीक तक पहुँच सकता है, इससे पहले कि उसे रुकना अनिवार्य हो जाए?","options":["बस के सामने से 10 feet से कम नहीं","बस के सामने से 5 feet से कम नहीं","बस के सामने से 20 feet से कम नहीं","बस के सामने से 25 feet से कम नहीं"],"explanation":"Connecticut General Statutes Sec. 14-279 के अनुसार चमकती लाल संकेत बत्तियाँ दिखा रही पंजीकृत स्कूल बस के पास पहुँचते समय वाहनों को सामने से 10 feet से कम नहीं, और पीछे से आगे निकलते या पीछा करते समय पीछे से 10 feet से कम नहीं की दूरी पर रुकना चाहिए।"},"63":{"q":"कनेक्टिकट के एक-तरफा या विभाजित राजमार्ग पर खराब हुए CMV को रोकने के बाद, चालक को तीन परावर्तक चेतावनी त्रिकोण कहाँ रखने चाहिए?","options":["आने वाले यातायात की ओर 10 feet, 100 feet, और 200 feet पर","वाहन के पीछे 10 feet, 50 feet, और 150 feet पर","आने वाले यातायात की ओर 25 feet, 75 feet, और 125 feet पर","आने वाले यातायात की ओर 5 feet, 50 feet, और 500 feet पर"],"explanation":"Connecticut CDL Manual (49 CFR 392.22 के अनुरूप) निर्देश देता है कि एक-तरफा या विभाजित राजमार्ग पर चेतावनी उपकरण रुके हुए वाहन के पीछे आने वाले यातायात की ओर 10 feet, 100 feet, और 200 feet पर रखे जाएँ।"},"64":{"q":"कनेक्टिकट में एक CDL चालक को सड़क या शोल्डर पर CMV रोकने के बाद कितने मिनट के भीतर आपातकालीन चेतावनी उपकरण रखने चाहिए?","options":["10 मिनट के भीतर","30 मिनट के भीतर","5 मिनट के भीतर","तुरंत, केबिन से बाहर निकलने से पहले"],"explanation":"Connecticut CDL Manual में कहा गया है कि यदि आपको सड़क या शोल्डर पर रुकना पड़े, तो आपको चार-तरफा फ्लैशर चालू करने चाहिए और 10 मिनट के भीतर आपातकालीन चेतावनी उपकरण बाहर रखने चाहिए।"},"65":{"q":"कौन-सी सूची सही ढंग से उन कनेक्टिकट वाहनों की पहचान करती है जिन्हें प्रत्येक रेलरोड समतल क्रॉसिंग पर रुकना ही चाहिए?","options":["यात्रियों को ले जाने वाली बसें, स्कूल परिवहन वाहन, और कार्गो टैंक वाले या खतरनाक सामग्री ले जाने वाले CMV","सभी वाणिज्यिक वाहन जो 10,000 pounds से अधिक हों, कार्गो की परवाह किए बिना","केवल खाली टैंक ट्रक और टो ट्रक","केवल ट्रेलर खींचने वाले वाहन"],"explanation":"Connecticut General Statutes Sec. 14-250 के अनुसार यात्रियों को ले जाने वाले प्रत्येक CMV, सेवा बस, या स्कूली बच्चों को ले जाने में उपयोग होने वाले वाहन, और कार्गो टैंक वाले या खतरनाक सामग्री ले जाने वाले प्रत्येक CMV के चालक को पार करने से पहले निकटतम रेल से 15 से 50 feet की दूरी पर रुकना चाहिए।"},"66":{"q":"कनेक्टिकट के इंटरस्टेट राजमार्ग पर एक CMV कानूनी रूप से अधिकतम कितनी तय गति सीमा तक चल सकता है?","options":["65 mph, वही अधिकतम जो यात्री वाहनों पर लागू होती है","55 mph, राज्यभर के सभी ट्रकों के लिए एक विशेष कम सीमा","ग्रामीण इंटरस्टेट पर 70 mph","26,000 pounds से अधिक किसी भी वाहन के लिए 60 mph"],"explanation":"कनेक्टिकट की अधिकतम तय गति सीमा 65 mph है (CGS Sec. 14-219 / 14-218a), और राज्य ट्रकों के लिए कोई अलग, कम राज्यव्यापी गति सीमा निर्धारित नहीं करता - जहाँ तय हो वहाँ ट्रक और कार समान 65 mph अधिकतम साझा करते हैं। चालकों को फिर भी किसी भी कम तय सीमा का पालन करना चाहिए।"},"67":{"q":"कनेक्टिकट की दो-लेन वाली ऐसी सड़क पर जो दोनों दिशाओं में यातायात ले जाती हो (अविभाजित), एक CMV चालक को रुकने के बाद तीन चेतावनी त्रिकोण कहाँ रखने चाहिए?","options":["वाहन के 10 feet के भीतर, और उससे 100 feet आगे तथा 100 feet पीछे","केवल वाहन के पीछे 10 feet, 100 feet, और 200 feet पर","केवल वाहन के 50 feet आगे और 50 feet पीछे","आगे और पीछे 10 feet के भीतर, और प्रत्येक दिशा में 250 feet पर"],"explanation":"Connecticut CDL Manual निर्देश देता है कि दो-लेन, दो-तरफा या अविभाजित राजमार्ग पर एक त्रिकोण वाहन के 10 feet के भीतर तथा एक-एक 100 feet पीछे और 100 feet आगे रखें, उस शोल्डर या लेन में जहाँ आप रुके थे।"},"68":{"q":"कनेक्टिकट के दाएँ-चलें नियम के तहत, यातायात की सामान्य गति से धीमा चलने वाले वाहन को कहाँ चलाया जाना चाहिए?","options":["दाईं ओर की लेन में या राजमार्ग के दाएँ किनारे के यथासंभव नजदीक","किसी भी लेन में, जब तक वह फ्लैशर का उपयोग करे","तीन-लेन वाली सड़क की मध्य लेन में","विलय यातायात से बचने के लिए बाईं लेन में"],"explanation":"Connecticut General Statutes Sec. 14-230 के अनुसार वाहनों को दाईं ओर चलाया जाना चाहिए, और यातायात की सामान्य गति से कम चलने वाले किसी भी वाहन को उपलब्ध दाईं ओर की लेन में, या दाएँ कर्ब या किनारे के यथासंभव नजदीक चलाया जाना चाहिए।"},"69":{"q":"कनेक्टिकट ऐसे राज्य पार्कवे पर वाणिज्यिक मोटर वाहन चलाने के लिए क्या दंड लगाता है जहाँ ऐसे वाहन प्रतिबंधित हैं?","options":["प्रत्येक उल्लंघन के लिए $500 का जुर्माना","पहले अपराध पर केवल एक लिखित चेतावनी","$35 का जुर्माना और दो अंक","30 दिनों के लिए अनिवार्य लाइसेंस निलंबन"],"explanation":"कनेक्टिकट ने पार्कवे (Merritt, Wilbur Cross, Milford) पर प्रतिबंधित वाणिज्यिक वाहन चलाने का दंड बढ़ाकर $500 प्रति उल्लंघन कर दिया। CT DOT Parkway Restrictions; CGS Chapter 249 / Sec. 14-298 पार्कवे-प्रतिबंध प्राधिकरण।"},"70":{"q":"आपातकालीन वाहनों के अलावा, कनेक्टिकट का Move Over कानून चालकों से शोल्डर पर रुके निम्न में से किसके लिए धीमा होने और हटकर चलने की भी माँग करता है?","options":["एक गैर-आपातकालीन वाहन जो शोल्डर पर स्थिर खड़ा हो","केवल चिह्नित पुलिस क्रूजर","केवल वे वाहन जिनके पास लाल फ्लेयर रखे हों","बस स्टॉप पर प्रतीक्षा कर रहे पैदल यात्री"],"explanation":"Connecticut General Statutes Sec. 14-283b का विस्तार न केवल चमकती बत्तियों वाले आपातकालीन वाहनों (रखरखाव वाहनों और रेकर सहित) बल्कि किसी भी गैर-आपातकालीन वाहन को भी शामिल करने के लिए किया गया जो स्थिर हो और शोल्डर पर स्थित हो; चालकों को सुरक्षित होने पर धीमा होकर हटकर चलना चाहिए।"},"71":{"q":"कनेक्टिकट में वह कानूनी वजन सीमा क्या है जिससे ऊपर एक वाहन को सामान्यतः DOT ओवरवेट परमिट की आवश्यकता होती है?","options":["80,000 pounds सकल वाहन वजन","73,280 pounds सकल वाहन वजन","100,000 pounds सकल वाहन वजन","65,000 pounds सकल वाहन वजन"],"explanation":"कनेक्टिकट 80,000 pounds सकल वाहन वजन (पाँच एक्सल पर) की संघीय कानूनी अधिकतम सीमा का पालन करता है। 80,000 pounds से अधिक भार के लिए CT DOT ओवरवेट परमिट की आवश्यकता होती है। CT DOT Oversize/Overweight Permit नियम।"},"72":{"q":"लाल बत्तियाँ चमकाती रुकी हुई स्कूल बस को अवैध रूप से पार करने (दूसरा या बाद का उल्लंघन) के लिए कनेक्टिकट में कौन-सा बाद-के-अपराध का दंड लागू होता है?","options":["$500 से कम नहीं और $1,000 से अधिक नहीं, और/या 30 दिनों तक की कैद","बिना जेल के समान $90 का अपराध","एक चेतावनी पत्र और दो लाइसेंस अंक","पहले अपराध के समान एक निश्चित $450 जुर्माना"],"explanation":"Connecticut General Statutes Sec. 14-279 रुकी हुई स्कूल बस को पार करने के पहले अपराध के लिए $450 जुर्माना निर्धारित करता है, और प्रत्येक बाद के अपराध के लिए $500 से कम नहीं और $1,000 से अधिक नहीं, या 30 दिनों से अधिक नहीं की कैद, या दोनों।"},"73":{"q":"ओवरसाइज परमिट की आवश्यकता होने से पहले कनेक्टिकट में अधिकतम कानूनी वाहन ऊँचाई क्या है?","options":["13 feet 6 inches","12 feet 0 inches","14 feet 6 inches","13 feet 0 inches"],"explanation":"कनेक्टिकट की कानूनी आयामी अधिकतम सीमाएँ 8 feet 6 inches चौड़ाई और 13 feet 6 inches ऊँचाई हैं (53-foot सेमिट्रेलर लंबाई के साथ)। ऊँचाई में 13 feet 6 inches से अधिक होने पर CT DOT ओवरसाइज परमिट की आवश्यकता होती है। CT DOT Oversize/Overweight Permit नियम।"},"74":{"q":"एक CDL चालक कनेक्टिकट में एक रेलरोड क्रॉसिंग के पास पहुँचता है, एक खाली कार्गो टैंक खींचते हुए जो अंतिम बार खतरनाक सामग्री के लिए इस्तेमाल हुआ था। चालक को क्या करना चाहिए?","options":["निकटतम रेल से 15 से 50 feet की दूरी पर रुके, क्योंकि यह नियम कार्गो टैंकों पर लागू होता है चाहे वे भरे हों या खाली","बिना रुके आगे बढ़े क्योंकि टैंक खाली है","तभी रुके जब कोई ट्रेन दिखाई दे","5 mph तक धीमा हो पर बिना पूरी तरह रुके पार करता रहे"],"explanation":"Connecticut General Statutes Sec. 14-250 और CT CDL Manual के अनुसार खतरनाक सामग्री के लिए उपयोग किए गए कार्गो टैंक वाले वाहनों को निकटतम रेल से 15 से 50 feet की दूरी पर रुकना चाहिए चाहे टैंक भरा हो या खाली, और तभी पार करना चाहिए जब पटरियाँ बिना रुके पार की जा सकें।"},"75":{"q":"कनेक्टिकट में Commercial Driver Licenses (CDLs) कौन-सी एजेंसी जारी करती है?","options":["Connecticut Department of Motor Vehicles (DMV)","Connecticut Department of Transportation (CTDOT)","Federal Motor Carrier Safety Administration (FMCSA)","Connecticut State Police, Commercial Vehicle Safety Division"],"explanation":"कनेक्टिकट में, Department of Motor Vehicles (DMV) CDL जारी करता है और ज्ञान तथा कौशल परीक्षण का प्रबंधन करता है। CTDOT ओवरसाइज/ओवरवेट परमिट संभालता है और FMCSA संघीय मानक तय करता है, लेकिन लाइसेंस स्वयं एक राज्य DMV प्रमाणपत्र है। स्रोत: CT DMV, 'Get a commercial driver's license' (portal.ct.gov/dmv)।"},"76":{"q":"कनेक्टिकट में, इंट्रास्टेट (केवल राज्य के भीतर) संचालन के लिए CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"कनेक्टिकट के अनुसार किसी चालक को इंट्रास्टेट (केवल कनेक्टिकट के भीतर) CMV संचालित करने के लिए कम से कम 18 वर्ष का होना चाहिए। इंटरस्टेट चलाने या खतरनाक सामग्री ले जाने के लिए चालक को कम से कम 21 वर्ष का होना चाहिए। स्रोत: CT DMV, 'Get a commercial driver's license' / 'Get a commercial learner's permit'।"},"77":{"q":"कनेक्टिकट में, इंटरस्टेट वाणिज्य में वाणिज्यिक मोटर वाहन संचालित करने या खतरनाक सामग्री ढोने की न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","23 वर्ष"],"explanation":"कनेक्टिकट, संघीय मानक का पालन करते हुए, किसी चालक को राज्य की सीमाओं के पार (इंटरस्टेट) CMV चलाने या प्लेकार्ड योग्य मात्रा में खतरनाक सामग्री ले जाने के लिए कम से कम 21 वर्ष का होने की माँग करता है। 18-20 वर्ष के चालक इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: CT DMV CLP/CDL पृष्ठ; 49 CFR 391.11।"},"78":{"q":"कनेक्टिकट में किसी नए आवेदक के Class A या Class B लाइसेंस के लिए CDL कौशल परीक्षा देने से पहले, कौन-सा प्रशिक्षण पूरा करना चाहिए?","options":["Entry-Level Driver Training (ELDT) — सिद्धांत के साथ-साथ पहिए के पीछे का — किसी FMCSA-पंजीकृत प्रदाता से","केवल एक 160-घंटे का राज्य-अनुमोदित व्यापार स्कूल कार्यक्रम","Connecticut DMV द्वारा अनुमोदित एक रक्षात्मक ड्राइविंग पाठ्यक्रम","एक आठ-घंटे का ऑनलाइन खतरनाक सामग्री जागरूकता पाठ्यक्रम"],"explanation":"7 फरवरी 2022 से प्रभावी, एक प्रवेश-स्तर के आवेदक को Class A/B कौशल परीक्षा देने से पहले (और जहाँ लागू हो, P, S, या H एंडोर्समेंट परीक्षाओं से पहले) FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता के माध्यम से अनिवार्य Entry-Level Driver Training (ELDT) — सिद्धांत (ज्ञान) और पहिए के पीछे का (BTW) दोनों — पूरा करना चाहिए। स्रोत: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR Part 380 Subpart F।"},"79":{"q":"कनेक्टिकट में इनमें से किस एंडोर्समेंट के लिए ज्ञान परीक्षा देने से पहले आवेदक को Entry-Level Driver Training पूरा करना चाहिए?","options":["Hazardous Materials (H) एंडोर्समेंट","Tank Vehicle (N) एंडोर्समेंट","Double/Triple Trailers (T) एंडोर्समेंट","केवल Combination (कोई एंडोर्समेंट अक्षर नहीं) श्रेणी"],"explanation":"Hazardous Materials (H) एंडोर्समेंट की ज्ञान परीक्षा से पहले ELDT पूरा करना चाहिए (H की कोई कौशल परीक्षा नहीं होती)। Passenger (P) और School Bus (S) एंडोर्समेंट की कौशल परीक्षाओं से पहले भी ELDT आवश्यक है। N और T एंडोर्समेंट ELDT के अधीन नहीं हैं। स्रोत: CT DMV, 'CDL Entry Level Driver Training Requirement'; 49 CFR 380.609।"},"80":{"q":"कनेक्टिकट लाइसेंसिंग प्रक्रिया में, पूर्ण CDL से पहले, एक नए CDL आवेदक को सबसे पहले कौन-सा दस्तावेज प्राप्त करना चाहिए?","options":["एक Commercial Learner's Permit (CLP)","DMV से एक DOT शारीरिक परीक्षा छूट","एक मोटर कैरियर संचालन प्राधिकरण (MC नंबर)","एक अस्थायी इंटरस्टेट ढुलाई प्रमाणपत्र"],"explanation":"प्रक्रिया Commercial Learner's Permit (CLP) प्राप्त करने के लिए आवश्यक ज्ञान परीक्षाएँ पास करने से शुरू होती है। फिर आवेदक अभ्यास करता है, ELDT पूरा करता है, और CLP को CDL में बदलने के लिए कौशल परीक्षा देता है। स्रोत: CT DMV, 'Get a commercial learner's permit' और 'Get a commercial driver's license'।"},"81":{"q":"कनेक्टिकट Commercial Learner's Permit (CLP) अपनी जारी होने की तारीख से कितने समय तक वैध रहता है?","options":["एक वर्ष","60 दिन","छह महीने","दो वर्ष"],"explanation":"एक कनेक्टिकट CLP जारी होने की तारीख से एक वर्ष तक वैध रहता है। यदि धारक उस वर्ष के भीतर CDL प्राप्त नहीं करता, तो नया परमिट पाने के लिए सभी आवश्यक परीक्षाएँ फिर से देनी होंगी। स्रोत: CT DMV, 'Get a commercial learner's permit'।"},"82":{"q":"कनेक्टिकट में, CDL कौशल परीक्षा देने के योग्य होने से पहले एक आवेदक को CLP कितने समय तक रखना चाहिए?","options":["कम से कम 14 days","कम से कम 30 days","कम से कम 10 days","कम से कम 60 days"],"explanation":"एक आवेदक को CDL कौशल परीक्षा देने से पहले CLP कम से कम 14 days तक रखना चाहिए। यह संघीय न्यूनतम प्रतीक्षा अवधि कनेक्टिकट में लागू की जाती है। स्रोत: CT DMV, 'Get a commercial learner's permit'; 49 CFR 383.25(a)(3)।"},"83":{"q":"कनेक्टिकट CDL सामान्य ज्ञान परीक्षा में 50 प्रश्न होते हैं। पास होने के लिए कितने सही उत्तर देने चाहिए?","options":["40 सही (80%)","35 सही (70%)","45 सही (90%)","30 सही (60%)"],"explanation":"कनेक्टिकट सामान्य ज्ञान परीक्षा में 50 बहुविकल्पीय प्रश्न होते हैं और पास होने के लिए 40 सही उत्तर (80%) आवश्यक हैं। स्रोत: CT DMV, 'Get a commercial learner's permit'।"},"84":{"q":"कनेक्टिकट CDL कौशल परीक्षा कितने अलग-अलग भागों से बनी होती है?","options":["तीन भाग","दो भाग","चार भाग","पाँच भाग"],"explanation":"CDL कौशल परीक्षा के तीन भाग होते हैं: यात्रा-पूर्व वाहन निरीक्षण, बुनियादी वाहन नियंत्रण कौशल परीक्षा, और सड़क पर ड्राइविंग परीक्षा। CDL अर्जित करने के लिए तीनों को पास करना चाहिए। स्रोत: CT DMV CDL परीक्षण; 49 CFR 383.113।"},"85":{"q":"निम्नलिखित में से कौन-सा कनेक्टिकट CDL कौशल परीक्षा के तीन आवश्यक भागों में से एक है?","options":["यात्रा-पूर्व वाहन निरीक्षण","50-प्रश्न वाली सामान्य ज्ञान परीक्षा","DOT शारीरिक परीक्षा","एयर ब्रेक लिखित एंडोर्समेंट परीक्षा"],"explanation":"कौशल-परीक्षा के तीन भाग हैं यात्रा-पूर्व वाहन निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग। सामान्य ज्ञान और एयर ब्रेक परीक्षाएँ लिखित ज्ञान परीक्षाएँ हैं (CLP के लिए दी जाती हैं), और DOT शारीरिक एक चिकित्सा परीक्षा है — इनमें से कोई भी कौशल परीक्षा का हिस्सा नहीं है। स्रोत: CT DMV; 49 CFR 383.113।"},"86":{"q":"कनेक्टिकट CDL रोड टेस्ट के दौरान, वह भाग जहाँ आवेदक नियंत्रित क्षेत्र में सीधी-रेखा बैकिंग या ऑफसेट बैकिंग जैसे युद्धाभ्यास प्रदर्शित करता है, कहलाता है:","options":["बुनियादी वाहन नियंत्रण कौशल परीक्षा","यात्रा-पूर्व निरीक्षण परीक्षा","सड़क पर ड्राइविंग परीक्षा","संयोजन वाहन परीक्षा"],"explanation":"सार्वजनिक सड़कों से बाहर किए गए बैकिंग और स्थिति-निर्धारण युद्धाभ्यास बुनियादी वाहन नियंत्रण कौशल परीक्षा का हिस्सा हैं, जो तीन कौशल-परीक्षा घटकों में से दूसरा है। यात्रा-पूर्व निरीक्षण है, और सड़क पर परीक्षा यातायात में आयोजित की जाती है। स्रोत: CT DMV; 49 CFR 383.113(b)।"},"87":{"q":"यदि कोई कनेक्टिकट CDL आवेदक एयर ब्रेक ज्ञान परीक्षा नहीं देता या पास नहीं करता, तो लाइसेंस का क्या होता है?","options":["एक 'L' प्रतिबंध लगाया जाता है, जो एयर ब्रेक से सुसज्जित किसी भी CMV के संचालन को रोकता है","आवेदक को एयर ब्रेक पास होने तक पूरी तरह CDL देने से मना कर दिया जाता है","चालक को इंट्रास्टेट संचालन तक सीमित करने वाला एक 'K' प्रतिबंध जोड़ा जाता है","कुछ नहीं — एयर ब्रेक वैकल्पिक है और कोई प्रतिबंध नहीं छोड़ता"],"explanation":"जो चालक एयर ब्रेक ज्ञान परीक्षा (और संबंधित कौशल जाँचें) पास करने में विफल रहता है, उसे एक 'L' प्रतिबंध मिलता है, जो एयर ब्रेक से सुसज्जित किसी भी CMV के संचालन को निषिद्ध करता है। स्रोत: CT DMV CLP/CDL जानकारी; 49 CFR 383.95।"},"88":{"q":"कनेक्टिकट में लागू संघीय CDL नियम प्रत्येक CDL/CLP धारक से 'स्व-प्रमाणन' (self-certify) की माँग करते हैं। संघीय ढाँचा कितनी स्व-प्रमाणन ड्राइविंग-प्रकार श्रेणियाँ परिभाषित करता है?","options":["चार","दो","तीन","छह"],"explanation":"संघीय स्व-प्रमाणन ढाँचा चार श्रेणियाँ परिभाषित करता है: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। कनेक्टिकट का ऑनलाइन स्व-प्रमाणन व्यावहारिक रूप से वे दो गैर-छूट विकल्प प्रस्तुत करता है जिनका उपयोग अधिकांश चालक करते हैं (NI और NA)। स्रोत: 49 CFR 383.71(b); CT DMV स्व-प्रमाणन।"},"89":{"q":"एक कनेक्टिकट चालक जो 'Non-Excepted Interstate' (NI) के रूप में स्व-प्रमाणन करता है, वह अपने संचालन और चिकित्सा स्थिति के बारे में कौन-सा कथन दे रहा है?","options":["वे राज्य की सीमाओं के पार संचालन करते हैं और उन्हें संघीय DOT चिकित्सा प्रमाणपत्र की आवश्यकता पूरी करनी चाहिए","वे केवल कनेक्टिकट के भीतर संचालन करते हैं और DOT चिकित्सा आवश्यकताओं से छूट प्राप्त हैं","वे राज्य की सीमाओं के पार संचालन करते हैं लेकिन किसी भी चिकित्सा प्रमाणपत्र से छूट प्राप्त हैं","वे केवल कनेक्टिकट के भीतर संचालन करते हैं और उन्हें एक खतरनाक सामग्री परमिट रखना चाहिए"],"explanation":"Non-Excepted Interstate (NI) का अर्थ है कि चालक इंटरस्टेट वाणिज्य में (कनेक्टिकट के भीतर और बाहर) CMV संचालित करता है और संघीय DOT चिकित्सा प्रमाणन आवश्यकताओं के अधीन है तथा उन्हें पूरा करना चाहिए। स्रोत: CT DMV स्व-प्रमाणन; 49 CFR 383.71(b)।"},"90":{"q":"एक कनेक्टिकट चालक जो 'Non-Excepted Intrastate' (NA) के रूप में स्व-प्रमाणन करता है, वह प्रमाणित कर रहा है कि वह:","options":["केवल कनेक्टिकट की सीमाओं के भीतर एक वाणिज्यिक मोटर वाहन संचालित करेगा","संघीय चिकित्सा छूट के तहत राज्य की सीमाओं के पार संचालन करेगा","किसी भी चिकित्सा प्रमाणन के बिना देशभर में संचालन करेगा","केवल CDL नियमों से छूट प्राप्त कृषि उपकरण संचालित करेगा"],"explanation":"Non-Excepted Intrastate (NA) केवल कनेक्टिकट के भीतर CMV के संचालन को प्रमाणित करता है। ऐसे चालकों पर एक 'K' प्रतिबंध हो सकता है जो उन्हें इंट्रास्टेट ड्राइविंग तक सीमित करता है और उन्हें कनेक्टिकट के चिकित्सा/चालक-योग्यता मानकों को पूरा करना चाहिए। स्रोत: CT DMV स्व-प्रमाणन (dmvselfservice.ct.gov)।"},"91":{"q":"एक CDL/CLP धारक Connecticut DMV के साथ स्व-प्रमाणन चरण कैसे पूरा करता है?","options":["इसे DMV ऑनलाइन स्व-सेवा प्रणाली के माध्यम से जमा करें और मुद्रित ईमेल पुष्टिकरण DMV में लाएँ","चिकित्सा परीक्षक से एक कागजी प्रमाणन FMCSA मुख्यालय को डाक से भिजवाएँ","केवल रोड टेस्ट के समय, परीक्षक को मौखिक रूप से स्व-प्रमाणन करें","प्रमाणन Connecticut Department of Labor के पास दर्ज करें"],"explanation":"चालक Connecticut DMV स्व-सेवा पोर्टल (dmvselfservice.ct.gov) के माध्यम से ऑनलाइन स्व-प्रमाणन करता है, एक ईमेल पुष्टिकरण प्राप्त करता है, और आवेदन करते, नवीनीकरण करते, अपग्रेड करते, या ड्राइविंग प्रकार बदलते समय वह मुद्रित पुष्टिकरण DMV में लाता है। स्रोत: CT DMV स्व-प्रमाणन।"},"92":{"q":"किसी कनेक्टिकट CDL धारक की DOT शारीरिक परीक्षा को प्रलेखित करने के लिए एक प्रमाणित चिकित्सा परीक्षक को कौन-सा फॉर्म उपयोग करना चाहिए, और यह DMV तक कैसे पहुँचता है?","options":["Form MCSA-5876, परीक्षक द्वारा National Registry के माध्यम से अपलोड किया गया और DMV को इलेक्ट्रॉनिक रूप से भेजा गया","Form R-229a, आवेदक द्वारा 30 दिनों के भीतर DMV को डाक से भेजा गया","Form MCSA-5876, चालक द्वारा हाथ में ले जाया गया और किसी भी DMV शाखा पर स्कैन किया गया","एक हस्तलिखित डॉक्टर का नोट, आवेदक द्वारा FMCSA को फैक्स किया गया"],"explanation":"DOT चिकित्सा परीक्षा को National Registry of Certified Medical Examiners पर सूचीबद्ध परीक्षक द्वारा Form MCSA-5876 (Medical Examiner's Certificate) पर दर्ज किया जाना चाहिए; परीक्षक परिणामों को National Registry के माध्यम से अपलोड करता है, और वे Connecticut DMV को इलेक्ट्रॉनिक रूप से प्रेषित किए जाते हैं। स्रोत: CT DMV, 'Getting medical certification for CDL'।"},"93":{"q":"यदि धारक DMV के पास एक वैध DOT चिकित्सा प्रमाणपत्र फाइल पर रखने में विफल रहता है तो कनेक्टिकट CDL का क्या होता है?","options":["एक डाउनग्रेड नोटिस के बाद, लाइसेंस को गैर-वाणिज्यिक Class D लाइसेंस में डाउनग्रेड कर दिया जाता है","CDL स्थायी रूप से निरस्त कर दिया जाता है और इसे बहाल नहीं किया जा सकता","प्रत्येक माह स्वचालित रूप से एक $500 संघीय नागरिक दंड लगाया जाता है","नियमित नवीनीकरण तिथि आने तक कुछ नहीं बदलता"],"explanation":"यदि एक वैध चिकित्सा प्रमाणपत्र बनाए नहीं रखा जाता, तो चालक की चिकित्सा स्थिति 'Not Certified' हो जाती है; DMV एक डाउनग्रेड नोटिस भेजता है, और यदि बताई गई तिथि तक एक नया वैध प्रमाणपत्र इलेक्ट्रॉनिक रूप से प्राप्त नहीं होता, तो CDL को Class D (गैर-वाणिज्यिक) लाइसेंस में डाउनग्रेड कर दिया जाता है। स्रोत: CT DMV, 'Getting medical certification for CDL'।"},"94":{"q":"कनेक्टिकट Commercial Driver License को कितनी बार नवीनीकृत करना होता है?","options":["हर चार वर्ष","हर छह वर्ष","हर दो वर्ष","हर आठ वर्ष"],"explanation":"एक कनेक्टिकट CDL चार-वर्षीय नवीनीकरण चक्र पर जारी किया जाता है (धारक के जन्मदिन के आसपास नवीनीकृत होता है), जो मानक गैर-वाणिज्यिक लाइसेंस अवधि से छोटा है। स्रोत: CT DMV, 'Renew a CDL (commercial) license'; Conn. Gen. Stat. § 14-44h।"}},"ar":{"0":{"q":"بموجب قانون ولاية كونيتيكت، ما هو الحد الأقصى لعرض المركبة التجارية (باستثناء أجهزة السلامة مثل المرايا) المسموح بتشغيلها على طرق كونيتيكت السريعة دون تصريح خاص؟","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"يحدد قانون ولاية كونيتيكت العام المادة 14-262 الحد الأقصى القانوني لعرض المركبة بـ 102 inches (8 feet 6 inches)، دون احتساب أجهزة السلامة مثل المرايا. وتُدرج ورقة قيود حجم ووزن المركبات الصادرة عن CTDOT العرض بـ 102.37 inches. المصدر: CGS Sec. 14-262؛ CTDOT Vehicle Size and Weight Limitations."},"1":{"q":"في كونيتيكت، ما هو الحد الأقصى للارتفاع، بما في ذلك الحمولة، الذي يمكن أن تبلغه المركبة قبل أن يصبح تصريح ارتفاع خاص من مفوض النقل مطلوبًا؟","options":["12 feet 6 inches","13 feet 0 inches","13 feet 6 inches","14 feet 0 inches"],"explanation":"يحظر قانون ولاية كونيتيكت العام المادة 14-264 تشغيل مركبة يتجاوز ارتفاعها مع حمولتها 13 feet 6 inches دون تصريح خطي خاص (باستثناء حمولة من القش أو التبن السائب). المصدر: CGS Sec. 14-264؛ CTDOT Vehicle Size and Weight Limitations."},"2":{"q":"في كونيتيكت، ما هو الحد الأقصى للطول، بما في ذلك الحمولة، لشاحنة وحدة واحدة (مستقيمة) تعمل دون تصريح؟","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"يحد قانون ولاية كونيتيكت العام المادة 14-262 مركبة الوحدة الواحدة بحد أقصى للطول، بما في ذلك الحمولة، يبلغ 45 feet. المصدر: CGS Sec. 14-262؛ CTDOT Vehicle Size and Weight Limitations (\"Single unit vehicle 45 feet\")."},"3":{"q":"بالنسبة لجرّار يسحب نصف مقطورة واحدة على الطرق السريعة العامة (غير المقيّدة) في كونيتيكت، ما هو الحد الأقصى القانوني لطول نصف المقطورة؟","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"على الطرق السريعة العامة، تسمح كونيتيكت بتركيبة جرّار ونصف مقطورة بطول 48-foot دون حد إجمالي للطول، لكن المقطورة نفسها محدودة بـ 48 feet. المصدر: CGS Sec. 14-262؛ CTDOT Vehicle Size and Weight Limitations."},"4":{"q":"على نظام الطرق السريعة المخصّص (المقيّد) في كونيتيكت، يُسمح بنصف مقطورة بطول 53-foot شريطة ألّا تتجاوز المسافة من مسمار الارتكاز (kingpin) إلى مركز المحور الخلفي الأبعد أي رقم؟","options":["41 feet","43 feet","45 feet","48 feet"],"explanation":"على نظام الطرق السريعة المخصّص، تسمح كونيتيكت بجرّار ونصف مقطورة بطول 53-foot دون حد إجمالي للطول، لكن يجب ألّا تتجاوز المسافة من مسمار الارتكاز إلى مركز المحور الخلفي الأبعد 43 feet. المصدر: CGS Sec. 14-262؛ CTDOT Vehicle Size and Weight Limitations."},"5":{"q":"على نظام الطرق السريعة المخصّص في كونيتيكت، يجوز أن يكون لجرّار يسحب مقطورتين توأمين (مزدوجتين) كل مقطورة بحد أقصى لطول يبلغ كم؟","options":["27 feet","28 feet","33 feet","40 feet"],"explanation":"على نظام الطرق السريعة المخصّص، تسمح كونيتيكت بتركيبة جرّار ومقطورتين توأمين دون حد إجمالي للطول، لكن كل مقطورة محدودة بـ 28 feet. المصدر: CTDOT Vehicle Size and Weight Limitations (Restricted to the Designated Highway System)."},"6":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة الذي يمكن أن تحمله تركيبة من 5 محاور على طرق كونيتيكت السريعة دون تصريح حمل زائد، عند استيفاء متطلبات معادلة الجسور؟","options":["73,000 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"الحد الأقصى للوزن العملي في كونيتيكت هو 80,000 pounds على 5 محاور مع وجود 51 feet بين المحور الأول والأخير، ويُسمح به عند استيفاء متطلبات معادلة الجسور الفيدرالية. المصدر: CTDOT Vehicle Size and Weight Limitations؛ CGS Sec. 14-267a."},"7":{"q":"في كونيتيكت، ما هو الحد الأقصى للوزن المسموح به على محور واحد عندما يكون المحور متباعدًا بمسافة 6 feet أو أكثر عن المحاور المجاورة؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"تسمح كونيتيكت بـ 22,400 pounds لكل محور عندما تكون المحاور متباعدة بمسافة 6 feet أو أكثر؛ أما المحاور المتباعدة بأقل من 6 feet فتقتصر على 18,000 pounds لكل محور. المصدر: CTDOT Vehicle Size and Weight Limitations؛ CGS Sec. 14-267a."},"8":{"q":"بموجب قواعد الوزن في كونيتيكت، ما هو الحد الأقصى للوزن المسموح به على أي محور واحد عندما يكون ذلك المحور متباعدًا بأقل من 6 feet عن محور مجاور؟","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"explanation":"تحد كونيتيكت المحاور المتباعدة بأقل من 6 feet بـ 18,000 pounds لكل محور؛ ولا يُسمح بـ 22,400 pounds إلا عند تباعد قدره 6 feet أو أكثر. المصدر: CTDOT Commercial Vehicle Limits in Connecticut؛ CGS Sec. 14-267a."},"9":{"q":"عندما يتجاوز الوزن الإجمالي لمركبة تركيبية في كونيتيكت 73,000 pounds (حتى 80,000 pounds)، ما هو الشرط الإضافي الذي يجب استيفاؤه؟","options":["يجب أن تستخدم المركبة إطارات مطاطية صلبة فقط","يجب استيفاء جميع متطلبات معادلة الجسور الفيدرالية","يجب أن تسير المركبة ليلًا فقط","يجب أن يرافق المركبة مرافقة من الشرطة"],"explanation":"وفقًا لـ CTDOT، يُسمح بحد أقصى للوزن الإجمالي يبلغ 80,000 pounds فقط عند استيفاء جميع متطلبات معادلة الجسور الفيدرالية للأوزان التي تتجاوز 73,000 pounds. المصدر: CTDOT Vehicle Size and Weight Limitations (Gross Vehicle Weights Over 73,000 pounds)."},"10":{"q":"في كونيتيكت، يستند الحد الأقصى للوزن المسموح بنقله إلى الطريق عبر إطارات أي مركبة إلى عرض الإطار. ما هو ذلك الحد؟","options":["500 pounds per inch of tire width","600 pounds per inch of tire width","700 pounds per inch of tire width","800 pounds per inch of tire width"],"explanation":"تحد كونيتيكت تحميل الإطارات بـ 600 pounds per inch of tire width (كحد أقصى). المصدر: CTDOT Vehicle Size and Weight Limitations (Tires - Load per inch width of tire 600 pounds maximum)."},"11":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به في كونيتيكت لشاحنة مستقيمة ذات محورين عندما لا يتجاوز وزن أي من المحورين 18,000 pounds؟","options":["32,000 pounds","36,000 pounds","40,000 pounds","53,800 pounds"],"explanation":"تسمح كونيتيكت لمركبة ذات محورين بما يصل إلى 36,000 pounds عندما لا يتجاوز وزن المحور 18,000 pounds (ويكون الرقم 32,000 pounds دون شرط المحور هذا). المصدر: CTDOT Commercial Vehicle Limits in Connecticut؛ CGS Sec. 14-267a."},"12":{"q":"بالنسبة لتركيبة جرّار ونصف مقطورة في كونيتيكت، ما هو الحد الأقصى للوزن الإجمالي عندما تتكون التركيبة من 3 محاور؟","options":["53,800 pounds","58,400 pounds","67,400 pounds","73,000 pounds"],"explanation":"تحدد كونيتيكت لتركيبة جرّار ونصف مقطورة ذات 3 محاور حدًا أقصى يبلغ 58,400 pounds؛ أما التركيبة ذات 4 محاور فتبلغ 67,400 pounds، والتركيبة ذات 5 محاور أو أكثر تصل إلى 73,000 pounds. المصدر: CTDOT Vehicle Size and Weight Limitations (Tractor Semitrailer)."},"13":{"q":"المعيار الفيدرالي للوزن الذي تطبقه كونيتيكت لتحديد الحد الأقصى للوزن الإجمالي المسموح به على مجموعة من المحاور المتتالية يُعرف باسم:","options":["Federal Axle Spread Rule","Federal Bridge Formula","Federal Gross Combination Standard","Federal Tandem Weight Table"],"explanation":"تطبق كونيتيكت معادلة الجسور الفيدرالية (Federal Bridge Formula) لتحديد الوزن المسموح به على مجموعات المحاور؛ ويجب استيفاؤها للأوزان الإجمالية التي تتجاوز 73,000 pounds وحتى 80,000 pounds. المصدر: CTDOT Vehicle Size and Weight Limitations؛ CGS Sec. 14-267a."},"14":{"q":"في كونيتيكت، من الذي يُصدر تصاريح المركبات ذات الحجم الزائد/الوزن الزائد (المركبات غير المطابقة)، ومن خلال أي نظام تُقدَّم الطلبات؟","options":["مفوض النقل، عبر بوابة عمليات المركبات التجارية (CVO) WebPortal التي يديرها DMV","قسم الشرطة المحلي في كل بلدة تمر بها المركبة","البوابة الإلكترونية للإدارة الفيدرالية لسلامة الناقلين بالشاحنات","قسم الطاقة والحماية البيئية عبر طلب ورقي"],"explanation":"بموجب CGS Sec. 14-270، يُصدر مفوض النقل تصاريح خاصة للمركبات غير المطابقة (ذات الحجم الزائد/الوزن الزائد)؛ وتُعالَج الطلبات عبر بوابة عمليات المركبات التجارية في كونيتيكت (CVO) WebPortal التي يديرها CT DMV. المصدر: CGS Sec. 14-270؛ CTDOT Oversize/Overweight Permit FAQ."},"15":{"q":"تصريح كونيتيكت القياسي للرحلة الواحدة للحجم الزائد/الوزن الزائد يكون عادةً صالحًا لأي مدة، وتقتصر القيادة على أي ساعات؟","options":["30 days؛ في أي وقت من النهار أو الليل","3 days؛ ساعات النهار فقط","7 days؛ ليلًا فقط","1 day؛ مع استثناء ساعات الذروة"],"explanation":"يُصدر CTDOT تصاريح الرحلة الواحدة للحجم الزائد/الوزن الزائد صالحة لمدة 3-day، مع قصر القيادة على ساعات النهار (عمومًا من نصف ساعة بعد الشروق إلى نصف ساعة قبل الغروب). المصدر: CTDOT Vehicle Size and Weight Limitations؛ CTDOT Oversize/Overweight Permit FAQ."},"16":{"q":"بموجب قانون كونيتيكت (CGS Sec. 14-267a)، ما هي الغرامة المفروضة لتشغيل مركبة تجارية ذات وزن زائد، استنادًا إلى مقدار الوزن الزائد؟","options":["$1 per 100 pounds of excess weight","$3 per 100 pounds (or fraction thereof) of excess weight","$10 per 100 pounds of excess weight","مبلغ ثابت قدره $500 بغض النظر عن الوزن الزائد"],"explanation":"يحدد قانون ولاية كونيتيكت العام المادة 14-267a غرامة الوزن الزائد بثلاثة دولارات لكل مئة رطل، أو أي جزء منها، من الوزن الزائد. المصدر: CGS Sec. 14-267a."},"17":{"q":"توفر كونيتيكت بدلًا خاصًا للوزن لبعض عمليات النقل الزراعي. ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به لصهريج تجميع الحليب السائب أو لمركبة تنقل سلعًا زراعية (حيثما يسمح القانون الفيدرالي)؟","options":["80,000 pounds","88,000 pounds","100,000 pounds","120,000 pounds"],"explanation":"يحدد قانون ولاية كونيتيكت العام المادة 14-267a وزنًا إجماليًا مسموحًا به يصل إلى 100,000 pounds لصهاريج تجميع الحليب السائب والمركبات التي تنقل سلعًا زراعية (العلف والبذور والأسمدة والمنتجات الزراعية)، حيثما يسمح القانون الفيدرالي. المصدر: CGS Sec. 14-267a."},"18":{"q":"بموجب CGS Sec. 14-267a، بالنسبة لمركبة ذات مجموعتين متتاليتين من المحاور الترادفية، يُسمح بحمل إجمالي قدره 68,000 pounds على تلك المحاور الترادفية فقط إذا كانت المسافة بين المحور الأول والأخير للمجموعتين لا تقل عن:","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"يسمح قانون ولاية كونيتيكت العام المادة 14-267a لمجموعتين متتاليتين من المحاور الترادفية بحمل إجمالي قدره 68,000 pounds شريطة أن تكون المسافة الإجمالية بين المحور الأول والأخير لتلك المجموعتين الترادفيتين المتتاليتين 36 feet أو أكثر. المصدر: CGS Sec. 14-267a."},"19":{"q":"في كونيتيكت، ما هو الحد الأدنى لتصنيف الوزن الإجمالي للمركبة (GVWR) الذي يضع مركبة واحدة ضمن فئة رخصة القيادة التجارية من الفئة B؟","options":["16,001 pounds or more","26,001 pounds or more","10,001 pounds or more","33,001 pounds or more"],"explanation":"تخوّل رخصة القيادة التجارية من الفئة B في كونيتيكت قيادة أي مركبة واحدة بتصنيف وزن إجمالي (GVWR) قدره 26,001 pounds أو أكثر، وأي مركبة من هذا القبيل تسحب وحدة لا تتجاوز 10,000 pounds. المصدر: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"20":{"q":"بموجب قواعد كونيتيكت، تُشترط رخصة القيادة التجارية من الفئة A لقيادة تركيبة من المركبات بتصنيف وزن إجمالي (GVWR) قدره 26,001 pounds أو أكثر شريطة أن يتجاوز تصنيف الوزن الإجمالي للوحدة المسحوبة أي رقم؟","options":["5,000 pounds","26,001 pounds","10,000 pounds","15,000 pounds"],"explanation":"تشمل رخصة القيادة التجارية من الفئة A في كونيتيكت التركيبات بتصنيف وزن إجمالي (GVWR) قدره 26,001 pounds أو أكثر حيث يتجاوز تصنيف الوزن الإجمالي للمركبة المسحوبة 10,000 pounds. المصدر: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"21":{"q":"يقود سائق في كونيتيكت مركبة واحدة بتصنيف وزن إجمالي أقل من 26,001 pounds مصمّمة لنقل 20 راكبًا بما في ذلك السائق. أي فئة من رخص القيادة التجارية تنطبق؟","options":["Class A","Class B","Class C","لا تُشترط رخصة قيادة تجارية"],"explanation":"تشمل رخصة القيادة التجارية من الفئة C في كونيتيكت مركبة واحدة بتصنيف وزن إجمالي أقل من 26,001 pounds (أو تسحب وحدة لا تتجاوز 10,000 pounds) مصمّمة لنقل 16 راكبًا أو أكثر بما في ذلك السائق، أو تنقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: CT DMV, CDL classes, endorsements, and restrictions (portal.ct.gov/dmv)."},"22":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة قيادة تجارية في كونيتيكت مقيّدة بالتشغيل داخل الولاية (داخل كونيتيكت فقط)؟","options":["16","18","19","21"],"explanation":"تشترط كونيتيكت أن يكون عمر مقدّم الطلب 18 عامًا على الأقل للحصول على رخصة قيادة تجارية داخل الولاية (التشغيل داخل كونيتيكت فقط). المصدر: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"23":{"q":"ما هو الحد الأدنى للعمر المطلوب لتشغيل مركبة آلية تجارية في التجارة بين الولايات برخصة قيادة تجارية من كونيتيكت؟","options":["18","19","20","21"],"explanation":"تشترط كونيتيكت أن يكون عمر مقدّم الطلب 21 عامًا على الأقل للتشغيل بين الولايات (داخل كونيتيكت وخارجها). المصدر: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"24":{"q":"أي تظهير تشترطه كونيتيكت لقيادة مركبة تنقل مواد خطرة بكميات تتطلب لوحات تحذيرية؟","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"تشترط كونيتيكت تظهير H (المواد الخطرة) لتشغيل مركبة تنقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"25":{"q":"في كونيتيكت، يُشترط تظهير N (الصهريج/السوائل السائبة) لصهريج شحن مثبّت بشكل دائم بسعة لا تقل عن كم؟","options":["100 gallons or more","119 gallons or more","500 gallons or more","1,000 gallons or more"],"explanation":"تشترط كونيتيكت تظهير N لمركبة مصمّمة لنقل سائل أو غاز سائل في صهريج شحن مثبّت بشكل دائم مصنّف بسعة 119 gallons أو أكثر (أو صهريج محمول مصنّف بسعة 1,000 gallons أو أكثر). المصدر: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"26":{"q":"أي تظهير في كونيتيكت يُشترط لسحب أكثر من مقطورة واحدة بمركبة تتطلب رخصة قيادة تجارية من الفئة A؟","options":["P endorsement","N endorsement","T endorsement","S endorsement"],"explanation":"تشترط كونيتيكت تظهير T (المزدوجات/الثلاثيات) عندما تسحب مركبة من الفئة A أكثر من مقطورة واحدة. المصدر: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"27":{"q":"قبل أن يتمكن سائق في كونيتيكت من الحصول على تظهير S (الحافلة المدرسية)، أي تظهير آخر يجب أن يحمله السائق أيضًا؟","options":["H (Hazardous Materials)","N (Tank)","P (Passenger)","T (Doubles/Triples)"],"explanation":"في كونيتيكت، يتطلب تظهير الحافلة المدرسية (S) أيضًا أن يكون حامله حائزًا على تظهير الركاب (P) وأن يحافظ على سجل قيادة مقبول. المصدر: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"28":{"q":"بموجب القواعد الفيدرالية المطبقة في كونيتيكت، كم يجب أن يحمل مقدّم الطلب تصريح المتعلّم التجاري (CLP) قبل أن يصبح مؤهلًا لخوض اختبار المهارات (اختبار الطريق) لرخصة القيادة التجارية؟","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"explanation":"لا يجوز لمقدّم الطلب خوض اختبار مهارات رخصة القيادة التجارية خلال الـ 14 days التي تلي الإصدار الأولي للـ CLP؛ ويجب الاحتفاظ بالتصريح لمدة لا تقل عن 14 days. المصدر: 49 CFR 383.25(e)، المطبق من قِبل Connecticut DMV."},"29":{"q":"كم تبلغ مدة صلاحية تصريح المتعلّم التجاري (CLP) في كونيتيكت اعتبارًا من تاريخ الإصدار؟","options":["90 days","180 days","سنة واحدة","سنتان"],"explanation":"يظل تصريح CLP في كونيتيكت ساريًا لمدة سنة واحدة من تاريخ الإصدار؛ وإذا لم يتم الحصول على رخصة القيادة التجارية خلال تلك المدة، فيجب على مقدّم الطلب إعادة خوض الاختبارات المطلوبة. المصدر: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"30":{"q":"اعتبارًا من 7 فبراير 2022، من الذي يجب أن يُكمل تدريب السائقين المبتدئين (ELDT) عبر مزوّد مسجّل لدى FMCSA قبل الاختبار في كونيتيكت؟","options":["فقط المتقدّمون لتظهير المواد الخطرة","أي شخص يجدّد رخصة قيادة تجارية قائمة","المتقدّمون لأول مرة لرخصة القيادة التجارية، ومن يرقّون الفئة B إلى الفئة A، والمتقدّمون لأول مرة لتظهير H أو P أو S","فقط السائقون دون سن 21"],"explanation":"منذ 7 فبراير 2022، يُشترط تدريب ELDT للمتقدّمين لأول مرة لرخصة القيادة التجارية، والسائقين الذين يرقّون الفئة B إلى الفئة A، والمتقدّمين لأول مرة لتظهير H أو P أو S، على أن يُقدَّم التدريب من قِبل مزوّد مدرج في FMCSA Training Provider Registry. المصدر: FMCSA ELDT rule (49 CFR Part 380)؛ CT DMV CDL pages (portal.ct.gov/dmv)."},"31":{"q":"يجب إكمال تدريب السائقين المبتدئين (ELDT) لمقدّم الطلب في كونيتيكت من خلال أي نظام؟","options":["بوابة التدريب التابعة لـ Connecticut DMV","FMCSA Training Provider Registry (TPR)","نظام التسجيل التابع لـ TSA","Drug and Alcohol Clearinghouse"],"explanation":"يجب إكمال تدريب ELDT مع مزوّد مدرج في FMCSA Training Provider Registry (TPR)، الذي يُبلّغ FMCSA بإتمام السائق للتدريب. المصدر: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov)؛ CT DMV CDL pages."},"32":{"q":"بالنسبة لتظهير المواد الخطرة (H)، يتكون متطلب تدريب ELDT من أي نوع من التدريب؟","options":["التدريب النظري فقط","التدريب العملي خلف المقود فقط","التدريب النظري والعملي خلف المقود معًا","لا يُشترط تدريب ELDT للمواد الخطرة"],"explanation":"متطلب تدريب ELDT لتظهير المواد الخطرة (H) نظري فقط؛ ولا يوجد مكوّن عملي خلف المقود، بخلاف الفئتين A/B وتظهيري P وS. المصدر: FMCSA ELDT rule (49 CFR Part 380)؛ FMCSA Training Provider Registry."},"33":{"q":"إلى جانب متطلبات المعرفة وتدريب ELDT، ما هو الفحص الفيدرالي الإضافي الذي يجب أن يجتازه مقدّم الطلب في كونيتيكت للحصول على تظهير المواد الخطرة (H)؟","options":["فحص طبي DOT فقط","تقييم تهديد أمني من TSA يشمل أخذ البصمات","فحص ائتماني على مستوى الولاية","فحص للنظر فقط"],"explanation":"يتطلب تظهير المواد الخطرة اجتياز تقييم التهديد الأمني من TSA، الذي يشمل التحقق من السوابق وأخذ البصمات، بالإضافة إلى اختبار المعرفة والتدريب النظري لـ ELDT. المصدر: TSA HazMat Endorsement Threat Assessment Program؛ CT DMV endorsement pages."},"34":{"q":"أي مجموعة من المستندات تشترطها Connecticut DMV عند التقدّم للحصول على تصريح المتعلّم التجاري، بما يتوافق مع REAL ID؟","options":["إثبات الهوية، ورقم الضمان الاجتماعي، والإقامة القانونية في الولايات المتحدة، وإثباتين للإقامة في كونيتيكت","جواز سفر فقط","شهادة ميلاد وفاتورة خدمات","رخصة القيادة الحالية في كونيتيكت فقط"],"explanation":"تشترط كونيتيكت مستندات REAL ID: إثبات الهوية، ورقم الضمان الاجتماعي، والإقامة القانونية في الولايات المتحدة، وإثباتين للإقامة في كونيتيكت، بالإضافة إلى تأكيد التصديق الذاتي ونموذج الطلب R-229a. المصدر: CT DMV, How to get a commercial learner's permit in CT (portal.ct.gov/dmv)."},"35":{"q":"السائق في كونيتيكت الذي سيشغّل مركبة تجارية داخل الولاية وخارجها ويجب أن يحمل بطاقة طبية DOT ينبغي أن يصدّق ذاتيًا تحت أي فئة؟","options":["Excepted Interstate (EI)","Non-excepted Interstate (NI)","Excepted Intrastate (EA)","Non-excepted Intrastate (NA)"],"explanation":"تغطي فئة Non-excepted Interstate (NI) القيادة داخل كونيتيكت وخارجها وتتطلب استيفاء متطلبات الشهادة الطبية الفيدرالية DOT. المصدر: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)."},"36":{"q":"أي فئة تصديق ذاتي في كونيتيكت تنطبق على سائق يشغّل مركبة داخل كونيتيكت فقط وغير ملزم باستيفاء متطلبات البطاقة الطبية الفيدرالية DOT؟","options":["Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)","Excepted Interstate (EI)"],"explanation":"تنطبق فئة Excepted Intrastate (EA) على السائقين الذين يشغّلون مركبات داخل كونيتيكت فقط والمعفيين من متطلب الشهادة الطبية الفيدرالية DOT. المصدر: CT DMV, Self-certification for CDL (portal.ct.gov/dmv)."},"37":{"q":"قبل معالجة معاملة رخصة القيادة التجارية في كونيتيكت، تتحقق DMV من حالة مقدّم الطلب في أي نظام فيدرالي؟","options":["قاعدة بيانات TSA PreCheck","FMCSA Drug and Alcohol Clearinghouse","National Driver Register فقط","Selective Service System"],"explanation":"يجب على مقدّمي الطلبات في كونيتيكت التسجيل في FMCSA Drug and Alcohol Clearinghouse، وتتحقق DMV من حالة مقدّم الطلب في الـ Clearinghouse قبل معالجة معاملة رخصة القيادة التجارية. المصدر: CT DMV CDL pages (portal.ct.gov/dmv)؛ FMCSA Drug and Alcohol Clearinghouse."},"38":{"q":"ما هو الحد الأدنى للعمر، وما هي حالة الجنسية/الهجرة، التي تشترطها كونيتيكت لتظهير المواد الخطرة (H)؟","options":["العمر 18، مواطن أمريكي فقط","العمر 21، مواطن أمريكي أو مقيم دائم قانوني أو حامل لوثيقة تصريح عمل سارية","العمر 19، أي مقيم قانوني","العمر 21، مواطن أمريكي فقط"],"explanation":"تشترط كونيتيكت أن يكون المتقدّمون لتظهير المواد الخطرة (H) في سن 21 على الأقل وأن يكونوا مواطنين أمريكيين أو مقيمين دائمين قانونيين أو حاملين لوثيقة تصريح عمل سارية. المصدر: CT DMV, Get an endorsement for your CDL or license (portal.ct.gov/dmv)."},"39":{"q":"في كونيتيكت، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للشخص قانونيًا تشغيل مركبة آلية تجارية (CMV)؟","options":["0.04%","0.08%","0.02%","0.00%"],"explanation":"تتبع كونيتيكت المعيار الفيدرالي للمركبات الآلية التجارية: من غير القانوني تشغيل مركبة آلية تجارية بتركيز كحول في الدم (BAC) قدره 0.04% أو أكثر (CT CDL Manual 1.3.2؛ 49 CFR 383.51)."},"40":{"q":"بتشغيله مركبة آلية تجارية في كونيتيكت، يُعتبر السائق تلقائيًا قد أعطى موافقته على فحص الكحول الكيميائي. ما اسم هذا المبدأ؟","options":["الموافقة الضمنية","السبب المحتمل","التنازل الصريح","المراجعة الإدارية"],"explanation":"يعتبر قانون الموافقة الضمنية في كونيتيكت أن أي مشغّل مرخّص قد وافق على إجراء فحص للدم أو النَّفَس أو البول (CT CDL Manual 1.3.2؛ CGS Sec. 14-227b)."},"41":{"q":"أُدين حامل رخصة قيادة تجارية في كونيتيكت بأول مخالفة كبرى، مثل قيادة مركبة آلية تجارية بتركيز كحول في الدم (BAC) قدره 0.04% أو أكثر. لأي مدة تُسحب أهلية رخصة القيادة التجارية؟","options":["At least 1 year","At least 90 days","At least 6 months","At least 3 years"],"explanation":"تؤدي أول مخالفة كبرى إلى سحب أهلية رخصة القيادة التجارية لمدة لا تقل عن سنة واحدة (CT CDL Manual 1.3.2؛ 49 CFR 383.51)."},"42":{"q":"بموجب قواعد كونيتيكت، إذا وقعت أول مخالفة كبرى (مثل تركيز كحول في الدم قدره 0.04 أو رفض الفحص) أثناء تشغيل السائق لمركبة آلية تجارية تحمل لوحات تحذيرية لمواد خطرة، فإن سحب الأهلية يكون لمدة لا تقل عن:","options":["3 years","1 year","5 years","18 months"],"explanation":"تؤدي أول مخالفة كبرى أثناء تشغيل مركبة آلية تجارية تحمل لوحات تحذيرية لمواد خطرة إلى سحب أهلية رخصة القيادة التجارية لمدة لا تقل عن ثلاث سنوات (CT CDL Manual 1.3.2؛ 49 CFR 383.51)."},"43":{"q":"ما هي عقوبة سحب الأهلية في كونيتيكت لسائق أُدين بثاني مخالفة كبرى (على سبيل المثال، ثاني قيادة تحت تأثير الكحول أو رفض الفحص)؟","options":["سحب الأهلية مدى الحياة","سحب الأهلية لمدة 10 سنوات","سحب الأهلية لمدة 5 سنوات","سحب الأهلية لمدة 3 سنوات"],"explanation":"تؤدي ثاني مخالفة كبرى إلى سحب أهلية رخصة القيادة التجارية مدى الحياة (CT CDL Manual 1.3.2؛ 49 CFR 383.51)."},"44":{"q":"يرفض حامل رخصة قيادة تجارية في كونيتيكت الخضوع لفحص كحول كيميائي للمرة الأولى. لأي مدة تُسحب أهلية رخصة القيادة التجارية بسبب هذا الرفض؟","options":["1 year","6 months","60 days","3 years"],"explanation":"يؤدي رفض الخضوع لفحص كيميائي (انتهاك الموافقة الضمنية) إلى سحب أهلية رخصة القيادة التجارية لمدة سنة واحدة عند المخالفة الأولى (CT CDL Manual 1.3.2؛ CGS Sec. 14-227b)."},"45":{"q":"بموجب قانون الموافقة الضمنية في كونيتيكت، إذا رفض شخص إجراء فحص كيميائي، فإن رخصة المشغّل العادية (غير التجارية) تخضع للتعليق لمدة لا تقل عن:","options":["6 months","30 days","1 year","90 days"],"explanation":"يُخضِع رفض إجراء فحص كيميائي رخصة المشغّل للتعليق لمدة لا تقل عن ستة أشهر؛ وإذا عُلّقت، فإن أهلية رخصة القيادة التجارية تُسحب أيضًا (CT CDL Manual 1.3.2؛ CGS Sec. 14-227b)."},"46":{"q":"في كونيتيكت، يخضع سائق مركبة آلية تجارية يُكتشف لديه كمية قابلة للكشف من الكحول أقل من 0.04% لأي إجراء فوري؟","options":["إخراجه من الخدمة لمدة 24 hours","سحب أهليته لمدة 60 days","اعتقاله بتهمة القيادة تحت التأثير","تغريمه $500 دون أي إجراء آخر"],"explanation":"يؤدي أي كحول قابل للكشف بنسبة أقل من 0.04% إلى الإخراج من الخدمة لمدة 24 hours (CT CDL Manual 1.3.2؛ 49 CFR 392.5)."},"47":{"q":"أي مما يلي يُصنّف على أنه مخالفة مرورية خطيرة لحامل رخصة قيادة تجارية في كونيتيكت؟","options":["تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد المعلن","أول قيادة تحت تأثير الكحول في مركبة آلية تجارية","عدم التوقف عند مزلقان السكة الحديدية","انتهاك أمر الإخراج من الخدمة"],"explanation":"تشمل المخالفات المرورية الخطيرة الإفراط في السرعة (15 mph أو أكثر فوق الحد)، والقيادة المتهورة، وتغيير المسارات بشكل غير منتظم؛ أما القيادة تحت التأثير وانتهاكات الإخراج من الخدمة فهي فئات منفصلة (CT CDL Manual 1.3.3)."},"48":{"q":"يرتكب حامل رخصة قيادة تجارية في كونيتيكت مخالفتين مروريتين خطيرتين خلال فترة ثلاث سنوات. الحد الأدنى لسحب الأهلية هو:","options":["60 days","30 days","120 days","1 year"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال ثلاث سنوات إلى سحب أهلية رخصة القيادة التجارية لمدة لا تقل عن 60 days (CT CDL Manual 1.3.3؛ 49 CFR 383.51)."},"49":{"q":"إذا ارتكب حامل رخصة قيادة تجارية في كونيتيكت ثلاث مخالفات مرورية خطيرة أو أكثر خلال فترة ثلاث سنوات، فإن الحد الأدنى لسحب الأهلية هو:","options":["120 days","60 days","180 days","1 year"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة أو أكثر خلال ثلاث سنوات إلى سحب أهلية رخصة القيادة التجارية لمدة لا تقل عن 120 days (CT CDL Manual 1.3.3؛ 49 CFR 383.51)."},"50":{"q":"أي مما يلي غير مُدرج في قائمة كونيتيكت للمخالفات المرورية الخطيرة؟","options":["القيادة بسرعة 8 mph فوق الحد المعلن للسرعة","تغيير المسارات بشكل غير صحيح أو غير منتظم","اتباع مركبة عن قرب أكثر من اللازم","القيادة المتهورة"],"explanation":"تتطلب المخالفات الخطيرة تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد؛ فالتجاوز بمقدار 8 mph لا يستوفي الشرط، في حين أن تغيير المسارات غير المنتظم والقيادة الملاصقة والقيادة المتهورة تستوفيه (CT CDL Manual 1.3.3)."},"51":{"q":"يرتكب حامل رخصة قيادة تجارية في كونيتيكت ثالث انتهاك لأمر الإخراج من الخدمة خلال فترة 10 سنوات. الحد الأدنى لسحب الأهلية هو:","options":["3 years","1 year","2 years","180 days"],"explanation":"يؤدي ثالث انتهاك لأمر الإخراج من الخدمة أو ما يليه خلال 10 سنوات إلى سحب أهلية رخصة القيادة التجارية لمدة لا تقل عن 3 years (وحتى 5) (CT CDL Manual 1.3.4؛ 49 CFR 383.51)."},"52":{"q":"ما هو سحب الأهلية في كونيتيكت لأول إدانة لسائق بمخالفة عند مزلقان تقاطع السكة الحديدية مع الطريق أثناء تشغيل مركبة آلية تجارية؟","options":["At least 60 days","At least 30 days","At least 120 days","At least 180 days"],"explanation":"تؤدي أول مخالفة عند مزلقان تقاطع السكة الحديدية مع الطريق إلى سحب أهلية رخصة القيادة التجارية لمدة لا تقل عن 60 days (CT CDL Manual 1.3.5؛ 49 CFR 383.51)."},"53":{"q":"بالنسبة لثاني مخالفة عند مزلقان تقاطع السكة الحديدية مع الطريق خلال ثلاث سنوات، تُسحب أهلية حامل رخصة القيادة التجارية في كونيتيكت لمدة لا تقل عن:","options":["120 days","60 days","180 days","1 year"],"explanation":"تؤدي ثاني مخالفة عند المزلقان خلال ثلاث سنوات إلى سحب أهلية رخصة القيادة التجارية لمدة لا تقل عن 120 days (CT CDL Manual 1.3.5؛ 49 CFR 383.51)."},"54":{"q":"بموجب قواعد المركبات الآلية التجارية في كونيتيكت والقواعد الفيدرالية، يواجه سائق أُدين بمخالفتين أو أكثر لحمل/استخدام هاتف محمول باليد أثناء تشغيل مركبة آلية تجارية سحبًا للأهلية لمدة 60 days للمخالفة الثانية وكم لثلاث مخالفات أو أكثر خلال ثلاث سنوات؟","options":["120 days","60 days","180 days","1 year"],"explanation":"يؤدي استخدام الهاتف المحمول باليد أثناء قيادة مركبة آلية تجارية إلى سحب الأهلية لمدة 60 days للمخالفة الثانية و120 days لثلاث مخالفات أو أكثر خلال ثلاث سنوات (CT CDL Manual 2.9.4؛ 49 CFR 383.51)."},"55":{"q":"بعد الإدانة بأي مخالفة مرورية (غير الوقوف غير القانوني)، خلال كم يومًا يجب على حامل رخصة القيادة التجارية في كونيتيكت إخطار صاحب عمله؟","options":["30 days","2 days","10 days","60 days"],"explanation":"يجب على حامل رخصة القيادة التجارية إخطار صاحب عمله خلال 30 days من الإدانة بأي مخالفة مرورية، بغض النظر عن المركبة التي تمت قيادتها (CT CDL Manual 1.4؛ 49 CFR 383.31)."},"56":{"q":"بموجب قانون معابر السكك الحديدية في ولاية كونيتيكت، أين يجب أن تتوقف الحافلة أو الحافلة المدرسية أو المركبة التجارية الحاملة للوحات تحذير المواد الخطرة (HazMat) أو صهريج الشحن قبل عبور القضبان عند المعبر السطحي؟","options":["على مسافة لا تقل عن 15 قدمًا ولا تزيد عن 50 قدمًا من أقرب قضيب","على مسافة 25 قدمًا بالضبط من أقرب قضيب","على مسافة لا تقل عن 10 أقدام ولا تزيد عن 40 قدمًا من أقرب قضيب","على مسافة لا تقل عن 50 قدمًا ولا تزيد عن 100 قدم من أقرب قضيب"],"explanation":"تتطلب القوانين العامة لولاية كونيتيكت المادة 14-250 ودليل CDL الخاص بكونيتيكت أن تتوقف الحافلات والمركبات الناقلة للركاب ومركبات نقل الطلاب والمركبات التجارية المزودة بصهاريج شحن أو الحاملة للمواد الخطرة على مسافة لا تقل عن 15 قدمًا ولا تزيد عن 50 قدمًا من أقرب قضيب، ثم النظر والإنصات قبل العبور."},"57":{"q":"عندما يقترب سائق في كونيتيكت من مركبة طوارئ متوقفة وأضواؤها وامضة على طريق سريع متعدد المسارات، فماذا يتطلب قانون \"التنحّي جانبًا\" (Move Over) في الولاية من السائق أن يفعل؟","options":["تخفيض السرعة إلى مستوى معقول، والانتقال إلى مسار واحد جانبًا عند الأمان إذا كان في المسار المجاور","التوقف التام حتى تغادر مركبة الطوارئ مكان الحادث","الحفاظ على حد السرعة المعلن مع إطلاق البوق","الانتقال مسارًا واحدًا فقط إذا كانت مركبة الطوارئ سيارة شرطة"],"explanation":"تتطلب القوانين العامة لولاية كونيتيكت المادة 14-283b (قانون \"التنحّي جانبًا\") من السائقين أن يقللوا فورًا السرعة إلى مستوى معقول أقل من الحد، وأن ينتقلوا مسارًا واحدًا جانبًا عند السير في المسار المجاور للكتف ما لم تكن تلك الحركة غير آمنة."},"58":{"q":"على طريق سريع مقسوم محدود الوصول في كونيتيكت يضم ثلاثة مسارات أو أكثر في الاتجاه نفسه حيث تحدد الولاية ذلك، أي مركبة يُحظر عليها القيادة في أقصى المسار الأيسر؟","options":["شاحنة مسجلة تجاريًا","سيارة ركاب بها راكب واحد","دراجة نارية","سيارة إسعاف تستجيب لنداء"],"explanation":"تمنع القوانين العامة لولاية كونيتيكت المادة 14-230a المركبات المسجلة تجاريًا والحافلات الآلية والمركبات المقطورة والحافلات المدرسية من أقصى المسار الأيسر على الطرق السريعة المقسومة محدودة الوصول التي تضم ثلاثة مسارات أو أكثر (في الاتجاه نفسه) حيث يحدد مكتب إدارة حركة المرور بالولاية ذلك؛ والغرامة 88 دولارًا."},"59":{"q":"أي الطرق في كونيتيكت تحظر المركبات التجارية مثل الجرارات-المقطورات والشاحنات الصندوقية؟","options":["متنزهات ميريت وويلبر كروس وميلفورد (ممر الطريق 15)","الطريق السريع بين الولايات 95 والطريق السريع بين الولايات 84","جميع طرق الولاية المرقمة فوق 100","الطريقان السريعان 9 و2"],"explanation":"تحظر متنزهات كونيتيكت - متنزه ميريت ومتنزه ويلبر كروس (الطريق 15) ومتنزه ميلفورد - المركبات التجارية والمقطورات والمركبات كبيرة الحجم، ويعود ذلك بشكل كبير إلى الجسور العلوية التاريخية المنخفضة. قيود متنزهات CT DOT؛ وغرامة مخالفة المتنزه 500 دولار لكل مخالفة."},"60":{"q":"على طريق سريع في كونيتيكت تكون فيه المسارات مفصولة بجزيرة أمان أو حاجز مادي، ماذا يجب على السائق الموجود على الجانب المقابل من الحاجز أن يفعل عندما تكون حافلة مدرسية متوقفة وأضواؤها الحمراء وامضة؟","options":["يجوز للسائق المتابعة دون توقف","يجب على السائق التوقف حتى تُطفأ الأضواء الحمراء","يجب على السائق التوقف فقط إذا كان باب الحافلة مفتوحًا","يجب على السائق التباطؤ إلى 15 ميلًا في الساعة لكن دون حاجة للتوقف"],"explanation":"تنص القوانين العامة لولاية كونيتيكت المادة 14-279 على أنه في طريق سريع تكون مساراته مفصولة بجزيرة أمان أو حاجز مادي، يجوز للسائق الموجود على الجانب المقابل من ذلك الحاجز المتابعة دون التوقف للحافلة المدرسية. أما الخط المرسوم وحده فلا يُؤهِّل لذلك - فيجب على الاتجاهين كليهما التوقف."},"61":{"q":"على طريق في كونيتيكت مفصول فقط بخط مرسوم في المنتصف (دون حاجز مادي)، ماذا يجب على السائق أن يفعل عند مقابلة حافلة مدرسية متوقفة تُظهر أضواء حمراء وامضة على الجانب المقابل؟","options":["التوقف، لأن الخط المرسوم لا يُؤهِّل لاستثناء الطريق المقسوم","المتابعة بسرعة مخفّضة دون توقف","المتابعة دون قيد لأنها حركة مرور قادمة في الاتجاه المعاكس","التوقف فقط إذا كان أطفال يعبرون بشكل ظاهر"],"explanation":"بموجب القوانين العامة لولاية كونيتيكت المادة 14-279، لا ينطبق استثناء عدم التوقف إلا حيث تفصل جزيرة أمان أو حاجز مادي بين المسارات. أما مع وجود خط مرسوم فقط، فيجب على المركبات على الجانبين كليهما التوقف توقفًا تامًا للحافلة المدرسية ذات الأضواء الحمراء الوامضة."},"62":{"q":"إلى أي مدى يجوز لسائق في كونيتيكت أن يقترب من حافلة مدرسية متوقفة وأضواؤها الحمراء وامضة من الأمام قبل أن يُطلَب منه التوقف؟","options":["على مسافة لا تقل عن 10 أقدام من مقدمة الحافلة","على مسافة لا تقل عن 5 أقدام من مقدمة الحافلة","على مسافة لا تقل عن 20 قدمًا من مقدمة الحافلة","على مسافة لا تقل عن 25 قدمًا من مقدمة الحافلة"],"explanation":"تتطلب القوانين العامة لولاية كونيتيكت المادة 14-279 من المركبات التوقف على مسافة لا تقل عن 10 أقدام من المقدمة عند الاقتراب، وعلى مسافة لا تقل عن 10 أقدام من المؤخرة عند التجاوز أو السير خلف حافلة مدرسية مسجلة تُظهر أضواء إشارة حمراء وامضة."},"63":{"q":"بعد توقف مركبة تجارية معطلة على طريق سريع باتجاه واحد أو مقسوم في كونيتيكت، أين يجب على السائق وضع مثلثات التحذير العاكسة الثلاثة؟","options":["على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة","على بُعد 10 أقدام و50 قدمًا و150 قدمًا خلف المركبة","على بُعد 25 قدمًا و75 قدمًا و125 قدمًا باتجاه حركة المرور القادمة","على بُعد 5 أقدام و50 قدمًا و500 قدم باتجاه حركة المرور القادمة"],"explanation":"يوجّه دليل CDL الخاص بكونيتيكت (بما يطابق 49 CFR 392.22) بأنه على طريق سريع باتجاه واحد أو مقسوم، تُوضع أجهزة التحذير على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة خلف المركبة المتوقفة."},"64":{"q":"خلال كم دقيقة يجب على سائق CDL في كونيتيكت وضع أجهزة التحذير من الطوارئ بعد توقف مركبة تجارية على الطريق أو الكتف؟","options":["خلال 10 دقائق","خلال 30 دقيقة","خلال 5 دقائق","فورًا، قبل الخروج من المقصورة"],"explanation":"ينص دليل CDL الخاص بكونيتيكت على أنه إذا اضطُررت إلى التوقف على طريق أو كتف، فيجب تشغيل الأضواء الوامضة الرباعية ووضع أجهزة التحذير من الطوارئ خلال 10 دقائق."},"65":{"q":"أي قائمة تحدد بشكل صحيح مركبات كونيتيكت التي يجب أن تتوقف عند كل معبر سكة حديدية سطحي؟","options":["الحافلات الناقلة للركاب ومركبات نقل الطلاب والمركبات التجارية المزودة بصهاريج شحن أو الحاملة للمواد الخطرة","جميع المركبات التجارية التي يزيد وزنها عن 10,000 رطل بغض النظر عن الحمولة","فقط شاحنات الصهاريج الفارغة وشاحنات القطر","فقط المركبات التي تقطر مقطورة"],"explanation":"تتطلب القوانين العامة لولاية كونيتيكت المادة 14-250 من مشغّل كل مركبة تجارية تنقل ركابًا، أو حافلة خدمة، أو مركبة تُستخدم لنقل أطفال المدارس، وكل مركبة تجارية مزودة بصهريج شحن أو حاملة لمواد خطرة، أن يتوقف على مسافة 15 إلى 50 قدمًا من أقرب قضيب قبل العبور."},"66":{"q":"ما هو أعلى حد سرعة معلن يجوز لمركبة تجارية السير به قانونيًا على طريق سريع بين الولايات في كونيتيكت؟","options":["65 ميلًا في الساعة، وهو الحد الأقصى نفسه الذي ينطبق على سيارات الركاب","55 ميلًا في الساعة، وهو حد أدنى خاص لجميع الشاحنات على مستوى الولاية","70 ميلًا في الساعة على الطرق السريعة الريفية بين الولايات","60 ميلًا في الساعة لأي مركبة يزيد وزنها عن 26,000 رطل"],"explanation":"الحد الأقصى المعلن للسرعة في كونيتيكت هو 65 ميلًا في الساعة (CGS المادة 14-219 / 14-218a)، ولا تضع الولاية حدًا منفصلًا أدنى لسرعة الشاحنات على مستوى الولاية - فالشاحنات والسيارات تتشارك الحد الأقصى نفسه البالغ 65 ميلًا في الساعة حيثما يكون معلنًا. ويجب على السائقين مع ذلك الالتزام بأي حدود معلنة أدنى."},"67":{"q":"على طريق ثنائي المسار في كونيتيكت يحمل حركة المرور في الاتجاهين (غير مقسوم)، أين يجب على سائق المركبة التجارية وضع مثلثات التحذير الثلاثة بعد التوقف؟","options":["ضمن 10 أقدام من المركبة، و100 قدم أمامها و100 قدم خلفها","على بُعد 10 أقدام و100 قدم و200 قدم خلف المركبة فقط","على بُعد 50 قدمًا أمام المركبة و50 قدمًا خلفها فقط","ضمن 10 أقدام من الأمام والخلف، و250 قدمًا في كل اتجاه"],"explanation":"يوجّه دليل CDL الخاص بكونيتيكت بأنه على طريق ثنائي المسار باتجاهين أو غير مقسوم، يُوضع مثلث واحد ضمن 10 أقدام من المركبة، وواحد على بُعد 100 قدم خلفها وآخر على بُعد 100 قدم أمامها، على الكتف أو في المسار الذي توقفت فيه."},"68":{"q":"بموجب قاعدة الالتزام باليمين في كونيتيكت، أين يجب أن تُقاد المركبة التي تسير بسرعة أبطأ من السرعة الطبيعية لحركة المرور؟","options":["في المسار الأيمن أو أقرب ما يمكن من الحافة اليمنى للطريق السريع","في أي مسار، طالما تستخدم الأضواء الوامضة","في المسار الأوسط لطريق ثلاثي المسارات","في المسار الأيسر للابتعاد عن حركة المرور المندمجة"],"explanation":"تتطلب القوانين العامة لولاية كونيتيكت المادة 14-230 أن تُقاد المركبات على اليمين، وأن تُقاد أي مركبة تسير بأقل من السرعة الطبيعية لحركة المرور في المسار الأيمن المتاح، أو أقرب ما يمكن من الرصيف أو الحافة اليمنى."},"69":{"q":"ما العقوبة التي تفرضها كونيتيكت على تشغيل مركبة آلية تجارية على متنزه تابع للولاية حيث تُحظر فيه مثل هذه المركبات؟","options":["غرامة قدرها 500 دولار لكل مخالفة","تحذير كتابي فقط في المخالفة الأولى","غرامة قدرها 35 دولارًا بالإضافة إلى نقطتين","تعليق إلزامي للرخصة لمدة 30 يومًا"],"explanation":"زادت كونيتيكت عقوبة تشغيل مركبة تجارية محظورة على متنزه (ميريت أو ويلبر كروس أو ميلفورد) إلى 500 دولار لكل مخالفة. قيود متنزهات CT DOT؛ صلاحية تقييد المتنزهات بموجب CGS الفصل 249 / المادة 14-298."},"70":{"q":"إلى جانب مركبات الطوارئ، يتطلب قانون \"التنحّي جانبًا\" في كونيتيكت أيضًا من السائقين التباطؤ والتنحّي جانبًا لأي مما يلي عند توقفه على الكتف؟","options":["مركبة غير طارئة متوقفة على الكتف","فقط سيارات الشرطة المميزة بعلامات","فقط المركبات التي وُضعت لها شُعَل حمراء","المشاة المنتظرون في موقف حافلات"],"explanation":"جرى توسيع القوانين العامة لولاية كونيتيكت المادة 14-283b لتشمل ليس فقط مركبات الطوارئ (بما في ذلك مركبات الصيانة وشاحنات القطر) ذات الأضواء الوامضة، بل أيضًا أي مركبة غير طارئة متوقفة وموجودة على الكتف؛ فيجب على السائقين التباطؤ والتنحّي جانبًا عند الأمان."},"71":{"q":"في كونيتيكت، ما حد الوزن القانوني الذي يحتاج بعده المركبة عمومًا إلى تصريح زيادة الوزن من DOT؟","options":["80,000 رطل من الوزن الإجمالي للمركبة","73,280 رطلًا من الوزن الإجمالي للمركبة","100,000 رطل من الوزن الإجمالي للمركبة","65,000 رطل من الوزن الإجمالي للمركبة"],"explanation":"تتبع كونيتيكت الحد الأقصى القانوني الفيدرالي البالغ 80,000 رطل من الوزن الإجمالي للمركبة (على خمسة محاور). والأحمال التي تتجاوز 80,000 رطل تتطلب تصريح زيادة الوزن من CT DOT. لوائح تصريح الأبعاد/الأوزان الزائدة لـ CT DOT."},"72":{"q":"أي عقوبة للمخالفة اللاحقة تنطبق في كونيتيكت على تجاوز حافلة مدرسية متوقفة وأضواؤها الحمراء وامضة بشكل غير قانوني (مخالفة ثانية أو لاحقة)؟","options":["ما لا يقل عن 500 دولار ولا يزيد عن 1,000 دولار، و/أو السجن حتى 30 يومًا","مخالفة ثابتة قدرها 90 دولارًا دون سجن","خطاب تحذير ونقطتان على الرخصة","غرامة ثابتة قدرها 450 دولارًا مطابقة للمخالفة الأولى"],"explanation":"تحدد القوانين العامة لولاية كونيتيكت المادة 14-279 غرامة قدرها 450 دولارًا للمخالفة الأولى لتجاوز حافلة مدرسية متوقفة، ولكل مخالفة لاحقة ما لا يقل عن 500 دولار ولا يزيد عن 1,000 دولار، أو السجن مدة لا تزيد عن 30 يومًا، أو كليهما."},"73":{"q":"ما الحد الأقصى القانوني لارتفاع المركبة في كونيتيكت قبل أن يُطلب تصريح الحجم الزائد؟","options":["13 قدمًا و6 بوصات","12 قدمًا و0 بوصة","14 قدمًا و6 بوصات","13 قدمًا و0 بوصة"],"explanation":"الحدود القصوى القانونية للأبعاد في كونيتيكت هي 8 أقدام و6 بوصات عرضًا و13 قدمًا و6 بوصات ارتفاعًا (بطول نصف مقطورة 53 قدمًا). وتجاوز الارتفاع 13 قدمًا و6 بوصات يتطلب تصريح الحجم الزائد من CT DOT. لوائح تصريح الأبعاد/الأوزان الزائدة لـ CT DOT."},"74":{"q":"يقترب سائق CDL من معبر سكة حديدية في كونيتيكت وهو ينقل صهريج شحن فارغًا كان آخر استخدام له لمواد خطرة. ماذا يجب على السائق أن يفعل؟","options":["التوقف على مسافة 15 إلى 50 قدمًا من أقرب قضيب، لأن القاعدة تنطبق على صهاريج الشحن سواء كانت محملة أو فارغة","المتابعة دون توقف لأن الصهريج فارغ","التوقف فقط إذا كان هناك قطار مرئي","التباطؤ إلى 5 أميال في الساعة لكن المتابعة عبر القضبان دون توقف تام"],"explanation":"تتطلب القوانين العامة لولاية كونيتيكت المادة 14-250 ودليل CDL الخاص بكونيتيكت من المركبات المزودة بصهاريج شحن استُخدمت للمواد الخطرة أن تتوقف على مسافة 15 إلى 50 قدمًا من أقرب قضيب سواء كان الصهريج محملًا أو فارغًا، وألا تعبر إلا عندما يمكن تجاوز القضبان دون توقف."},"75":{"q":"أي جهة تُصدر رخص القيادة التجارية (CDLs) في كونيتيكت؟","options":["دائرة المركبات الآلية في كونيتيكت (DMV)","دائرة النقل في كونيتيكت (CTDOT)","الإدارة الفيدرالية لسلامة الناقلين بالشاحنات (FMCSA)","شرطة ولاية كونيتيكت، شعبة سلامة المركبات التجارية"],"explanation":"في كونيتيكت، تُصدر دائرة المركبات الآلية (DMV) رخص CDL وتدير اختبارات المعرفة والمهارات. وتتولى CTDOT تصاريح الأبعاد/الأوزان الزائدة وتضع FMCSA المعايير الفيدرالية، لكن الرخصة نفسها هي وثيقة صادرة عن DMV الولاية. المصدر: CT DMV، \"الحصول على رخصة قيادة تجارية\" (portal.ct.gov/dmv)."},"76":{"q":"في كونيتيكت، ما الحد الأدنى للسن للحصول على رخصة CDL للتشغيل داخل الولاية فقط (intrastate)؟","options":["18 عامًا","16 عامًا","21 عامًا","25 عامًا"],"explanation":"تتطلب كونيتيكت أن يكون السائق 18 عامًا على الأقل لتشغيل مركبة تجارية داخل الولاية (داخل كونيتيكت فقط). ويجب أن يكون السائق 21 عامًا على الأقل للقيادة بين الولايات أو لنقل المواد الخطرة. المصدر: CT DMV، \"الحصول على رخصة قيادة تجارية\" / \"الحصول على تصريح متعلّم تجاري\"."},"77":{"q":"في كونيتيكت، ما الحد الأدنى للسن لتشغيل مركبة آلية تجارية في التجارة بين الولايات أو لنقل المواد الخطرة؟","options":["21 عامًا","18 عامًا","19 عامًا","23 عامًا"],"explanation":"تتطلب كونيتيكت، اتباعًا للمعيار الفيدرالي، أن يكون السائق 21 عامًا على الأقل لقيادة مركبة تجارية عبر حدود الولايات (بين الولايات) أو لنقل كميات تستلزم لوحات تحذير من المواد الخطرة. والسائقون من 18 إلى 20 عامًا محصورون في التشغيل داخل الولاية. المصدر: صفحات CLP/CDL لـ CT DMV؛ 49 CFR 391.11."},"78":{"q":"قبل أن يتمكن متقدم جديد من إجراء اختبار مهارات CDL لرخصة من الفئة A أو الفئة B في كونيتيكت، ما التدريب الذي يجب إتمامه؟","options":["تدريب السائق المبتدئ (ELDT) — نظري بالإضافة إلى التدريب خلف عجلة القيادة — من مزوّد مسجّل لدى FMCSA","برنامج مدرسة مهنية معتمد من الولاية مدته 160 ساعة فقط","دورة قيادة دفاعية معتمدة من DMV كونيتيكت","دورة توعية بالمواد الخطرة عبر الإنترنت مدتها ثماني ساعات"],"explanation":"اعتبارًا من 7 فبراير 2022، يجب على المتقدم المبتدئ إتمام تدريب السائق المبتدئ (ELDT) الإلزامي — النظري (المعرفي) والتدريب خلف عجلة القيادة (BTW) على حد سواء — عبر مزوّد مدرج في سجل مزودي التدريب لدى FMCSA قبل إجراء اختبار مهارات الفئة A/B (وقبل اختبارات تصديقات P أو S أو H، حسب الانطباق). المصدر: CT DMV، \"متطلب تدريب السائق المبتدئ لـ CDL\"؛ 49 CFR Part 380 Subpart F."},"79":{"q":"يجب على المتقدم إتمام تدريب السائق المبتدئ قبل إجراء اختبار المعرفة لأي من هذه التصديقات في كونيتيكت؟","options":["تصديق المواد الخطرة (H)","تصديق مركبة الصهريج (N)","تصديق المقطورات المزدوجة/الثلاثية (T)","فئة المركبة المركّبة (دون حرف تصديق) فقط"],"explanation":"يجب إتمام ELDT قبل اختبار المعرفة لتصديق المواد الخطرة (H) (وليس لـ H اختبار مهارات). كما أن ELDT مطلوب قبل اختبارات المهارات لتصديقَي الركاب (P) والحافلة المدرسية (S). أما تصديقا N وT فلا يخضعان لـ ELDT. المصدر: CT DMV، \"متطلب تدريب السائق المبتدئ لـ CDL\"؛ 49 CFR 380.609."},"80":{"q":"ما الوثيقة التي يجب على المتقدم الجديد لرخصة CDL الحصول عليها أولًا في عملية الترخيص في كونيتيكت، قبل رخصة CDL الكاملة؟","options":["تصريح المتعلّم التجاري (CLP)","إعفاء من الفحص الطبي لـ DOT من DMV","تفويض تشغيل ناقل بالشاحنات (رقم MC)","شهادة نقل مؤقتة بين الولايات"],"explanation":"تبدأ العملية باجتياز اختبارات المعرفة المطلوبة للحصول على تصريح المتعلّم التجاري (CLP). ثم يتدرّب المتقدم ويُتم ELDT ويُجري اختبار المهارات لتحويل CLP إلى CDL. المصدر: CT DMV، \"الحصول على تصريح متعلّم تجاري\" و\"الحصول على رخصة قيادة تجارية\"."},"81":{"q":"كم مدة صلاحية تصريح المتعلّم التجاري (CLP) في كونيتيكت من تاريخ إصداره؟","options":["سنة واحدة","60 يومًا","ستة أشهر","سنتان"],"explanation":"تصريح CLP في كونيتيكت صالح لمدة سنة واحدة من تاريخ الإصدار. وإذا لم يحصل حامله على رخصة CDL خلال تلك السنة، فيجب إعادة جميع الاختبارات المطلوبة للحصول على تصريح جديد. المصدر: CT DMV، \"الحصول على تصريح متعلّم تجاري\"."},"82":{"q":"في كونيتيكت، كم يجب أن يحمل المتقدم تصريح CLP قبل أن يصبح مؤهلًا لإجراء اختبار مهارات CDL؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","10 أيام على الأقل","60 يومًا على الأقل"],"explanation":"يجب على المتقدم حمل تصريح CLP لمدة 14 يومًا كحد أدنى قبل إجراء اختبار مهارات CDL. وتُطبَّق فترة الانتظار الدنيا الفيدرالية هذه في كونيتيكت. المصدر: CT DMV، \"الحصول على تصريح متعلّم تجاري\"؛ 49 CFR 383.25(a)(3)."},"83":{"q":"يتكوّن اختبار المعرفة العامة لـ CDL في كونيتيكت من 50 سؤالًا. كم عددًا يجب الإجابة عنه بشكل صحيح للنجاح؟","options":["40 إجابة صحيحة (80%)","35 إجابة صحيحة (70%)","45 إجابة صحيحة (90%)","30 إجابة صحيحة (60%)"],"explanation":"يضم اختبار المعرفة العامة في كونيتيكت 50 سؤالًا من نوع الاختيار من متعدد ويتطلب 40 إجابة صحيحة (80%) للنجاح. المصدر: CT DMV، \"الحصول على تصريح متعلّم تجاري\"."},"84":{"q":"من كم جزء منفصل يتكوّن اختبار مهارات CDL في كونيتيكت؟","options":["ثلاثة أجزاء","جزءان","أربعة أجزاء","خمسة أجزاء"],"explanation":"يتكوّن اختبار مهارات CDL من ثلاثة أجزاء: فحص المركبة قبل الرحلة، واختبار مهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. ويجب اجتياز الأجزاء الثلاثة كلها للحصول على رخصة CDL. المصدر: اختبار CDL لـ CT DMV؛ 49 CFR 383.113."},"85":{"q":"أي مما يلي هو أحد الأجزاء الثلاثة المطلوبة في اختبار مهارات CDL في كونيتيكت؟","options":["فحص المركبة قبل الرحلة","اختبار المعرفة العامة المكوّن من 50 سؤالًا","الفحص الطبي لـ DOT","اختبار تصديق المكابح الهوائية الكتابي"],"explanation":"الأجزاء الثلاثة لاختبار المهارات هي فحص المركبة قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق. أما اختبارا المعرفة العامة والمكابح الهوائية فهما اختبارا معرفة كتابيان (يُجريان للحصول على CLP)، والفحص الطبي لـ DOT هو فحص طبي — ولا شيء من هذه أجزاء من اختبار المهارات. المصدر: CT DMV؛ 49 CFR 383.113."},"86":{"q":"خلال اختبار القيادة لـ CDL في كونيتيكت، الجزء الذي يُظهر فيه المتقدم مناورات مثل الرجوع للخلف في خط مستقيم أو الرجوع المنحرف في منطقة محكومة يُسمّى:","options":["اختبار مهارات التحكم الأساسي بالمركبة","اختبار الفحص قبل الرحلة","اختبار القيادة على الطريق","اختبار المركبة المركّبة"],"explanation":"مناورات الرجوع للخلف وتحديد الموضع التي تُؤدّى خارج الطرق العامة هي جزء من اختبار مهارات التحكم الأساسي بالمركبة، وهو الثاني من مكونات اختبار المهارات الثلاثة. والفحص قبل الرحلة هو المعاينة، واختبار القيادة على الطريق يُجرى ضمن حركة المرور. المصدر: CT DMV؛ 49 CFR 383.113(b)."},"87":{"q":"إذا لم يُجرِ متقدم CDL في كونيتيكت اختبار معرفة المكابح الهوائية أو لم يجتزه، فماذا يحدث للرخصة؟","options":["يُوضع قيد \"L\"، يمنع تشغيل أي مركبة تجارية مزودة بمكابح هوائية","يُحرَم المتقدم من رخصة CDL كليًا حتى يجتاز المكابح الهوائية","يُضاف قيد \"K\" يحصر السائق في التشغيل داخل الولاية","لا شيء — المكابح الهوائية اختيارية ولا تترك أي قيد"],"explanation":"السائق الذي يفشل في اجتياز اختبار معرفة المكابح الهوائية (والفحوص المهارية المرتبطة) يحصل على قيد \"L\"، الذي يمنع تشغيل أي مركبة تجارية مزودة بمكابح هوائية. المصدر: معلومات CLP/CDL لـ CT DMV؛ 49 CFR 383.95."},"88":{"q":"تتطلب قواعد CDL الفيدرالية المطبَّقة في كونيتيكت من كل حامل CDL/CLP \"التصديق الذاتي\". كم عدد فئات نوع القيادة في التصديق الذاتي التي يحددها الإطار الفيدرالي؟","options":["أربع","اثنتان","ثلاث","ست"],"explanation":"يحدد إطار التصديق الذاتي الفيدرالي أربع فئات: غير المعفى بين الولايات (NI)، والمعفى بين الولايات (EI)، وغير المعفى داخل الولاية (NA)، والمعفى داخل الولاية (EA). ويقدّم التصديق الذاتي عبر الإنترنت في كونيتيكت عمليًا الخيارين غير المعفيَين اللذين يستخدمهما معظم السائقين (NI وNA). المصدر: 49 CFR 383.71(b)؛ التصديق الذاتي لـ CT DMV."},"89":{"q":"السائق في كونيتيكت الذي يُصدّق ذاتيًا بأنه \"غير معفى بين الولايات\" (NI) يدلي بأي بيان عن تشغيله وحالته الطبية؟","options":["أنه يشغّل عبر حدود الولايات ويجب أن يستوفي متطلب الشهادة الطبية الفيدرالية لـ DOT","أنه يشغّل داخل كونيتيكت فقط ومعفى من المتطلبات الطبية لـ DOT","أنه يشغّل عبر حدود الولايات لكنه معفى من أي شهادة طبية","أنه يشغّل داخل كونيتيكت فقط ويجب أن يحمل تصريح مواد خطرة"],"explanation":"تعني فئة \"غير المعفى بين الولايات\" (NI) أن السائق يشغّل مركبة تجارية في التجارة بين الولايات (داخل كونيتيكت وخارجها) وأنه خاضع لمتطلبات الشهادة الطبية الفيدرالية لـ DOT ويجب أن يستوفيها. المصدر: التصديق الذاتي لـ CT DMV؛ 49 CFR 383.71(b)."},"90":{"q":"السائق في كونيتيكت الذي يُصدّق ذاتيًا بأنه \"غير معفى داخل الولاية\" (NA) يُصدّق على أنه سوف:","options":["يشغّل مركبة آلية تجارية داخل حدود كونيتيكت فقط","يشغّل عبر حدود الولايات بموجب إعفاء طبي فيدرالي","يشغّل على مستوى البلاد دون أي شهادة طبية","يشغّل فقط معدات زراعية معفاة من قواعد CDL"],"explanation":"تُصدّق فئة \"غير المعفى داخل الولاية\" (NA) على تشغيل مركبة تجارية داخل كونيتيكت فقط. وقد يحمل هؤلاء السائقون قيد \"K\" يحصرهم في القيادة داخل الولاية، ويجب أن يستوفوا معايير كونيتيكت الطبية/تأهيل السائق. المصدر: التصديق الذاتي لـ CT DMV (dmvselfservice.ct.gov)."},"91":{"q":"كيف يُتم حامل CDL/CLP خطوة التصديق الذاتي لدى DMV كونيتيكت؟","options":["تقديمها عبر نظام الخدمة الذاتية على الإنترنت لـ DMV وإحضار تأكيد البريد الإلكتروني المطبوع إلى DMV","أن يرسل الفاحص الطبي تصديقًا ورقيًا بالبريد إلى مقر FMCSA","التصديق الذاتي فقط وقت اختبار القيادة، شفهيًا للفاحص","إيداع التصديق لدى دائرة العمل في كونيتيكت"],"explanation":"يُصدّق السائق ذاتيًا عبر الإنترنت من خلال بوابة الخدمة الذاتية لـ DMV كونيتيكت (dmvselfservice.ct.gov)، ويتلقّى تأكيدًا بالبريد الإلكتروني، ويُحضر ذلك التأكيد المطبوع إلى DMV عند التقديم أو التجديد أو الترقية أو تغيير نوع القيادة. المصدر: التصديق الذاتي لـ CT DMV."},"92":{"q":"أي نموذج يجب أن يستخدمه فاحص طبي معتمد لتوثيق الفحص الطبي لـ DOT لحامل CDL في كونيتيكت، وكيف يصل إلى DMV؟","options":["النموذج MCSA-5876، يرفعه الفاحص عبر السجل الوطني ويُرسَل إلى DMV إلكترونيًا","النموذج R-229a، يرسله المتقدم بالبريد إلى DMV خلال 30 يومًا","النموذج MCSA-5876، يحمله السائق بيده ويُمسَح ضوئيًا في أي فرع لـ DMV","مذكرة طبيب بخط اليد، يرسلها المتقدم بالفاكس إلى FMCSA"],"explanation":"يجب تسجيل الفحص الطبي لـ DOT على النموذج MCSA-5876 (شهادة الفاحص الطبي) بواسطة فاحص مدرج في السجل الوطني للفاحصين الطبيين المعتمدين؛ ويرفع الفاحص النتائج عبر السجل الوطني، وتُنقَل إلى DMV كونيتيكت إلكترونيًا. المصدر: CT DMV، \"الحصول على الشهادة الطبية لـ CDL\"."},"93":{"q":"ماذا يحدث لرخصة CDL في كونيتيكت إذا فشل حاملها في الإبقاء على شهادة طبية صالحة لـ DOT مودعة لدى DMV؟","options":["بعد إشعار بالتخفيض، تُخفَّض الرخصة إلى رخصة غير تجارية من الفئة D","تُلغى رخصة CDL نهائيًا ولا يمكن استعادتها","تُفرَض غرامة مدنية فيدرالية قدرها 500 دولار تلقائيًا كل شهر","لا يتغيّر شيء حتى يحين موعد التجديد المعتاد"],"explanation":"إذا لم تُحفظ شهادة طبية صالحة، تصبح الحالة الطبية للسائق \"غير معتمد\"؛ وترسل DMV إشعارًا بالتخفيض، وإذا لم تُستلَم شهادة صالحة جديدة إلكترونيًا بحلول التاريخ المحدد، تُخفَّض رخصة CDL إلى رخصة من الفئة D (غير تجارية). المصدر: CT DMV، \"الحصول على الشهادة الطبية لـ CDL\"."},"94":{"q":"كم مرة يجب تجديد رخصة القيادة التجارية في كونيتيكت؟","options":["كل أربع سنوات","كل ست سنوات","كل سنتين","كل ثماني سنوات"],"explanation":"تُصدَر رخصة CDL في كونيتيكت بدورة تجديد كل أربع سنوات (تُجدَّد قرب عيد ميلاد حاملها)، وهي أقصر من مدة الرخصة غير التجارية المعتادة. المصدر: CT DMV، \"تجديد رخصة CDL (تجارية)\"؛ Conn. Gen. Stat. § 14-44h."}}};
